// ═══════════════════════════════════════════════════════════════
// LOGIN + CADASTRO SELF-SERVICE — Vicke
// ═══════════════════════════════════════════════════════════════
// 3 telas alternantes (controladas por estado local):
//   1. "login"           — entrada normal por email/senha
//   2. "cadastro-form"   — usuário novo: nome empresa, CNPJ, email, senha
//   3. "cadastro-codigo" — digite código de 6 dígitos enviado por email
//
// Após validar código, recebe JWT e usuário direto via auto-login
// (chama onLogin do pai) — sem precisar fazer login manual depois.

const TOKEN_KEY = "vicke-token";
const USER_KEY  = "vicke-user";

function getToken()   { try { return localStorage.getItem(TOKEN_KEY); } catch { return null; } }
function getUser()    { try { return JSON.parse(localStorage.getItem(USER_KEY)); } catch { return null; } }
function saveAuth(token, usuario) {
  localStorage.setItem(TOKEN_KEY, token);
  localStorage.setItem(USER_KEY, JSON.stringify(usuario));
}
function clearAuth() {
  localStorage.removeItem(TOKEN_KEY);
  localStorage.removeItem(USER_KEY);
}

// POST sem Authorization (auth não tem token ainda)
async function apiPost(path, body) {
  const _url = (typeof API_URL !== "undefined" && API_URL)
    || "https://orbi-production-5f5c.up.railway.app";
  const res = await fetch(_url + path, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
  return res.json();
}

// ───────────────────────────────────────────────────────────────
// Estilos compartilhados pelas 3 telas
// ───────────────────────────────────────────────────────────────
function getEstilos(loading) {
  return {
    wrap: {
      fontFamily: "'Helvetica Neue', Helvetica, Arial, sans-serif",
      minHeight: "100vh",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      background: "#fff",
      padding: "20px",
    },
    box: { width: "100%", maxWidth: 360 },
    header: { textAlign: "center", marginBottom: 32 },
    titulo: { fontSize: 22, fontWeight: 700, color: "#111", letterSpacing: -0.5, margin: 0 },
    sub: { fontSize: 13, color: "#9ca3af", marginTop: 6 },
    card: { background: "#fff", border: "1px solid #e5e7eb", borderRadius: 12, padding: "28px 24px" },
    label: { fontSize: 13, color: "#6b7280", display: "block", marginBottom: 6 },
    input: {
      width: "100%",
      border: "1px solid #d1d5db",
      borderRadius: 10,
      padding: "11px 14px",
      fontSize: 14,
      color: "#111",
      outline: "none",
      background: "#fff",
      boxSizing: "border-box",
      fontFamily: "inherit",
      transition: "border-color 0.15s",
    },
    grupo: { marginBottom: 16 },
    btn: {
      width: "100%",
      background: "#111",
      color: "#fff",
      border: "none",
      borderRadius: 10,
      padding: "12px 0",
      fontSize: 14,
      fontWeight: 600,
      cursor: "pointer",
      fontFamily: "inherit",
      marginTop: 8,
      opacity: loading ? 0.6 : 1,
    },
    btnSec: {
      width: "100%",
      background: "#fff",
      color: "#374151",
      border: "1px solid #d1d5db",
      borderRadius: 10,
      padding: "12px 0",
      fontSize: 14,
      fontWeight: 500,
      cursor: "pointer",
      fontFamily: "inherit",
      marginTop: 8,
    },
    erro: { fontSize: 13, color: "#dc2626", textAlign: "center", marginTop: 12, minHeight: 20 },
    info: { fontSize: 13, color: "#059669", textAlign: "center", marginTop: 12, minHeight: 20 },
    rodape: { textAlign: "center", marginTop: 24, fontSize: 12, color: "#d1d5db" },
    // Link "Criar conta" / "Voltar pro login"
    linkSec: {
      textAlign: "center",
      marginTop: 16,
      fontSize: 13,
      color: "#6b7280",
    },
    linkBtn: {
      background: "none",
      border: "none",
      color: "#111",
      fontWeight: 600,
      cursor: "pointer",
      padding: 0,
      fontSize: 13,
      fontFamily: "inherit",
      textDecoration: "underline",
      textUnderlineOffset: 3,
    },
  };
}

// ═══════════════════════════════════════════════════════════════
// TelaAuth — wrapper que decide entre login / cadastro / código
// ═══════════════════════════════════════════════════════════════
function TelaLogin({ onLogin }) {
  // Estado da tela ativa: "login" | "cadastro-form" | "cadastro-codigo"
  // | "recuperar-senha" | "redefinir-senha"
  // Detecta token de recuperação na URL ao iniciar — se tiver, abre direto
  // a tela de redefinir. Token chega como ?recuperar=xxx.
  const tokenRecuperarInicial = (() => {
    try {
      const params = new URLSearchParams(window.location.search);
      return params.get("recuperar") || null;
    } catch { return null; }
  })();
  const [tela, setTela] = useState(tokenRecuperarInicial ? "redefinir-senha" : "login");
  const [tokenRecuperar] = useState(tokenRecuperarInicial);
  // Email persistido entre telas: usuário digitou no cadastro,
  // precisamos lembrar dele ao mostrar a tela do código.
  const [emailCadastro, setEmailCadastro] = useState("");

  if (tela === "cadastro-form") {
    return (
      <TelaCadastro
        onVoltar={() => setTela("login")}
        onCodigoEnviado={email => {
          setEmailCadastro(email);
          setTela("cadastro-codigo");
        }}
      />
    );
  }

  if (tela === "cadastro-codigo") {
    return (
      <TelaCadastroCodigo
        email={emailCadastro}
        onVoltar={() => setTela("cadastro-form")}
        onValidado={(usuario, token) => {
          saveAuth(token, usuario);
          onLogin(usuario, token);
        }}
      />
    );
  }

  if (tela === "recuperar-senha") {
    return (
      <TelaRecuperarSenha onVoltar={() => setTela("login")} />
    );
  }

  if (tela === "redefinir-senha") {
    return (
      <TelaRedefinirSenha
        token={tokenRecuperar}
        onConcluido={() => {
          // Limpa token da URL pra não ficar visível ao login
          try {
            const url = new URL(window.location.href);
            url.searchParams.delete("recuperar");
            window.history.replaceState({}, "", url.pathname + url.search);
          } catch {}
          setTela("login");
        }}
      />
    );
  }

  return <TelaLoginEntrada onLogin={onLogin} onCriarConta={() => setTela("cadastro-form")} onEsqueciSenha={() => setTela("recuperar-senha")} />;
}

// ═══════════════════════════════════════════════════════════════
// 1. Tela de Login (email + senha)
// ═══════════════════════════════════════════════════════════════
function TelaLoginEntrada({ onLogin, onCriarConta, onEsqueciSenha }) {
  const [email, setEmail]               = useState("");
  const [senha, setSenha]               = useState("");
  const [mostrarSenha, setMostrarSenha] = useState(false);
  const [erro, setErro]                 = useState("");
  const [loading, setLoading]           = useState(false);
  const S = getEstilos(loading);

  async function handleLogin() {
    if (!email || !senha) { setErro("Preencha e-mail e senha."); return; }
    setErro("");
    setLoading(true);
    try {
      const res = await apiPost("/auth/login", { email, senha });
      if (res.ok) {
        saveAuth(res.data.token, res.data.usuario);
        onLogin(res.data.usuario, res.data.token);
      } else {
        setErro(res.error || "E-mail ou senha inválidos.");
      }
    } catch (e) {
      console.error("Erro de login:", e);
      setErro("Não foi possível conectar ao servidor.");
    }
    setLoading(false);
  }

  function handleKey(e) { if (e.key === "Enter") handleLogin(); }

  return (
    <div style={S.wrap}>
      <div style={S.box}>
        <div style={S.header}>
          <div style={S.titulo}>Vicke</div>
          <div style={S.sub}>Entre na sua conta</div>
        </div>
        <div style={S.card}>
          <div style={S.grupo}>
            <label style={S.label}>E-mail</label>
            <input
              style={S.input}
              type="email"
              placeholder="seu@email.com"
              value={email}
              onChange={e => setEmail(e.target.value)}
              onKeyDown={handleKey}
              autoFocus
            />
          </div>
          <div style={S.grupo}>
            <label style={S.label}>Senha</label>
            <div style={{ position:"relative" }}>
              <input
                style={{ ...S.input, paddingRight: 40 }}
                type={mostrarSenha ? "text" : "password"}
                placeholder="••••••••"
                value={senha}
                onChange={e => setSenha(e.target.value)}
                onKeyDown={handleKey}
              />
              <button
                type="button"
                onClick={() => setMostrarSenha(v => !v)}
                aria-label={mostrarSenha ? "Ocultar senha" : "Mostrar senha"}
                title={mostrarSenha ? "Ocultar senha" : "Mostrar senha"}
                style={{
                  position:"absolute", right: 8, top:"50%", transform:"translateY(-50%)",
                  background:"none", border:"none", padding: 6, cursor:"pointer",
                  color:"#9ca3af", display:"flex", alignItems:"center", justifyContent:"center",
                  borderRadius: 6,
                }}
                onMouseEnter={e => { e.currentTarget.style.color = "#374151"; e.currentTarget.style.background = "#f3f4f6"; }}
                onMouseLeave={e => { e.currentTarget.style.color = "#9ca3af"; e.currentTarget.style.background = "none"; }}
              >
                {mostrarSenha ? (
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M9.88 9.88a3 3 0 1 0 4.24 4.24"/>
                    <path d="M10.73 5.08A10.43 10.43 0 0 1 12 5c7 0 10 7 10 7a13.16 13.16 0 0 1-1.67 2.68"/>
                    <path d="M6.61 6.61A13.526 13.526 0 0 0 2 12s3 7 10 7a9.74 9.74 0 0 0 5.39-1.61"/>
                    <line x1="2" y1="2" x2="22" y2="22"/>
                  </svg>
                ) : (
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M2 12s3-7 10-7 10 7 10 7-3 7-10 7-10-7-10-7Z"/>
                    <circle cx="12" cy="12" r="3"/>
                  </svg>
                )}
              </button>
            </div>
          </div>
          <button style={S.btn} onClick={handleLogin} disabled={loading}>
            {loading ? "Entrando..." : "Entrar"}
          </button>
          {erro && <div style={S.erro}>{erro}</div>}
          {/* Link de recuperação — discreto, abaixo do botão Entrar.
              Padrão UX universal pra logins. */}
          <div style={{ textAlign:"center", marginTop:14 }}>
            <button
              type="button"
              onClick={onEsqueciSenha}
              style={{
                background:"none", border:"none", padding:0, cursor:"pointer",
                fontFamily:"inherit", fontSize:12.5, color:"#9ca3af",
                textDecoration:"underline", textUnderlineOffset:2,
              }}
              onMouseEnter={e => { e.currentTarget.style.color = "#374151"; }}
              onMouseLeave={e => { e.currentTarget.style.color = "#9ca3af"; }}>
              Esqueci minha senha
            </button>
          </div>
        </div>
        {/* Link de cadastro — caminho de baixa fricção pra novos usuários */}
        <div style={S.linkSec}>
          Não tem conta?{" "}
          <button style={S.linkBtn} onClick={onCriarConta}>Criar conta</button>
        </div>
        <div style={S.rodape}>Vicke — Conectando elos</div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// 2. Tela de Cadastro (form com dados da empresa + admin)
// ═══════════════════════════════════════════════════════════════
function TelaCadastro({ onVoltar, onCodigoEnviado }) {
  const [nomeEmpresa, setNomeEmpresa]   = useState("");
  const [cnpjCpf, setCnpjCpf]           = useState("");
  const [nomeResp, setNomeResp]         = useState("");
  const [email, setEmail]               = useState("");
  const [senha, setSenha]               = useState("");
  const [mostrarSenha, setMostrarSenha] = useState(false);
  const [erro, setErro]                 = useState("");
  const [loading, setLoading]           = useState(false);
  const S = getEstilos(loading);

  async function handleCadastrar() {
    setErro("");
    if (!nomeEmpresa.trim()) return setErro("Informe o nome do escritório.");
    if (!nomeResp.trim())    return setErro("Informe seu nome.");
    if (!email.trim())       return setErro("Informe seu e-mail.");
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) return setErro("E-mail inválido.");
    if (senha.length < 6)    return setErro("Senha deve ter no mínimo 6 caracteres.");

    setLoading(true);
    try {
      const res = await apiPost("/auth/signup-iniciar", {
        nome_empresa: nomeEmpresa,
        cnpj_cpf: cnpjCpf || null,
        nome_responsavel: nomeResp,
        email,
        senha,
      });
      if (res.ok) {
        // Sobe pra próxima tela com email memorizado
        onCodigoEnviado(email.trim().toLowerCase());
      } else {
        setErro(res.error || "Não foi possível criar a conta.");
      }
    } catch (e) {
      console.error("Erro signup:", e);
      setErro("Não foi possível conectar ao servidor.");
    }
    setLoading(false);
  }

  return (
    <div style={S.wrap}>
      <div style={S.box}>
        <div style={S.header}>
          <div style={S.titulo}>Criar conta</div>
          <div style={S.sub}>Preencha os dados pra começar</div>
        </div>
        <div style={S.card}>
          <div style={S.grupo}>
            <label style={S.label}>Nome do escritório *</label>
            <input
              style={S.input}
              placeholder="Ex: Vicke Associados"
              value={nomeEmpresa}
              onChange={e => setNomeEmpresa(e.target.value)}
              autoFocus
            />
          </div>
          <div style={S.grupo}>
            <label style={S.label}>CNPJ / CPF <span style={{ color:"#9ca3af", fontWeight:400 }}>(opcional)</span></label>
            <input
              style={S.input}
              placeholder="00.000.000/0001-00"
              value={cnpjCpf}
              onChange={e => setCnpjCpf(e.target.value)}
            />
          </div>
          <div style={S.grupo}>
            <label style={S.label}>Seu nome *</label>
            <input
              style={S.input}
              placeholder="Como você quer ser chamado"
              value={nomeResp}
              onChange={e => setNomeResp(e.target.value)}
            />
          </div>
          <div style={S.grupo}>
            <label style={S.label}>E-mail *</label>
            <input
              style={S.input}
              type="email"
              placeholder="seu@email.com"
              value={email}
              onChange={e => setEmail(e.target.value)}
            />
          </div>
          <div style={S.grupo}>
            <label style={S.label}>Senha * <span style={{ color:"#9ca3af", fontWeight:400 }}>(mínimo 6 caracteres)</span></label>
            <div style={{ position:"relative" }}>
              <input
                style={{ ...S.input, paddingRight: 40 }}
                type={mostrarSenha ? "text" : "password"}
                placeholder="••••••••"
                value={senha}
                onChange={e => setSenha(e.target.value)}
                onKeyDown={e => { if (e.key === "Enter") handleCadastrar(); }}
              />
              <button
                type="button"
                onClick={() => setMostrarSenha(v => !v)}
                aria-label={mostrarSenha ? "Ocultar senha" : "Mostrar senha"}
                style={{
                  position:"absolute", right: 8, top:"50%", transform:"translateY(-50%)",
                  background:"none", border:"none", padding: 6, cursor:"pointer",
                  color:"#9ca3af", display:"flex", alignItems:"center", justifyContent:"center",
                  borderRadius: 6,
                }}
                onMouseEnter={e => { e.currentTarget.style.color = "#374151"; e.currentTarget.style.background = "#f3f4f6"; }}
                onMouseLeave={e => { e.currentTarget.style.color = "#9ca3af"; e.currentTarget.style.background = "none"; }}
              >
                {mostrarSenha ? (
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M9.88 9.88a3 3 0 1 0 4.24 4.24"/>
                    <path d="M10.73 5.08A10.43 10.43 0 0 1 12 5c7 0 10 7 10 7a13.16 13.16 0 0 1-1.67 2.68"/>
                    <path d="M6.61 6.61A13.526 13.526 0 0 0 2 12s3 7 10 7a9.74 9.74 0 0 0 5.39-1.61"/>
                    <line x1="2" y1="2" x2="22" y2="22"/>
                  </svg>
                ) : (
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M2 12s3-7 10-7 10 7 10 7-3 7-10 7-10-7-10-7Z"/>
                    <circle cx="12" cy="12" r="3"/>
                  </svg>
                )}
              </button>
            </div>
          </div>
          <button style={S.btn} onClick={handleCadastrar} disabled={loading}>
            {loading ? "Enviando código..." : "Continuar"}
          </button>
          {erro && <div style={S.erro}>{erro}</div>}
        </div>
        <div style={S.linkSec}>
          Já tem conta?{" "}
          <button style={S.linkBtn} onClick={onVoltar}>Entrar</button>
        </div>
        <div style={S.rodape}>Vicke — Conectando elos</div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// 3. Tela do código (6 dígitos enviados por email)
// ═══════════════════════════════════════════════════════════════
function TelaCadastroCodigo({ email, onVoltar, onValidado }) {
  // 6 dígitos individuais — UX padrão de OTP (Stripe, Vercel, Linear)
  // Refs pra mover foco automaticamente entre inputs
  const [digitos, setDigitos] = useState(["", "", "", "", "", ""]);
  const [erro, setErro]       = useState("");
  const [info, setInfo]       = useState("");
  const [loading, setLoading] = useState(false);
  const [reenviando, setReenviando] = useState(false);
  // Cooldown do botão "Reenviar" (60s) — evita spam
  const [cooldown, setCooldown] = useState(0);
  const refsInputs = useRef([]);
  const S = getEstilos(loading);

  // Auto-foca primeiro input ao montar
  useEffect(() => {
    if (refsInputs.current[0]) refsInputs.current[0].focus();
  }, []);

  // Decrementa cooldown a cada segundo
  useEffect(() => {
    if (cooldown <= 0) return;
    const t = setTimeout(() => setCooldown(c => c - 1), 1000);
    return () => clearTimeout(t);
  }, [cooldown]);

  function handleChangeDigito(idx, valor) {
    // Aceita só dígitos. Se colaram número longo, distribui pelos campos.
    const limpo = valor.replace(/\D/g, "");
    if (!limpo) {
      setDigitos(d => { const n = [...d]; n[idx] = ""; return n; });
      return;
    }
    if (limpo.length === 1) {
      setDigitos(d => { const n = [...d]; n[idx] = limpo; return n; });
      // Auto-avança próximo input
      if (idx < 5 && refsInputs.current[idx + 1]) refsInputs.current[idx + 1].focus();
    } else {
      // Colaram >1 dígito: distribui a partir do idx atual
      setDigitos(d => {
        const n = [...d];
        for (let i = 0; i < limpo.length && idx + i < 6; i++) {
          n[idx + i] = limpo[i];
        }
        return n;
      });
      // Foca no próximo após o último preenchido (ou último input)
      const proxIdx = Math.min(idx + limpo.length, 5);
      if (refsInputs.current[proxIdx]) refsInputs.current[proxIdx].focus();
    }
  }

  function handleKeyDown(idx, e) {
    if (e.key === "Backspace" && !digitos[idx] && idx > 0) {
      // Backspace em campo vazio: volta pro anterior
      refsInputs.current[idx - 1].focus();
    }
    if (e.key === "Enter") {
      handleValidar();
    }
  }

  // Auto-valida quando todos 6 dígitos preenchem
  useEffect(() => {
    if (digitos.every(d => d !== "")) {
      handleValidar();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [digitos]);

  async function handleValidar() {
    const codigo = digitos.join("");
    if (codigo.length !== 6) return setErro("Digite os 6 dígitos.");
    setErro("");
    setInfo("");
    setLoading(true);
    try {
      const res = await apiPost("/auth/signup-validar", { email, codigo });
      if (res.ok) {
        // JWT + usuário retornados — auto-login
        onValidado(res.data.usuario, res.data.token);
      } else {
        setErro(res.error || "Código inválido.");
        // Limpa os dígitos pra usuário tentar de novo
        setDigitos(["", "", "", "", "", ""]);
        if (refsInputs.current[0]) refsInputs.current[0].focus();
      }
    } catch (e) {
      console.error("Erro validar código:", e);
      setErro("Não foi possível conectar ao servidor.");
    }
    setLoading(false);
  }

  async function handleReenviar() {
    if (cooldown > 0) return;
    setReenviando(true);
    setErro("");
    setInfo("");
    try {
      const res = await apiPost("/auth/signup-reenviar", { email });
      if (res.ok) {
        setInfo("Novo código enviado para seu e-mail.");
        setCooldown(60);
        setDigitos(["", "", "", "", "", ""]);
        if (refsInputs.current[0]) refsInputs.current[0].focus();
      } else {
        setErro(res.error || "Não foi possível reenviar o código.");
      }
    } catch (e) {
      console.error("Erro reenviar:", e);
      setErro("Não foi possível conectar ao servidor.");
    }
    setReenviando(false);
  }

  // Estilo dos 6 inputs do código — quadradinhos grandes
  const inputCodigo = {
    width: 44,
    height: 52,
    border: "1.5px solid #d1d5db",
    borderRadius: 8,
    fontSize: 22,
    fontWeight: 600,
    color: "#111",
    textAlign: "center",
    outline: "none",
    background: "#fff",
    fontFamily: "'SF Mono', Menlo, Consolas, monospace",
    padding: 0,
    transition: "border-color 0.15s, box-shadow 0.15s",
  };

  return (
    <div style={S.wrap}>
      <div style={S.box}>
        <div style={S.header}>
          <div style={S.titulo}>Digite o código</div>
          <div style={S.sub}>
            Enviamos um código de 6 dígitos para<br/>
            <span style={{ color:"#374151", fontWeight:500 }}>{email}</span>
          </div>
        </div>
        <div style={S.card}>
          {/* 6 quadradinhos pra dígito */}
          <div style={{ display:"flex", justifyContent:"space-between", gap:6, marginBottom:20 }}>
            {digitos.map((d, idx) => (
              <input
                key={idx}
                ref={el => { refsInputs.current[idx] = el; }}
                type="text"
                inputMode="numeric"
                maxLength={6}
                value={d}
                onChange={e => handleChangeDigito(idx, e.target.value)}
                onKeyDown={e => handleKeyDown(idx, e)}
                onFocus={e => { e.currentTarget.style.borderColor = "#111"; }}
                onBlur={e => { e.currentTarget.style.borderColor = "#d1d5db"; }}
                style={inputCodigo}
                disabled={loading}
              />
            ))}
          </div>
          <button style={S.btn} onClick={handleValidar} disabled={loading}>
            {loading ? "Validando..." : "Confirmar"}
          </button>
          {erro && <div style={S.erro}>{erro}</div>}
          {info && <div style={S.info}>{info}</div>}
          <div style={{ textAlign:"center", marginTop:16 }}>
            <button
              style={{
                background:"none", border:"none", color: cooldown > 0 ? "#d1d5db" : "#6b7280",
                fontSize: 13, cursor: cooldown > 0 ? "default" : "pointer", fontFamily:"inherit",
                padding: 4,
              }}
              onClick={handleReenviar}
              disabled={cooldown > 0 || reenviando}
            >
              {reenviando ? "Reenviando..." : cooldown > 0 ? `Reenviar código em ${cooldown}s` : "Não recebeu? Reenviar código"}
            </button>
          </div>
        </div>
        <div style={S.linkSec}>
          <button style={S.linkBtn} onClick={onVoltar}>← Voltar</button>
        </div>
        <div style={S.rodape}>Vicke — Conectando elos</div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// 4. Tela de Recuperar Senha (digite email → recebe link)
// ═══════════════════════════════════════════════════════════════
// Anti-enumeração: backend sempre retorna sucesso, então UI também
// mostra a mesma mensagem de "se existir, vai receber". Não vazamos
// se o email existe ou não.
function TelaRecuperarSenha({ onVoltar }) {
  const [email, setEmail]   = useState("");
  const [loading, setLoading] = useState(false);
  const [enviado, setEnviado] = useState(false);
  const [erro, setErro]     = useState("");
  const S = getEstilos(loading);

  async function handleEnviar() {
    const e = email.trim();
    if (!e) { setErro("Digite seu e-mail."); return; }
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e)) { setErro("E-mail inválido."); return; }
    setErro("");
    setLoading(true);
    try {
      const res = await apiPost("/auth/recuperar-senha", { email: e });
      if (res.ok) {
        setEnviado(true);
      } else {
        setErro(res.error || "Não foi possível processar a solicitação.");
      }
    } catch (err) {
      console.error("Erro recuperar senha:", err);
      setErro("Não foi possível conectar ao servidor.");
    }
    setLoading(false);
  }

  function handleKey(ev) { if (ev.key === "Enter") handleEnviar(); }

  // Tela de confirmação após envio. Texto é genérico de propósito —
  // não confirma se o email realmente existe (anti-enumeração).
  if (enviado) {
    return (
      <div style={S.wrap}>
        <div style={S.box}>
          <div style={S.header}>
            <div style={S.titulo}>Vicke</div>
            <div style={S.sub}>Verifique seu e-mail</div>
          </div>
          <div style={S.card}>
            <div style={{ fontSize:13.5, color:"#374151", lineHeight:1.6, textAlign:"center" }}>
              Se houver uma conta com o e-mail informado, você receberá em instantes um link para redefinir sua senha.
            </div>
            <div style={{ fontSize:12, color:"#9ca3af", lineHeight:1.5, marginTop:14, textAlign:"center" }}>
              O link expira em 1 hora. Verifique também a pasta de spam.
            </div>
          </div>
          <div style={S.linkSec}>
            <button style={S.linkBtn} onClick={onVoltar}>← Voltar para o login</button>
          </div>
          <div style={S.rodape}>Vicke — Conectando elos</div>
        </div>
      </div>
    );
  }

  return (
    <div style={S.wrap}>
      <div style={S.box}>
        <div style={S.header}>
          <div style={S.titulo}>Vicke</div>
          <div style={S.sub}>Recuperar senha</div>
        </div>
        <div style={S.card}>
          <div style={{ fontSize:12.5, color:"#6b7280", lineHeight:1.5, marginBottom:16 }}>
            Digite o e-mail da sua conta. Vamos te enviar um link para criar uma nova senha.
          </div>
          <div style={S.grupo}>
            <label style={S.label}>E-mail</label>
            <input
              style={S.input}
              type="email"
              placeholder="seu@email.com"
              value={email}
              onChange={ev => setEmail(ev.target.value)}
              onKeyDown={handleKey}
              autoFocus
            />
          </div>
          <button style={S.btn} onClick={handleEnviar} disabled={loading}>
            {loading ? "Enviando..." : "Enviar link"}
          </button>
          {erro && <div style={S.erro}>{erro}</div>}
        </div>
        <div style={S.linkSec}>
          <button style={S.linkBtn} onClick={onVoltar}>← Voltar para o login</button>
        </div>
        <div style={S.rodape}>Vicke — Conectando elos</div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// 5. Tela de Redefinir Senha (com token vindo do link do email)
// ═══════════════════════════════════════════════════════════════
function TelaRedefinirSenha({ token, onConcluido }) {
  const [senha, setSenha]                 = useState("");
  const [confirmar, setConfirmar]         = useState("");
  const [mostrarSenha, setMostrarSenha]   = useState(false);
  const [erro, setErro]                   = useState("");
  const [loading, setLoading]             = useState(false);
  const [sucesso, setSucesso]             = useState(false);
  const S = getEstilos(loading);

  async function handleRedefinir() {
    if (!token) { setErro("Link inválido ou expirado."); return; }
    if (senha.length < 8) { setErro("A senha precisa ter pelo menos 8 caracteres."); return; }
    if (senha !== confirmar) { setErro("As senhas não coincidem."); return; }
    setErro("");
    setLoading(true);
    try {
      const res = await apiPost("/auth/redefinir-senha", { token, senha_nova: senha });
      if (res.ok) {
        setSucesso(true);
        // Volta pro login automaticamente após 2.5s
        setTimeout(onConcluido, 2500);
      } else {
        setErro(res.error || "Não foi possível redefinir a senha.");
      }
    } catch (e) {
      console.error("Erro redefinir senha:", e);
      setErro("Não foi possível conectar ao servidor.");
    }
    setLoading(false);
  }

  function handleKey(ev) { if (ev.key === "Enter") handleRedefinir(); }

  // Sem token na URL — usuário caiu aqui sem clicar no link válido.
  // Não acontece em fluxo normal (TelaLogin só roteia aqui se tiver token).
  // Mas defesa em profundidade.
  if (!token) {
    return (
      <div style={S.wrap}>
        <div style={S.box}>
          <div style={S.header}>
            <div style={S.titulo}>Vicke</div>
            <div style={S.sub}>Link inválido</div>
          </div>
          <div style={S.card}>
            <div style={{ fontSize:13.5, color:"#374151", lineHeight:1.6, textAlign:"center" }}>
              Este link de redefinição de senha não é válido ou já foi usado.
            </div>
          </div>
          <div style={S.linkSec}>
            <button style={S.linkBtn} onClick={onConcluido}>← Voltar para o login</button>
          </div>
          <div style={S.rodape}>Vicke — Conectando elos</div>
        </div>
      </div>
    );
  }

  if (sucesso) {
    return (
      <div style={S.wrap}>
        <div style={S.box}>
          <div style={S.header}>
            <div style={S.titulo}>Vicke</div>
            <div style={S.sub}>Senha redefinida</div>
          </div>
          <div style={S.card}>
            <div style={{ display:"flex", justifyContent:"center", marginBottom:14 }}>
              <div style={{
                width:48, height:48, borderRadius:"50%",
                background:"#111", color:"#fff",
                display:"flex", alignItems:"center", justifyContent:"center",
              }}>
                <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                  <polyline points="20 6 9 17 4 12"/>
                </svg>
              </div>
            </div>
            <div style={{ fontSize:14, fontWeight:600, color:"#111", textAlign:"center", marginBottom:6 }}>
              Pronto!
            </div>
            <div style={{ fontSize:13, color:"#6b7280", textAlign:"center", lineHeight:1.5 }}>
              Sua senha foi redefinida. Você já pode entrar com a nova senha.
            </div>
          </div>
          <div style={S.rodape}>Vicke — Conectando elos</div>
        </div>
      </div>
    );
  }

  return (
    <div style={S.wrap}>
      <div style={S.box}>
        <div style={S.header}>
          <div style={S.titulo}>Vicke</div>
          <div style={S.sub}>Crie uma nova senha</div>
        </div>
        <div style={S.card}>
          <div style={{ fontSize:12.5, color:"#6b7280", lineHeight:1.5, marginBottom:16 }}>
            Digite a nova senha que você quer usar a partir de agora. Mínimo de 8 caracteres.
          </div>
          <div style={S.grupo}>
            <label style={S.label}>Nova senha</label>
            <div style={{ position:"relative" }}>
              <input
                style={{ ...S.input, paddingRight: 40 }}
                type={mostrarSenha ? "text" : "password"}
                placeholder="••••••••"
                value={senha}
                onChange={ev => setSenha(ev.target.value)}
                onKeyDown={handleKey}
                autoFocus
              />
              <button
                type="button"
                onClick={() => setMostrarSenha(v => !v)}
                aria-label={mostrarSenha ? "Ocultar senha" : "Mostrar senha"}
                style={{
                  position:"absolute", right: 8, top:"50%", transform:"translateY(-50%)",
                  background:"none", border:"none", padding: 6, cursor:"pointer",
                  color:"#9ca3af", display:"flex", alignItems:"center", justifyContent:"center",
                  borderRadius: 6,
                }}>
                {mostrarSenha ? (
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"/>
                    <line x1="1" y1="1" x2="23" y2="23"/>
                  </svg>
                ) : (
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/>
                    <circle cx="12" cy="12" r="3"/>
                  </svg>
                )}
              </button>
            </div>
          </div>
          <div style={S.grupo}>
            <label style={S.label}>Confirmar nova senha</label>
            <input
              style={S.input}
              type={mostrarSenha ? "text" : "password"}
              placeholder="••••••••"
              value={confirmar}
              onChange={ev => setConfirmar(ev.target.value)}
              onKeyDown={handleKey}
            />
          </div>
          <button style={S.btn} onClick={handleRedefinir} disabled={loading}>
            {loading ? "Redefinindo..." : "Redefinir senha"}
          </button>
          {erro && <div style={S.erro}>{erro}</div>}
        </div>
        <div style={S.linkSec}>
          <button style={S.linkBtn} onClick={onConcluido}>← Voltar para o login</button>
        </div>
        <div style={S.rodape}>Vicke — Conectando elos</div>
      </div>
    </div>
  );
}


// ════════════════════════════════════════════════════════════
// mensagens.jsx
// ════════════════════════════════════════════════════════════

// ═══════════════════════════════════════════════════════════════
// MENSAGENS — Caixa de email do Time VICKE (Sprint 3 Bloco E)
// ═══════════════════════════════════════════════════════════════
// Master vê todas as mensagens recebidas em qualquer endereço
// @vicke.com.br (time@, contato@, suporte@, etc).
// Webhook do Resend salva tudo na tabela mensagem_recebida; aqui
// listamos, lemos detalhe e marcamos como lida/excluímos.
//
// Layout 2 colunas estilo email client:
//   - Esquerda: lista de threads (remetente, assunto, preview, data)
//   - Direita: detalhe da mensagem selecionada (HTML renderizado)
//
// Backend endpoints:
//   GET    /admin/mensagens               — lista paginada
//   GET    /admin/mensagens/:id           — detalhe completo
//   PUT    /admin/mensagens/:id/lida      — marca como lida
//   PUT    /admin/mensagens/:id/nao-lida  — marca como não lida
//   DELETE /admin/mensagens/:id           — apaga

function Mensagens({ usuario }) {
  const [mensagens, setMensagens] = useState([]);
  const [naoLidas, setNaoLidas]   = useState(0);
  const [loading, setLoading]     = useState(true);
  const [erro, setErro]           = useState(null);
  const [filtro, setFiltro]       = useState("todas"); // "todas" | "nao-lidas"
  // Mensagem selecionada (objeto com body completo carregado sob demanda)
  const [selecionada, setSelecionada] = useState(null);
  const [carregandoDet, setCarregandoDet] = useState(false);
  // Modal de Responder
  const [respondendo, setRespondendo]       = useState(null); // mensagem a responder, ou null
  const [respAssunto, setRespAssunto]       = useState("");
  const [respCorpo, setRespCorpo]           = useState("");
  const [enviandoResp, setEnviandoResp]     = useState(false);

  // Carrega lista quando filtro muda ou ao montar
  useEffect(() => {
    carregarLista();
    // Polling a cada 30s pra detectar novas mensagens.
    // Não é tempo real (precisaria SSE/WebSocket), mas pra volume baixo
    // de email do Master é suficiente e simples.
    const t = setInterval(carregarLista, 30000);
    return () => clearInterval(t);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [filtro]);

  async function carregarLista() {
    try {
      const filtroParam = filtro === "nao-lidas" ? "nao-lidas" : null;
      const data = await api.admin.mensagens.list(filtroParam);
      // api retorna json.data direto (req() já desempacota), então `data` aqui
      // é { mensagens, total, nao_lidas }
      setMensagens(data.mensagens || []);
      setNaoLidas(data.nao_lidas || 0);
    } catch (e) {
      console.error("Erro carregar mensagens:", e);
      setErro(e.message);
    }
    setLoading(false);
  }

  async function abrirMensagem(msg) {
    // Otimista: já mostra os dados que temos (preview, etc)
    setSelecionada(msg);
    setCarregandoDet(true);
    try {
      const detalhe = await api.admin.mensagens.get(msg.id);
      setSelecionada(detalhe);
      // Se ainda não lida, marca como lida automaticamente ao abrir
      if (!detalhe.lida) {
        await api.admin.mensagens.marcarLida(msg.id);
        // Atualiza lista local sem refetch
        setMensagens(ms => ms.map(m => m.id === msg.id ? { ...m, lida: true } : m));
        setNaoLidas(n => Math.max(0, n - 1));
      }
    } catch (e) {
      console.error("Erro ao abrir mensagem:", e);
    }
    setCarregandoDet(false);
  }

  async function marcarNaoLida(msg) {
    try {
      await api.admin.mensagens.marcarNaoLida(msg.id);
      setMensagens(ms => ms.map(m => m.id === msg.id ? { ...m, lida: false } : m));
      setNaoLidas(n => n + 1);
      if (selecionada?.id === msg.id) {
        setSelecionada({ ...selecionada, lida: false });
      }
    } catch (e) {
      toast.erro("Erro ao marcar como não lida");
    }
  }

  async function excluirMensagem(msg) {
    const ok = await dialogo.confirmar({
      titulo: "Excluir mensagem?",
      mensagem: `Esta ação não pode ser desfeita. A mensagem de "${msg.de}" será apagada permanentemente.`,
      confirmar: "Excluir",
      destrutivo: true,
    });
    if (!ok) return;
    try {
      await api.admin.mensagens.delete(msg.id);
      setMensagens(ms => ms.filter(m => m.id !== msg.id));
      if (selecionada?.id === msg.id) setSelecionada(null);
      if (!msg.lida) setNaoLidas(n => Math.max(0, n - 1));
      toast.sucesso("Mensagem excluída");
    } catch (e) {
      toast.erro("Erro ao excluir");
    }
  }

  function abrirResponder(msg) {
    // Pré-preenche o assunto com "Re: " se ainda não tiver.
    // Isso é convenção universal de email reply.
    const assuntoOriginal = msg.assunto || "";
    const novoAssunto = assuntoOriginal.match(/^re:\s/i)
      ? assuntoOriginal
      : `Re: ${assuntoOriginal || "(sem assunto)"}`;

    // Quote do email original (padrão de email client). Usa body_text;
    // se só tem HTML, faz um stripping simples pra não poluir a resposta.
    const dataFormatada = new Date(msg.recebido_em).toLocaleString("pt-BR", {
      day:"2-digit", month:"long", year:"numeric",
      hour:"2-digit", minute:"2-digit",
    });
    let textoOriginal = msg.body_text || "";
    if (!textoOriginal && msg.body_html) {
      // Strip HTML simples — só pra ter algo no quote. Não é parser robusto
      // mas é suficiente pra dar contexto na resposta.
      textoOriginal = msg.body_html
        .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, "")
        .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, "")
        .replace(/<br\s*\/?>/gi, "\n")
        .replace(/<\/p>/gi, "\n\n")
        .replace(/<[^>]+>/g, "")
        .replace(/&nbsp;/g, " ")
        .replace(/&amp;/g, "&")
        .replace(/&lt;/g, "<")
        .replace(/&gt;/g, ">")
        .replace(/\n{3,}/g, "\n\n")
        .trim();
    }
    const quote = textoOriginal
      ? `\n\n\n\nEm ${dataFormatada}, ${msg.de} escreveu:\n${textoOriginal.split("\n").map(l => `> ${l}`).join("\n")}`
      : "";

    setRespondendo(msg);
    setRespAssunto(novoAssunto);
    setRespCorpo(quote);
  }

  function fecharResponder() {
    setRespondendo(null);
    setRespAssunto("");
    setRespCorpo("");
  }

  async function enviarResposta() {
    if (!respondendo) return;
    if (!respAssunto.trim()) {
      toast.erro("Informe o assunto");
      return;
    }
    if (!respCorpo.trim()) {
      toast.erro("Escreva uma mensagem");
      return;
    }
    setEnviandoResp(true);
    try {
      const resp = await api.admin.mensagens.responder(respondendo.id, {
        assunto: respAssunto.trim(),
        corpo: respCorpo,
      });
      toast.sucesso(`Resposta enviada para ${resp.destinatario}`);
      fecharResponder();
    } catch (e) {
      console.error("Erro ao responder:", e);
      toast.erro("Falha ao enviar: " + (e.message || "erro desconhecido"));
    }
    setEnviandoResp(false);
  }

  // Helper: parser do "from" do Resend — vem como "Nome <email@dominio>"
  // Extrai nome (se houver) e email separados pra exibição.
  function parsearRemetente(de) {
    if (!de) return { nome: "", email: "" };
    const match = de.match(/^(.+?)\s*<(.+?)>$/);
    if (match) return { nome: match[1].trim().replace(/^"|"$/g, ""), email: match[2].trim() };
    return { nome: "", email: de.trim() };
  }

  function formatarData(iso) {
    if (!iso) return "";
    const d = new Date(iso);
    const agora = new Date();
    const ms = agora - d;
    const min = Math.floor(ms / 60000);
    const hr = Math.floor(ms / 3600000);
    const dias = Math.floor(ms / 86400000);
    if (min < 1) return "agora";
    if (min < 60) return `${min}m`;
    if (hr < 24) return `${hr}h`;
    if (dias < 7) return `${dias}d`;
    return d.toLocaleDateString("pt-BR", { day: "2-digit", month: "short" });
  }

  const S = {
    wrap: { fontFamily:"'Helvetica Neue',Helvetica,Arial,sans-serif", height:"100vh", display:"flex", flexDirection:"column", background:"#fff" },
    header: { borderBottom:"1px solid #e5e7eb", padding:"20px 32px", display:"flex", justifyContent:"space-between", alignItems:"center" },
    titulo: { fontSize:18, fontWeight:700, color:"#111", margin:0 },
    sub: { fontSize:13, color:"#9ca3af", marginTop:3 },
    filtros: { display:"flex", gap:4, padding:"12px 32px", borderBottom:"1px solid #f3f4f6" },
    btnFiltro: (ativo) => ({
      background: ativo ? "#f3f4f6" : "transparent",
      color: ativo ? "#111" : "#6b7280",
      border: "none",
      borderRadius: 6,
      padding: "6px 12px",
      fontSize: 12.5,
      fontWeight: ativo ? 600 : 400,
      cursor: "pointer",
      fontFamily: "inherit",
    }),
    body: { flex:1, display:"flex", overflow:"hidden" },
    listaCol: { width:380, minWidth:380, borderRight:"1px solid #e5e7eb", overflowY:"auto", background:"#fff" },
    detalheCol: { flex:1, overflowY:"auto", background:"#fafbfc" },
    item: (selecionada, lida) => ({
      padding:"14px 18px",
      borderBottom:"1px solid #f3f4f6",
      cursor:"pointer",
      background: selecionada ? "#f9fafb" : "#fff",
      borderLeft: selecionada ? "3px solid #111" : "3px solid transparent",
      transition: "background 0.1s",
      paddingLeft: selecionada ? 15 : 18,
    }),
    nome: (lida) => ({ fontSize:13, fontWeight: lida ? 400 : 700, color:"#111", marginBottom:2, display:"flex", justifyContent:"space-between", alignItems:"center" }),
    assunto: (lida) => ({ fontSize:13, fontWeight: lida ? 400 : 600, color: lida ? "#374151" : "#111", marginBottom:3, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }),
    preview: { fontSize:12, color:"#9ca3af", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" },
    data: { fontSize:11, color:"#9ca3af", fontWeight:400 },
    pontoNaoLida: { display:"inline-block", width:8, height:8, background:"#3b82f6", borderRadius:"50%", marginRight:8, flexShrink:0 },
    vazio: { fontSize:13, color:"#9ca3af", textAlign:"center", padding:"60px 20px" },

    detHeader: { padding:"24px 32px", borderBottom:"1px solid #e5e7eb", background:"#fff" },
    detAssunto: { fontSize:18, fontWeight:700, color:"#111", marginBottom:12 },
    detLinha: { fontSize:13, color:"#6b7280", marginBottom:4 },
    detLinhaForte: { fontSize:14, color:"#111", fontWeight:500 },
    detAcoes: { display:"flex", gap:8, marginTop:16 },
    detBody: { padding:"32px", background:"#fff", margin:"24px 32px", borderRadius:8, border:"1px solid #f3f4f6" },
    detHtml: { fontSize:14, color:"#111", lineHeight:1.6 },
    btnAcao: { background:"#fff", color:"#374151", border:"1px solid #e5e7eb", borderRadius:7, padding:"6px 12px", fontSize:12.5, cursor:"pointer", fontFamily:"inherit", display:"inline-flex", alignItems:"center", gap:6 },
    btnAcaoPrimaria: { background:"#111", color:"#fff", border:"1px solid #111", borderRadius:7, padding:"6px 14px", fontSize:12.5, fontWeight:600, cursor:"pointer", fontFamily:"inherit", display:"inline-flex", alignItems:"center", gap:6 },
    btnAcaoDestrutiva: { background:"#fff", color:"#dc2626", border:"1px solid #fecaca", borderRadius:7, padding:"6px 12px", fontSize:12.5, cursor:"pointer", fontFamily:"inherit", display:"inline-flex", alignItems:"center", gap:6 },
    badge: { display:"inline-block", fontSize:11, fontWeight:600, color:"#7c3aed", background:"#f5f3ff", border:"1px solid #ddd6fe", borderRadius:10, padding:"2px 8px", marginLeft:8 },
    // Modal de Responder
    overlay: { position:"fixed", inset:0, background:"rgba(0,0,0,0.4)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:20 },
    modal: { background:"#fff", border:"1px solid #e5e7eb", borderRadius:12, width:"100%", maxWidth:680, maxHeight:"85vh", display:"flex", flexDirection:"column", boxShadow:"0 8px 32px rgba(0,0,0,0.12)" },
    modalHeader: { padding:"20px 24px 16px", borderBottom:"1px solid #f3f4f6" },
    modalTitulo: { fontSize:16, fontWeight:700, color:"#111", margin:0 },
    modalBody: { padding:"20px 24px", flex:1, overflowY:"auto", display:"flex", flexDirection:"column", gap:14 },
    modalLabel: { fontSize:11, fontWeight:600, color:"#9ca3af", textTransform:"uppercase", letterSpacing:0.5, marginBottom:4, display:"block" },
    modalInput: { width:"100%", border:"1px solid #e5e7eb", borderRadius:8, padding:"10px 12px", fontSize:13, fontFamily:"inherit", outline:"none", boxSizing:"border-box" },
    modalReadonly: { fontSize:13, color:"#374151", padding:"10px 12px", background:"#f9fafb", border:"1px solid #f3f4f6", borderRadius:8 },
    modalTextarea: { width:"100%", border:"1px solid #e5e7eb", borderRadius:8, padding:"12px", fontSize:13, fontFamily:"inherit", outline:"none", boxSizing:"border-box", minHeight:200, resize:"vertical", lineHeight:1.5 },
    modalFooter: { padding:"14px 24px 18px", borderTop:"1px solid #f3f4f6", display:"flex", justifyContent:"flex-end", gap:10 },
    btnEnviar: { background:"#111", color:"#fff", border:"none", borderRadius:8, padding:"10px 20px", fontSize:13, fontWeight:600, cursor:"pointer", fontFamily:"inherit" },
    btnCancelar: { background:"#fff", color:"#6b7280", border:"1px solid #e5e7eb", borderRadius:8, padding:"10px 20px", fontSize:13, cursor:"pointer", fontFamily:"inherit" },
  };

  if (loading) {
    return (
      <div style={S.wrap}>
        <div style={{ ...S.vazio, paddingTop:120 }}>Carregando mensagens…</div>
      </div>
    );
  }

  return (
    <div style={S.wrap}>
      <div style={S.header}>
        <div>
          <div style={{ display:"flex", alignItems:"center" }}>
            <h1 style={S.titulo}>Mensagens</h1>
            {naoLidas > 0 && <span style={S.badge}>{naoLidas} não {naoLidas === 1 ? "lida" : "lidas"}</span>}
          </div>
          <div style={S.sub}>Caixa de entrada do time VICKE — emails recebidos em @vicke.com.br</div>
        </div>
        <button onClick={carregarLista} style={S.btnAcao}>↻ Atualizar</button>
      </div>

      <div style={S.filtros}>
        <button style={S.btnFiltro(filtro === "todas")} onClick={() => setFiltro("todas")}>
          Todas
        </button>
        <button style={S.btnFiltro(filtro === "nao-lidas")} onClick={() => setFiltro("nao-lidas")}>
          Não lidas{naoLidas > 0 && ` (${naoLidas})`}
        </button>
      </div>

      <div style={S.body}>
        <div style={S.listaCol}>
          {mensagens.length === 0 ? (
            <div style={S.vazio}>
              {filtro === "nao-lidas"
                ? "Nenhuma mensagem não lida."
                : "Nenhuma mensagem ainda. Os emails enviados para qualquer endereço @vicke.com.br aparecerão aqui."}
            </div>
          ) : (
            mensagens.map(m => {
              const { nome, email } = parsearRemetente(m.de);
              const ehSelecionada = selecionada?.id === m.id;
              return (
                <div
                  key={m.id}
                  style={S.item(ehSelecionada, m.lida)}
                  onClick={() => abrirMensagem(m)}
                  onMouseEnter={e => { if (!ehSelecionada) e.currentTarget.style.background = "#fafbfc"; }}
                  onMouseLeave={e => { if (!ehSelecionada) e.currentTarget.style.background = "#fff"; }}
                >
                  <div style={S.nome(m.lida)}>
                    <span style={{ display:"flex", alignItems:"center", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
                      {!m.lida && <span style={S.pontoNaoLida}></span>}
                      {nome || email}
                    </span>
                    <span style={S.data}>{formatarData(m.recebido_em)}</span>
                  </div>
                  <div style={S.assunto(m.lida)}>{m.assunto || "(sem assunto)"}</div>
                  {m.preview && <div style={S.preview}>{m.preview}</div>}
                </div>
              );
            })
          )}
        </div>

        <div style={S.detalheCol}>
          {!selecionada ? (
            <div style={{ ...S.vazio, paddingTop:120 }}>
              Selecione uma mensagem para visualizar
            </div>
          ) : carregandoDet && !selecionada.body_html && !selecionada.body_text ? (
            <div style={{ ...S.vazio, paddingTop:120 }}>Carregando…</div>
          ) : (
            <>
              <div style={S.detHeader}>
                <div style={S.detAssunto}>{selecionada.assunto || "(sem assunto)"}</div>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start" }}>
                  <div>
                    <div style={S.detLinhaForte}>{selecionada.de}</div>
                    <div style={S.detLinha}>
                      Para: {Array.isArray(selecionada.para) ? selecionada.para.join(", ") : (selecionada.para || "")}
                    </div>
                    <div style={S.detLinha}>
                      {new Date(selecionada.recebido_em).toLocaleString("pt-BR", {
                        day:"2-digit", month:"long", year:"numeric",
                        hour:"2-digit", minute:"2-digit",
                      })}
                    </div>
                  </div>
                </div>
                <div style={S.detAcoes}>
                  <button style={S.btnAcaoPrimaria} onClick={() => abrirResponder(selecionada)}>
                    ↪ Responder
                  </button>
                  {selecionada.lida ? (
                    <button style={S.btnAcao} onClick={() => marcarNaoLida(selecionada)}>
                      ↩ Marcar como não lida
                    </button>
                  ) : null}
                  <button style={S.btnAcaoDestrutiva} onClick={() => excluirMensagem(selecionada)}>
                    🗑 Excluir
                  </button>
                </div>
              </div>
              <div style={S.detBody}>
                {selecionada.body_html ? (
                  // HTML renderizado direto. ATENÇÃO: aqui há risco teórico de XSS
                  // se o atacante enviar email com script inline. No futuro vale
                  // adicionar sanitização (DOMPurify ou similar). Pra MVP do
                  // Master só, com poucos remetentes confiáveis, aceitável.
                  <div
                    style={S.detHtml}
                    dangerouslySetInnerHTML={{ __html: selecionada.body_html }}
                  />
                ) : selecionada.body_text ? (
                  <pre style={{ ...S.detHtml, whiteSpace:"pre-wrap", fontFamily:"inherit", margin:0 }}>
                    {selecionada.body_text}
                  </pre>
                ) : (
                  <div style={{ color:"#9ca3af", fontStyle:"italic", fontSize:13 }}>
                    Conteúdo ainda sendo processado pelo servidor… Recarregue em alguns segundos.
                  </div>
                )}
              </div>
            </>
          )}
        </div>
      </div>

      {/* Modal de Responder mensagem */}
      {respondendo && (
        <div style={S.overlay} onClick={(e) => { if (e.target === e.currentTarget && !enviandoResp) fecharResponder(); }}>
          <div style={S.modal} onClick={e => e.stopPropagation()}>
            <div style={S.modalHeader}>
              <h2 style={S.modalTitulo}>Responder mensagem</h2>
            </div>
            <div style={S.modalBody}>
              <div>
                <label style={S.modalLabel}>Para</label>
                <div style={S.modalReadonly}>{respondendo.de}</div>
              </div>
              <div>
                <label style={S.modalLabel}>De</label>
                <div style={S.modalReadonly}>Time VICKE &lt;time@vicke.com.br&gt;</div>
              </div>
              <div>
                <label style={S.modalLabel}>Assunto</label>
                <input
                  style={S.modalInput}
                  value={respAssunto}
                  onChange={e => setRespAssunto(e.target.value)}
                  disabled={enviandoResp}
                />
              </div>
              <div>
                <label style={S.modalLabel}>Mensagem</label>
                <textarea
                  style={S.modalTextarea}
                  value={respCorpo}
                  onChange={e => setRespCorpo(e.target.value)}
                  placeholder="Escreva sua resposta…"
                  disabled={enviandoResp}
                  autoFocus
                />
              </div>
            </div>
            <div style={S.modalFooter}>
              <button style={S.btnCancelar} onClick={fecharResponder} disabled={enviandoResp}>
                Cancelar
              </button>
              <button style={{ ...S.btnEnviar, opacity: enviandoResp ? 0.6 : 1 }} onClick={enviarResposta} disabled={enviandoResp}>
                {enviandoResp ? "Enviando…" : "Enviar resposta"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}


// ════════════════════════════════════════════════════════════
// onboarding.jsx
// ════════════════════════════════════════════════════════════

// ═══════════════════════════════════════════════════════════════
// ONBOARDING — Sprint 3
// ═══════════════════════════════════════════════════════════════
// Tela bloqueante que aparece pra empresas novas (precisa_fazer_onboarding=true).
// Coleta perfil do escritório em 7 perguntas + estado, calcula pct_matriz,
// permite calibragem (digitar valor desejado pra casa exemplo) e salva.
//
// Estilo: vertical scrolling igual Claude.ai. Pergunta clicada → próxima
// aparece logo abaixo com fade-in suave. Pode voltar e mudar respostas
// anteriores — recálculos acontecem automaticamente.
//
// Visual: paleta neutra preto/branco, alinhada ao resto do app.
//
// Backend usa nomenclatura oficial NBR 12721 ("Normal" pro padrão médio),
// mas no UI mostramos "Médio" (mais intuitivo pro usuário). Mapeamento
// fica isolado nas constantes ESTADOS / labels da matriz.

// ── Constantes ─────────────────────────────────────────────────
// Estados que têm CUB coletado (alinhado com ESTADOS_VALIDOS_ONBOARDING do backend)
const ESTADOS_DISPONIVEIS = [
  { sigla: "SP", nome: "São Paulo (SP)" },
  { sigla: "RJ", nome: "Rio de Janeiro (RJ)" },
  { sigla: "MG", nome: "Minas Gerais (MG)" },
  { sigla: "SC", nome: "Santa Catarina (SC)" },
];

// Mapeia chave do backend → label de exibição.
// Padrão: backend manda "medio", mostramos "Maior parte médio padrão".
// Fonte da verdade são os labels que vêm de /api/onboarding/matriz, mas
// mantemos esses fallbacks caso a API esteja indisponível por algum motivo.
const ORDEM_PORTE = ["1-3", "4-10", "11-30", "30+"];
const ORDEM_EXPERIENCIA = ["0-2", "3-5", "6-10", "11-20", "20+"];
// "Referência no mercado" foi renomeada pra "Momento atual da carreira" — escala
// de 7 níveis cobrindo do iniciante ao referência internacional. O nome do
// campo no DB continua sendo `referencia` pra evitar migration de schema.
const ORDEM_REFERENCIA = [
  "iniciando",
  "alguns_projetos",
  "projetos_crescendo",
  "referencia_cidade",
  "referencia_alem",
  "nacional",
  "internacional",
];
const ORDEM_PADRAO = ["baixo", "medio", "alto"];

// ════════════════════════════════════════════════════════════════
// CASA EXEMPLO — usada pra calibragem e simulação
// ════════════════════════════════════════════════════════════════
// Composição "típica" residencial padrão Médio. DEVE BATER com a CASA_EXEMPLO
// definida no backend (server.js). Se mudar uma, mudar a outra — senão o
// pct_calibrado reverso vai sair errado quando o usuário calibrar.
//
// Espelha a estrutura do app real: índices de cômodos vêm de COMODOS de
// shared.jsx, áreas são as do tamanho "Médio".
const CASA_EXEMPLO = {
  comodos: [
    { nome: "Suíte Master",   qtd: 1, indice: 0.05, area: 32.50 }, // 5 × 6.5
    { nome: "Suíte",          qtd: 2, indice: 0.05, area: 25.30 }, // 4.6 × 5.5
    { nome: "Living",         qtd: 1, indice: 0.05, area: 32.00 }, // 8 × 4
    { nome: "Sala de jantar", qtd: 1, indice: 0.05, area: 12.00 }, // 4 × 3
    { nome: "Cozinha",        qtd: 1, indice: 0.08, area: 12.00 }, // 4 × 3
    { nome: "Lavabo",         qtd: 1, indice: 0.05, area:  2.80 }, // 2 × 1.4
    { nome: "Lavanderia",     qtd: 1, indice: 0.05, area:  6.00 }, // 3 × 2
    { nome: "Garagem",        qtd: 2, indice: 0.03, area: 15.60 }, // 5.2 × 3
  ],
  acrescimoCirk: 0.25,
  faixasDesconto: [
    { ate: 200,      desconto: 0.00 },
    { ate: 300,      desconto: 0.30 },
    { ate: 400,      desconto: 0.35 },
    { ate: 500,      desconto: 0.40 },
    { ate: 600,      desconto: 0.45 },
    { ate: Infinity, desconto: 0.50 },
  ],
};

// Calcula honorário da casa exemplo dado o precoBase (R$/m²) e o padrão.
// Reproduz a fórmula do orcamento-teste.jsx: indiceComodos somado, fator
// multiplicador, faixas de desconto progressivas. INDICE_PADRAO: baixo=-0.1,
// medio=0, alto=+0.1 (mesmos valores do shared.jsx).
function calcularCasaExemplo(precoBase, padrao = "medio") {
  const INDICE_PADRAO = { baixo: -0.1, medio: 0, alto: 0.1 };
  const indicePadrao = INDICE_PADRAO[padrao] ?? 0;

  let indiceComodos = 0;
  let areaBruta = 0;
  for (const c of CASA_EXEMPLO.comodos) {
    indiceComodos += c.indice * c.qtd;
    areaBruta     += c.area   * c.qtd;
  }
  indiceComodos = Math.round(indiceComodos * 1000) / 1000;
  const areaTotal = Math.round(areaBruta * (1 + CASA_EXEMPLO.acrescimoCirk) * 100) / 100;
  const fatorMult = Math.round((1 + indiceComodos + indicePadrao) * 1000) / 1000;
  const precoM2Ef = precoBase * fatorMult;

  const faixas = [];
  let acum = 0, rest = areaTotal, total = 0;
  for (const f of CASA_EXEMPLO.faixasDesconto) {
    const chunk = Math.min(rest, f.ate - acum);
    if (chunk <= 0) break;
    const valorChunk = chunk * precoM2Ef * (1 - f.desconto);
    total += valorChunk;
    faixas.push({
      m2: Math.round(chunk * 100) / 100,
      desconto: f.desconto,
      precoM2Efetivo: Math.round(precoM2Ef * (1 - f.desconto) * 100) / 100,
      subtotal: Math.round(valorChunk * 100) / 100,
    });
    rest -= chunk; acum += chunk;
    if (rest <= 0) break;
  }

  return {
    areaBruta:     Math.round(areaBruta * 100) / 100,
    areaTotal,
    indiceComodos,
    indicePadrao,
    fatorMult,
    padrao,
    precoBase:     Math.round(precoBase * 100) / 100,
    precoM2:       Math.round(precoM2Ef * 100) / 100,
    faixas,
    honorario:     Math.round(total * 100) / 100,
  };
}

// Limites pra disparar aviso de "valor absurdo" na calibragem.
const RATIO_MUITO_BAIXO = 0.5;  // valor < 50% do calculado
const RATIO_MUITO_ALTO  = 2.0;  // valor > 200% do calculado

// ── Componente principal ───────────────────────────────────────
function TelaOnboarding({ usuario, onConcluido, onLogout }) {
  // Estado das respostas. null = ainda não respondeu.
  const [profissao, setProfissao]       = useState(null);  // "arquiteto" | "engenheiro"
  const [porte, setPorte]               = useState(null);
  const [experiencia, setExperiencia]   = useState(null);
  const [referencia, setReferencia]     = useState(null);
  const [padrao, setPadrao]             = useState(null);
  const [capital, setCapital]           = useState(null);  // boolean
  const [estado, setEstado]             = useState(null);

  // Matriz vinda do backend (com labels e ratings).
  const [matriz, setMatriz]             = useState(null);
  const [matrizErro, setMatrizErro]     = useState(null);

  // CUB do estado escolhido — buscado quando seleciona estado, usado pro
  // exemplo de cálculo na tela de resumo/calibragem.
  const [cubEstado, setCubEstado]       = useState(null);
  const [cubErro, setCubErro]           = useState(null);

  // Calibragem: null = ainda não decidiu, true = aceita o calculado,
  // false = quer ajustar (mostra campo de input).
  const [aceitouCalculado, setAceitouCalculado] = useState(null);
  const [valorCalibragem, setValorCalibragem]   = useState(""); // string do input
  const [confirmandoAbsurdo, setConfirmandoAbsurdo] = useState(false);

  // Estado de salvamento.
  const [salvando, setSalvando] = useState(false);
  const [erroSalvar, setErroSalvar] = useState(null);

  // Após salvar com sucesso, mostra tela de transição com explicação do
  // que vem em seguida (cadastro do escritório). Usuário clica e libera.
  const [concluido, setConcluido] = useState(false);

  // Ref pra rolar o conteúdo conforme novas perguntas aparecem.
  const containerRef = useRef(null);

  // Busca matriz do backend ao montar.
  useEffect(() => {
    api.onboarding.matriz()
      .then(setMatriz)
      .catch(e => setMatrizErro(e.message || "Falha ao carregar perguntas"));
  }, []);

  // Indicador sutil de "atualizando referências de mercado" mostrado quando
  // o usuário troca de estado pelo resumo lateral. Não limpa o cubEstado
  // anterior — assim a UI não pisca em branco enquanto o fetch roda.
  const [cubLoading, setCubLoading] = useState(false);

  // Busca CUB quando estado é selecionado (pra mostrar exemplo de cálculo).
  useEffect(() => {
    if (!estado) { setCubEstado(null); setCubErro(null); setCubLoading(false); return; }
    setCubErro(null);
    setCubLoading(true);
    // Carrega os 3 níveis de CUB R-1 (Baixo/Normal/Alto) do estado escolhido.
    // O padrão escolhido pelo usuário define qual será usado na simulação:
    // Baixo→Baixo, Médio→Normal, Alto→Alto. Carrega tudo de uma vez pra que
    // a UI possa alternar entre padrões sem fazer fetch novo.
    //
    // IMPORTANTE: NÃO setamos cubEstado(null) antes do fetch — assim a tela
    // não pisca em branco quando o usuário troca de estado pelo resumo lateral.
    // Mantemos o conteúdo antigo até o novo chegar, então substituímos.
    Promise.all([
      api.cub.atual(estado, "R-1", "Baixo"),
      api.cub.atual(estado, "R-1", "Normal"),
      api.cub.atual(estado, "R-1", "Alto"),
    ])
      .then(([baixo, normal, alto]) => {
        setCubEstado({ estado, baixo, normal, alto });
      })
      .catch(e => setCubErro(e.message || "Falha ao carregar referência de mercado"))
      .finally(() => setCubLoading(false));
  }, [estado]);

  // Auto-scroll suave pro fim do conteúdo quando uma pergunta nova aparece.
  // Detectamos "pergunta nova" quando qualquer resposta muda — aí esperamos
  // 1 frame pra DOM atualizar e rolamos.
  const lastAnswerCount = useRef(0);
  useEffect(() => {
    const respondidas = [profissao, porte, experiencia, referencia, padrao, capital, estado].filter(v => v !== null && v !== undefined).length;
    if (respondidas > lastAnswerCount.current) {
      lastAnswerCount.current = respondidas;
      // Esperar 1 tick pra DOM atualizar e medir altura corretamente
      requestAnimationFrame(() => {
        if (containerRef.current) {
          containerRef.current.scrollTo({ top: containerRef.current.scrollHeight, behavior: "smooth" });
        }
      });
    } else {
      lastAnswerCount.current = respondidas;
    }
  }, [profissao, porte, experiencia, referencia, padrao, capital, estado]);

  // Rating efetivo somando as respostas atuais. Retorna null se ainda
  // faltam respostas (não dá pra mostrar resultado).
  const todasRespondidas = profissao && porte && experiencia && referencia && padrao && (capital !== null) && estado;
  const pctMatriz = useMemo(() => {
    if (!matriz || !todasRespondidas) return null;
    return (matriz.profissao?.[profissao]?.rating || 0)
         + (matriz.porte?.[porte]?.rating || 0)
         + (matriz.experiencia?.[experiencia]?.rating || 0)
         + (matriz.referencia?.[referencia]?.rating || 0)
         + (matriz.padrao_projetos?.[padrao]?.rating || 0)
         + (matriz.capital?.[String(capital)]?.rating || 0);
  }, [matriz, profissao, porte, experiencia, referencia, padrao, capital, todasRespondidas]);

  // Cálculo completo da casa exemplo com o PADRÃO escolhido pelo usuário.
  // CUB usado depende do padrão: Baixo→R-1 Baixo, Médio→Normal, Alto→Alto
  // (refletindo realidade do mercado: alto padrão tem custo unitário maior).
  // Quando o padrão muda, simulação atualiza instantaneamente sem refetch
  // porque cubEstado já tem os 3 níveis carregados.
  const cubAtualPorPadrao = useMemo(() => {
    if (!cubEstado) return null;
    return { baixo: cubEstado.baixo, medio: cubEstado.normal, alto: cubEstado.alto }[padrao || "medio"];
  }, [cubEstado, padrao]);

  const casaCalc = useMemo(() => {
    if (pctMatriz === null || !cubAtualPorPadrao) return null;
    const precoBase = pctMatriz * cubAtualPorPadrao.valor_m2;
    return calcularCasaExemplo(precoBase, padrao || "medio");
  }, [pctMatriz, cubAtualPorPadrao, padrao]);
  const honorarioCalculado = casaCalc?.honorario ?? null;

  // Análise da calibragem: valor digitado vs calculado. Como a fórmula nova
  // tem faixas de desconto não-lineares, o pct_calibrado reverso é encontrado
  // por bisseção (igual ao backend faz). Usa o mesmo padrão+CUB da simulação.
  const analiseCalibragem = useMemo(() => {
    if (aceitouCalculado !== false || !valorCalibragem || !honorarioCalculado || !cubAtualPorPadrao) return null;
    const v = parseFloat(String(valorCalibragem).replace(/[^\d,.-]/g, "").replace(",", "."));
    if (!v || v <= 0) return { invalido: true };

    let lo = 0.001, hi = 0.20;
    for (let i = 0; i < 50; i++) {
      const mid = (lo + hi) / 2;
      const honor = calcularCasaExemplo(mid * cubAtualPorPadrao.valor_m2, padrao || "medio").honorario;
      if (honor < v) lo = mid; else hi = mid;
      if (Math.abs(honor - v) < 1) break;
    }
    const pctCalibrado = (lo + hi) / 2;

    const ratio = v / honorarioCalculado;
    return {
      valor: v,
      ratio,
      muitoBaixo: ratio < RATIO_MUITO_BAIXO,
      muitoAlto:  ratio > RATIO_MUITO_ALTO,
      pctCalibrado,
    };
  }, [valorCalibragem, honorarioCalculado, aceitouCalculado, cubAtualPorPadrao, padrao]);

  // Loading / erro inicial.
  if (matrizErro) {
    return (
      <div style={tela}>
        <div style={card}>
          <div style={{ fontSize:15, fontWeight:600, color:"#991b1b", marginBottom:8 }}>Erro ao carregar configuração</div>
          <div style={{ fontSize:13, color:"#6b7280", marginBottom:14 }}>{matrizErro}</div>
          <button onClick={() => location.reload()} style={btnPrimario}>Tentar novamente</button>
          <button onClick={onLogout} style={btnSecundario}>Sair</button>
        </div>
      </div>
    );
  }
  if (!matriz) {
    return (
      <div style={tela}>
        <div style={{ fontSize:13, color:"#9ca3af" }}>Carregando…</div>
      </div>
    );
  }

  // Pode "concluir" quando tudo respondido e:
  //   - aceitou o calculado, OU
  //   - digitou valor de calibragem válido (e confirmou caso seja absurdo)
  const podeConcluir = todasRespondidas && (
    aceitouCalculado === true ||
    (aceitouCalculado === false && analiseCalibragem && !analiseCalibragem.invalido && (
      // Se for absurdo, só pode concluir se já confirmou
      (!analiseCalibragem.muitoBaixo && !analiseCalibragem.muitoAlto) || confirmandoAbsurdo
    ))
  );

  async function handleConcluir() {
    if (!podeConcluir) return;
    setSalvando(true);
    setErroSalvar(null);
    try {
      const valor_calibrado = aceitouCalculado === false && analiseCalibragem && !analiseCalibragem.invalido
        ? analiseCalibragem.valor
        : null;
      await api.onboarding.concluir({
        profissao,
        porte,
        experiencia,
        referencia,
        padrao_projetos: padrao,
        capital,
        estado,
        valor_calibrado,
      });
      // Sucesso → mostra tela de transição. onConcluido() é chamado quando
      // usuário clicar "Continuar para o cadastro" (ver TelaTransicao abaixo).
      setConcluido(true);
    } catch (e) {
      setErroSalvar(e.message || "Falha ao salvar perfil");
    } finally {
      setSalvando(false);
    }
  }

  // Após salvar com sucesso, mostra tela de transição amigável que prepara
  // o usuário pra próxima etapa (cadastro do escritório). Não usa o mesmo
  // layout do questionário porque é momento de "respirar" e celebrar a
  // conclusão antes de seguir.
  if (concluido) {
    return (
      <TelaTransicao
        usuarioNome={usuario?.nome}
        onContinuar={() => onConcluido(estado)}
      />
    );
  }

  return (
    <div ref={containerRef} style={tela}>
      {/* Largura adapta ao modo: 560 pro questionário (perguntas centralizadas e
          legíveis), expande pra 960 quando resultado aparece. */}
      <div style={{
        width:"100%",
        maxWidth: todasRespondidas ? 960 : 560,
        padding: todasRespondidas ? "32px 24px 40px" : "40px 20px 80px",
        transition:"max-width 0.3s ease",
      }}>

        {/* ── Cabeçalho — só aparece enquanto questionário ativo ── */}
        {!todasRespondidas && (
          <div style={{ marginBottom:32 }}>
            <div style={{ fontSize:11, fontWeight:700, color:"#9ca3af", textTransform:"uppercase", letterSpacing:1, marginBottom:8 }}>VICKE</div>
            <div style={{ fontSize:24, fontWeight:300, color:"#111", letterSpacing:-0.5, marginBottom:6 }}>
              Bem-vindo, {(usuario?.nome || "").split(" ")[0]}!
            </div>
            <div style={{ fontSize:14, color:"#6b7280", lineHeight:1.5 }}>
              Configure seu perfil profissional para personalizar seus orçamentos. Vai levar 2 minutos.
            </div>
          </div>
        )}

        {/* ── Questionário (1-7) — escondido quando o resultado aparece ── */}
        {!todasRespondidas && (<>

        {/* ── 1. Profissão ── */}
        <PerguntaBlock pergunta="Qual é a sua profissão?">
          <Opcao
            label={matriz.profissao.arquiteto.label}
            selecionada={profissao === "arquiteto"}
            onClick={() => setProfissao("arquiteto")}
          />
          <Opcao
            label={matriz.profissao.engenheiro.label}
            selecionada={profissao === "engenheiro"}
            onClick={() => setProfissao("engenheiro")}
          />
        </PerguntaBlock>

        {/* ── 2. Porte ── */}
        {profissao && (
          <PerguntaBlock pergunta="Quantas pessoas trabalham no seu escritório?">
            {ORDEM_PORTE.map(k => (
              <Opcao key={k}
                label={matriz.porte[k].label}
                selecionada={porte === k}
                onClick={() => setPorte(k)}
              />
            ))}
          </PerguntaBlock>
        )}

        {/* ── 3. Experiência ── */}
        {porte && (
          <PerguntaBlock pergunta="Quantos anos de experiência tem o(a) profissional responsável?">
            {ORDEM_EXPERIENCIA.map(k => (
              <Opcao key={k}
                label={matriz.experiencia[k].label}
                selecionada={experiencia === k}
                onClick={() => setExperiencia(k)}
              />
            ))}
          </PerguntaBlock>
        )}

        {/* ── 4. Momento atual da carreira ── */}
        {experiencia && (
          <PerguntaBlock
            pergunta="Em que momento da sua carreira você está?"
            sub="Pense no estágio atual, não no que pretende alcançar — você poderá refazer essa calibragem quando seu momento mudar."
          >
            {ORDEM_REFERENCIA
              .filter(k => matriz.referencia?.[k])  // resilência: ignora itens que sumiram da matriz (em vez de quebrar a tela)
              .map(k => (
                <Opcao key={k}
                  label={matriz.referencia[k].label}
                  selecionada={referencia === k}
                  onClick={() => setReferencia(k)}
                />
              ))}
          </PerguntaBlock>
        )}

        {/* ── 5. Padrão de projetos ── */}
        {referencia && (
          <PerguntaBlock pergunta="Qual o padrão da maioria dos seus projetos?">
            {ORDEM_PADRAO.map(k => (
              <Opcao key={k}
                label={matriz.padrao_projetos[k].label}
                selecionada={padrao === k}
                onClick={() => setPadrao(k)}
              />
            ))}
          </PerguntaBlock>
        )}

        {/* ── 6. Capital ── */}
        {padrao && (
          <PerguntaBlock pergunta="Seu escritório está localizado em uma capital?">
            <Opcao
              label={matriz.capital.true.label}
              selecionada={capital === true}
              onClick={() => setCapital(true)}
            />
            <Opcao
              label={matriz.capital.false.label}
              selecionada={capital === false}
              onClick={() => setCapital(false)}
            />
          </PerguntaBlock>
        )}

        {/* ── 7. Estado ── */}
        {capital !== null && (
          <PerguntaBlock
            pergunta="Em qual estado fica o escritório?"
            sub="Usamos os dados do seu estado pra calcular o preço base dos projetos."
          >
            {ESTADOS_DISPONIVEIS.map(e => (
              <Opcao key={e.sigla}
                label={e.nome}
                selecionada={estado === e.sigla}
                onClick={() => setEstado(e.sigla)}
              />
            ))}
          </PerguntaBlock>
        )}

        </>)}{/* ── fim do questionário condicional ── */}

        {/* ── Resultado + calibragem ── */}
        {todasRespondidas && (
          <BlocoResultado
            pctMatriz={pctMatriz}
            cubEstado={cubEstado}
            cubErro={cubErro}
            casaCalc={casaCalc}
            honorarioCalculado={honorarioCalculado}
            aceitouCalculado={aceitouCalculado}
            setAceitouCalculado={setAceitouCalculado}
            valorCalibragem={valorCalibragem}
            setValorCalibragem={(v) => { setValorCalibragem(v); setConfirmandoAbsurdo(false); }}
            analiseCalibragem={analiseCalibragem}
            confirmandoAbsurdo={confirmandoAbsurdo}
            setConfirmandoAbsurdo={setConfirmandoAbsurdo}
            // Respostas atuais (pra resumo lateral) e setters (pra editar)
            respostas={{ profissao, porte, experiencia, referencia, padrao, capital, estado }}
            setters={{ setProfissao, setPorte, setExperiencia, setReferencia, setPadrao, setCapital, setEstado }}
            matriz={matriz}
            containerRef={containerRef}
            cubLoading={cubLoading}
          />
        )}

        {/* ── Botão concluir ── */}
        {todasRespondidas && aceitouCalculado !== null && (
          <div style={{ marginTop:32, paddingTop:24, borderTop:"1px solid #f3f4f6" }}>
            {erroSalvar && (
              <div style={{ fontSize:12.5, color:"#991b1b", background:"#fef2f2", border:"1px solid #fecaca", borderRadius:8, padding:"8px 12px", marginBottom:14 }}>
                {erroSalvar}
              </div>
            )}
            <button
              onClick={handleConcluir}
              disabled={!podeConcluir || salvando}
              style={{
                ...btnPrimario,
                width:"100%",
                opacity: (!podeConcluir || salvando) ? 0.5 : 1,
                cursor: (!podeConcluir || salvando) ? "not-allowed" : "pointer",
              }}>
              {salvando ? "Salvando..." : "Salvar e começar a usar o VICKE"}
            </button>
            <button
              onClick={onLogout}
              disabled={salvando}
              style={{ ...btnSecundario, width:"100%", marginTop:8 }}>
              Sair sem concluir
            </button>
          </div>
        )}

      </div>
    </div>
  );
}

// ── Sub-componentes ────────────────────────────────────────────

// Bloco de uma pergunta + suas opções. Fade-in suave ao montar.
function PerguntaBlock({ pergunta, sub, children }) {
  return (
    <div style={{
      marginTop:28,
      animation:"vk-onb-fade-in 0.35s ease-out",
    }}>
      <style>{`
        @keyframes vk-onb-fade-in {
          from { opacity: 0; transform: translateY(8px); }
          to   { opacity: 1; transform: translateY(0); }
        }
      `}</style>
      <div style={{ fontSize:15, fontWeight:500, color:"#111", marginBottom: sub ? 4 : 12, lineHeight:1.4 }}>
        {pergunta}
      </div>
      {sub && (
        <div style={{ fontSize:12.5, color:"#9ca3af", marginBottom:12, lineHeight:1.5 }}>
          {sub}
        </div>
      )}
      <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
        {children}
      </div>
    </div>
  );
}

// Botão de opção. Quando selecionada, fica destacada com borda preta + check.
function Opcao({ label, selecionada, onClick }) {
  return (
    <button
      onClick={onClick}
      style={{
        display:"flex", alignItems:"center", gap:10,
        padding:"12px 14px",
        background: selecionada ? "#fafbfc" : "#fff",
        border: selecionada ? "1.5px solid #111" : "1px solid #e5e7eb",
        borderRadius:8,
        cursor:"pointer",
        textAlign:"left",
        fontFamily:"inherit",
        fontSize:13.5,
        color:"#111",
        fontWeight: selecionada ? 600 : 400,
        transition:"all 0.12s",
      }}
      onMouseEnter={e => { if (!selecionada) e.currentTarget.style.borderColor="#9ca3af"; }}
      onMouseLeave={e => { if (!selecionada) e.currentTarget.style.borderColor="#e5e7eb"; }}>
      <span style={{
        flexShrink:0,
        width:18, height:18, borderRadius:"50%",
        border: selecionada ? "5px solid #111" : "1.5px solid #d1d5db",
        background:"#fff",
        transition:"all 0.12s",
      }} />
      <span style={{ flex:1 }}>{label}</span>
    </button>
  );
}

// ════════════════════════════════════════════════════════════════
// Bloco final: 2 etapas.
//   Etapa 1: análise digitando + botão "Próximo"
//   Etapa 2: tabela compacta + gráfico waterfall + pergunta calibragem
// ════════════════════════════════════════════════════════════════
function BlocoResultado({
  pctMatriz, cubEstado, cubErro, casaCalc, honorarioCalculado,
  aceitouCalculado, setAceitouCalculado,
  valorCalibragem, setValorCalibragem, analiseCalibragem,
  confirmandoAbsurdo, setConfirmandoAbsurdo,
  respostas, setters, matriz, containerRef, cubLoading,
}) {
  // Etapa atual: 1 = só texto, 2 = simulação completa
  const [etapa, setEtapa] = useState(1);
  // Nota: NÃO resetamos etapa quando casaCalc muda. Edições inline pelo
  // resumo lateral devem só atualizar os valores reativamente — gráfico,
  // tabela e números recalculam sozinhos pelo useMemo do componente pai.

  // Auto-scroll: sempre que conteúdo novo aparece (etapa 2 montada, ou input
  // de calibragem aberto após "Quero ajustar"), rola o container até o final
  // pra mostrar pro usuário que tem mais informação. Espera 1 frame pro DOM
  // atualizar e calcular scrollHeight corretamente antes de rolar.
  useEffect(() => {
    if (!containerRef?.current) return;
    requestAnimationFrame(() => {
      requestAnimationFrame(() => {
        if (containerRef.current) {
          containerRef.current.scrollTo({
            top: containerRef.current.scrollHeight,
            behavior: "smooth",
          });
        }
      });
    });
  }, [etapa, aceitouCalculado, containerRef]);

  if (cubErro) {
    return (
      <div style={{ marginTop:32, padding:"16px 18px", background:"#fef2f2", border:"1px solid #fecaca", borderRadius:8 }}>
        <div style={{ fontSize:13, color:"#991b1b", fontWeight:600, marginBottom:4 }}>Referência indisponível</div>
        <div style={{ fontSize:12.5, color:"#7f1d1d" }}>{cubErro}</div>
      </div>
    );
  }
  if (!cubEstado || honorarioCalculado === null || !casaCalc) {
    return (
      <div style={{ marginTop:32, fontSize:13, color:"#9ca3af" }}>Calculando…</div>
    );
  }

  return (
    <div style={{ animation:"vk-onb-fade-in 0.4s ease-out" }}>
      {/* Header da apresentação — kicker e título lado a lado pra economizar
          altura. Em mobile (telas estreitas) volta a empilhar via CSS. */}
      <div style={{
        display:"flex", flexWrap:"wrap", alignItems:"baseline", gap:14,
        marginBottom: etapa === 1 ? 24 : 8,
      }} className="vk-onb-header">
        <div style={{ fontSize:10.5, fontWeight:700, color:"#9ca3af", textTransform:"uppercase", letterSpacing:1.2, flexShrink:0 }}>
          VICKE · Análise Inteligente
        </div>
        <div style={{ fontSize: etapa === 1 ? 22 : 16, fontWeight:300, color:"#111", letterSpacing:-0.4, lineHeight:1.2, display:"flex", alignItems:"center", gap:10 }}>
          Resultado da sua calibragem
          {/* Indicador sutil quando troca de estado e CUB recarrega — evita
              flash em branco. Spinner pequeno + texto delicado. */}
          {cubLoading && etapa === 2 && (
            <span style={{ display:"inline-flex", alignItems:"center", gap:6, fontSize:11, color:"#9ca3af", fontStyle:"italic", fontWeight:400 }}>
              <span style={{
                display:"inline-block",
                width:10, height:10,
                border:"1.5px solid #e5e7eb",
                borderTopColor:"#6b7280",
                borderRadius:"50%",
                animation:"vk-spin 0.8s linear infinite",
              }} />
              atualizando referências…
            </span>
          )}
        </div>
      </div>

      {/* Etapa 1: layout limpo, sem resumo lateral. Texto centralizado pra
          foco total na apresentação inicial. */}
      {etapa === 1 ? (
        <EtapaTexto casaCalc={casaCalc} onProximo={() => setEtapa(2)} />
      ) : (
        <>
          {/* Linha 1: resumo lateral + tabela */}
          <div style={{
            display:"grid",
            gridTemplateColumns:"minmax(0, 220px) minmax(0, 1fr)",
            gap:12,
            marginBottom:6,
          }} className="vk-onb-grid">
            <ResumoLateral respostas={respostas} setters={setters} matriz={matriz} />
            <TabelaCasaExemplo casaCalc={casaCalc} />
          </div>

          {/* Linha 2: gráfico waterfall */}
          <Waterfall casaCalc={casaCalc} honorarioCalculado={honorarioCalculado} />

          {/* Pergunta de calibragem — IDÊNTICA ao estilo do questionário */}
          <div style={{ marginTop:4, animation:"vk-onb-fade-in 0.3s ease-out" }}>
            <PerguntaBlock pergunta="Esse valor está alinhado com o que você cobraria?">
              <Opcao
                label="Sim, esse valor está bom"
                selecionada={aceitouCalculado === true}
                onClick={() => { setAceitouCalculado(true); setValorCalibragem(""); setConfirmandoAbsurdo(false); }}
              />
              <Opcao
                label="Quero ajustar — eu cobraria valor diferente"
                selecionada={aceitouCalculado === false}
                onClick={() => setAceitouCalculado(false)}
              />
            </PerguntaBlock>

            {aceitouCalculado === false && (
              <div style={{ marginTop:14, animation:"vk-onb-fade-in 0.3s ease-out" }}>
                <div style={{ fontSize:13, color:"#111", marginBottom:8 }}>
                  Quanto você cobraria pela casa de {casaCalc.areaTotal.toLocaleString("pt-BR")}m² descrita acima?
                </div>
                <div style={{ position:"relative", maxWidth:360 }}>
                  <span style={{ position:"absolute", left:14, top:"50%", transform:"translateY(-50%)", fontSize:13, color:"#9ca3af", pointerEvents:"none" }}>R$</span>
                  <input
                    type="text"
                    inputMode="decimal"
                    value={valorCalibragem}
                    onChange={e => setValorCalibragem(e.target.value)}
                    placeholder="20.000,00"
                    autoFocus
                    style={{
                      width:"100%", boxSizing:"border-box",
                      border:"1px solid #e5e7eb", borderRadius:8,
                      padding:"11px 14px 11px 38px",
                      fontSize:14, fontFamily:"inherit", outline:"none",
                      fontVariantNumeric:"tabular-nums",
                    }}
                  />
                </div>

                {analiseCalibragem && !analiseCalibragem.invalido && (analiseCalibragem.muitoBaixo || analiseCalibragem.muitoAlto) && (
                  <div style={{
                    marginTop:14, padding:"12px 14px",
                    background: analiseCalibragem.muitoAlto ? "#fffbeb" : "#fef2f2",
                    border: analiseCalibragem.muitoAlto ? "1px solid #fde68a" : "1px solid #fecaca",
                    borderRadius:8, maxWidth:560,
                  }}>
                    <div style={{ fontSize:12.5, fontWeight:600, color: analiseCalibragem.muitoAlto ? "#92400e" : "#991b1b", marginBottom:6 }}>
                      {analiseCalibragem.muitoAlto ? "Valor parece muito alto" : "Valor parece muito baixo"}
                    </div>
                    <div style={{ fontSize:12, color:"#6b7280", lineHeight:1.5, marginBottom:10 }}>
                      {moeda(analiseCalibragem.valor)} é {analiseCalibragem.ratio.toFixed(1)}× {analiseCalibragem.muitoAlto ? "maior" : "menor"} que o sugerido pela análise ({moeda(honorarioCalculado)}).
                    </div>
                    <label style={{ display:"flex", alignItems:"center", gap:8, fontSize:12.5, color:"#111", cursor:"pointer" }}>
                      <input
                        type="checkbox"
                        checked={confirmandoAbsurdo}
                        onChange={e => setConfirmandoAbsurdo(e.target.checked)}
                        style={{ cursor:"pointer" }}
                      />
                      Confirmo que quero usar esse valor mesmo assim
                    </label>
                  </div>
                )}

                {analiseCalibragem && !analiseCalibragem.invalido && !analiseCalibragem.muitoBaixo && !analiseCalibragem.muitoAlto && (
                  <div style={{ marginTop:12, fontSize:12, color:"#6b7280", lineHeight:1.5 }}>
                    {moeda(analiseCalibragem.valor)} será o seu novo preço de referência.
                  </div>
                )}
              </div>
            )}
          </div>
        </>
      )}

      {/* CSS — animações + responsivo + cursor digitando */}
      <style>{`
        @media (max-width: 720px) {
          .vk-onb-grid { grid-template-columns: 1fr !important; }
        }
        @keyframes vk-bar-grow {
          from { transform: scaleY(0); }
          to   { transform: scaleY(1); }
        }
        @keyframes vk-fade-up {
          from { opacity:0; transform: translateY(6px); }
          to   { opacity:1; transform: translateY(0); }
        }
        @keyframes vk-cursor-blink {
          0%, 49%   { opacity:1; }
          50%, 100% { opacity:0; }
        }
        @keyframes vk-spin {
          to { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
}

// ───────────────────────────────────────────────────────────────
// EtapaTexto: bloco da etapa 1 — texto digitando + botão "Próximo"
// Texto fica ao lado do resumo lateral, ocupando a coluna direita.
// ───────────────────────────────────────────────────────────────
function EtapaTexto({ casaCalc, onProximo }) {
  // Texto pedido pelo usuário — versão analítica e direta. Substitui {valor}
  // pela R$ do preço base.
  const textoAnalise = useMemo(() => {
    return `Cruzamos seu perfil de carreira, porte de escritório, padrão de projetos e localização com a base VICKE de mercado. O preço base sugerido é ${moeda(casaCalc.precoBase)} por m² — ele varia com a complexidade do projeto, sobe com padrão alto e tem desconto progressivo em obras maiores. Veja como isso se aplica numa casa típica:`;
  }, [casaCalc.precoBase]);

  const [chars, setChars] = useState(0);
  const [terminou, setTerminou] = useState(false);

  useEffect(() => {
    setChars(0);
    setTerminou(false);
  }, [textoAnalise]);

  useEffect(() => {
    if (chars >= textoAnalise.length) { setTerminou(true); return; }
    const t = setTimeout(() => setChars(c => c + 1), 22);
    return () => clearTimeout(t);
  }, [chars, textoAnalise]);

  const handleSkip = () => {
    if (!terminou) { setChars(textoAnalise.length); setTerminou(true); }
  };

  // Layout: alinhado à esquerda como o resto da página (texto justificado).
  // O "C" de "Cruzamos" começa alinhado verticalmente com o "R" de "Resultado".
  return (
    <div style={{
      padding: "8px 0 32px",
    }}>
      <div
        onClick={handleSkip}
        style={{
          fontSize:16, color:"#111", lineHeight:1.7,
          maxWidth: 760,
          textAlign:"justify",
          textAlignLast:"left",
          cursor: terminou ? "default" : "pointer",
          marginBottom: 24,
        }}>
        {textoAnalise.slice(0, chars)}
        {!terminou && (
          <span style={{
            display:"inline-block",
            width:2, height:"1em",
            background:"#111",
            verticalAlign:"text-bottom",
            marginLeft:2,
            animation:"vk-cursor-blink 1s steps(2) infinite",
          }} />
        )}
      </div>

      {/* Botão "Próximo" — só habilita quando o texto termina de digitar */}
      <div style={{
        animation: terminou ? "vk-fade-up 0.3s ease-out" : "none",
        opacity: terminou ? 1 : 0,
        transition:"opacity 0.3s",
      }}>
        <button
          onClick={onProximo}
          disabled={!terminou}
          style={{
            background:"#111", color:"#fff",
            border:"none", borderRadius:8,
            padding:"12px 24px",
            fontSize:13, fontWeight:600,
            cursor: terminou ? "pointer" : "default",
            fontFamily:"inherit",
            display:"inline-flex", alignItems:"center", gap:8,
            transition:"background 0.15s",
          }}
          onMouseEnter={e => terminou && (e.currentTarget.style.background = "#000")}
          onMouseLeave={e => terminou && (e.currentTarget.style.background = "#111")}>
          Próximo
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
            <line x1="5" y1="12" x2="19" y2="12"/>
            <polyline points="12 5 19 12 12 19"/>
          </svg>
        </button>
      </div>
    </div>
  );
}

// ───────────────────────────────────────────────────────────────
// ResumoLateral — header preto/branco arredondado, linhas zebra.
// Clicar num campo abre um popover com as opções daquele campo,
// permitindo alterar SEM zerar as respostas posteriores.
// Atualização do gráfico/tabela é automática (state reativo).
// ───────────────────────────────────────────────────────────────
function ResumoLateral({ respostas, setters, matriz }) {
  // Campo atualmente sendo editado (null = nenhum). Quando setado, mostra
  // popover com opções daquele campo. Clicar numa opção atualiza o setter
  // correspondente e fecha o popover.
  const [editando, setEditando] = useState(null);

  // Fecha popover ao clicar fora
  useEffect(() => {
    if (!editando) return;
    const onDocClick = (e) => {
      // Só fecha se o click foi fora de qualquer elemento do resumo lateral
      if (!e.target.closest("[data-resumo-lateral]")) {
        setEditando(null);
      }
    };
    document.addEventListener("mousedown", onDocClick);
    return () => document.removeEventListener("mousedown", onDocClick);
  }, [editando]);

  const labelOu = (cat, key, fallback) => {
    if (key === null || key === undefined) return fallback || "—";
    const k = typeof key === "boolean" ? String(key) : key;
    return matriz?.[cat]?.[k]?.label || fallback || String(key);
  };

  // Cada linha: campo no banco + label exibida + valor formatado + ordem das
  // opções na hora de editar + setter pra aplicar a mudança.
  // Importante: ORDEM das opções deve bater com ORDEM_* do questionário pra
  // experiência consistente (do menos pro mais "alto").
  const linhas = [
    {
      campo: "profissao", label: "Profissão",
      valor: labelOu("profissao", respostas.profissao),
      opcoes: ["arquiteto", "engenheiro"],
      catMatriz: "profissao",
      setter: setters.setProfissao,
    },
    {
      campo: "porte", label: "Porte",
      valor: labelOu("porte", respostas.porte),
      opcoes: ["1-3", "4-10", "11-30", "30+"],
      catMatriz: "porte",
      setter: setters.setPorte,
    },
    {
      campo: "experiencia", label: "Experiência",
      valor: labelOu("experiencia", respostas.experiencia),
      opcoes: ["0-2", "3-5", "6-10", "11-20", "20+"],
      catMatriz: "experiencia",
      setter: setters.setExperiencia,
    },
    {
      campo: "referencia", label: "Momento",
      valor: labelOu("referencia", respostas.referencia),
      opcoes: ["iniciando", "alguns_projetos", "projetos_crescendo", "referencia_cidade", "referencia_alem", "nacional", "internacional"],
      catMatriz: "referencia",
      setter: setters.setReferencia,
    },
    {
      campo: "padrao", label: "Padrão",
      valor: labelOu("padrao_projetos", respostas.padrao),
      opcoes: ["baixo", "medio", "alto"],
      catMatriz: "padrao_projetos",
      setter: setters.setPadrao,
    },
    {
      campo: "capital", label: "Localização",
      valor: labelOu("capital", respostas.capital),
      // capital é boolean — armazenamos a chave como "true"/"false"
      opcoes: ["true", "false"],
      catMatriz: "capital",
      setter: (v) => setters.setCapital(v === "true"),
      valorAtual: String(respostas.capital),
    },
    {
      campo: "estado", label: "Estado",
      valor: respostas.estado || "—",
      // Estado: lista hardcoded (não tem matriz — labels são as siglas)
      opcoes: ["SP", "RJ", "MG", "SC"],
      catMatriz: null,
      setter: setters.setEstado,
    },
  ];

  return (
    <div data-resumo-lateral style={{
      background:"#fff",
      border:"1px solid #e5e7eb",
      borderRadius:10,
      overflow:"visible",  // popover precisa vazar pra fora
      alignSelf:"start",
      boxShadow:"0 1px 2px rgba(0,0,0,0.03)",
      position:"relative",  // popover ancora aqui
    }}>
      {/* Header preto/branco */}
      <div style={{
        background:"#111",
        color:"#fff",
        padding:"7px 12px",
        fontSize:10.5, fontWeight:700, letterSpacing:1, textTransform:"uppercase",
        borderRadius:"10px 10px 0 0",
      }}>
        Suas respostas
      </div>

      {/* Linhas zebra clicáveis */}
      <div>
        {linhas.map((l, i) => {
          const aberto = editando === l.campo;
          const valorAtualKey = l.valorAtual ?? respostas[l.campo];
          return (
            <div key={l.campo} style={{ position:"relative" }}>
              <div
                onClick={() => setEditando(aberto ? null : l.campo)}
                style={{
                  display:"flex", alignItems:"center", justifyContent:"space-between", gap:8,
                  padding:"5px 12px",
                  background: aberto ? "#f3f4f6" : (i % 2 === 0 ? "#fff" : "#fafbfc"),
                  borderTop: i === 0 ? "none" : "1px solid #f3f4f6",
                  borderRadius: i === linhas.length - 1 ? "0 0 10px 10px" : 0,
                  cursor:"pointer",
                  transition:"background 0.12s",
                }}
                onMouseEnter={e => !aberto && (e.currentTarget.style.background = "#f3f4f6")}
                onMouseLeave={e => !aberto && (e.currentTarget.style.background = i % 2 === 0 ? "#fff" : "#fafbfc")}
                title="Clique pra alterar">
                <div style={{ fontSize:9, color:"#9ca3af", textTransform:"uppercase", letterSpacing:0.5, fontWeight:700, flexShrink:0, minWidth:60 }}>
                  {l.label}
                </div>
                <div style={{ fontSize:11, color:"#111", lineHeight:1.25, fontWeight:500, textAlign:"right" }}>
                  {l.valor}
                </div>
              </div>

              {/* Popover com opções desse campo. Anchorado à direita da linha,
                  zIndex alto pra ficar sobre tabela/gráfico. */}
              {aberto && (
                <div style={{
                  position:"absolute",
                  top: 0, left: "calc(100% + 8px)",
                  background:"#fff",
                  border:"1px solid #e5e7eb",
                  borderRadius:8,
                  boxShadow:"0 8px 24px rgba(0,0,0,0.12)",
                  padding:"6px",
                  zIndex: 100,
                  minWidth: 200,
                  animation:"vk-fade-up 0.15s ease-out",
                }}>
                  <div style={{ fontSize:9, color:"#9ca3af", textTransform:"uppercase", letterSpacing:0.5, fontWeight:700, padding:"4px 8px 6px" }}>
                    Alterar {l.label.toLowerCase()}
                  </div>
                  {l.opcoes.map(opt => {
                    const optLabel = l.catMatriz
                      ? (matriz?.[l.catMatriz]?.[opt]?.label || opt)
                      : opt;  // estado: usa a sigla mesmo
                    const selecionada = String(valorAtualKey) === String(opt);
                    return (
                      <div key={opt}
                        onClick={() => {
                          l.setter(opt);
                          setEditando(null);
                        }}
                        style={{
                          padding:"7px 10px",
                          fontSize:12,
                          borderRadius:5,
                          cursor:"pointer",
                          background: selecionada ? "#f3f4f6" : "transparent",
                          color: selecionada ? "#111" : "#374151",
                          fontWeight: selecionada ? 600 : 400,
                          transition:"background 0.1s",
                        }}
                        onMouseEnter={e => !selecionada && (e.currentTarget.style.background = "#f9fafb")}
                        onMouseLeave={e => !selecionada && (e.currentTarget.style.background = "transparent")}>
                        {optLabel}
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ───────────────────────────────────────────────────────────────
// TabelaCasaExemplo: header preto, linhas zebra, tipografia hierárquica.
// ───────────────────────────────────────────────────────────────
function TabelaCasaExemplo({ casaCalc }) {
  const labelPadrao = { baixo: "Baixo", medio: "Médio", alto: "Alto" };

  // Cada linha é uma tupla [label, valor, opcional={destaque, separador}]
  const linhas = [
    { label: "Área útil",                       valor: `${casaCalc.areaBruta.toLocaleString("pt-BR")} m²` },
    { label: "+ 25% circ. + paredes",           valor: `+${(casaCalc.areaTotal - casaCalc.areaBruta).toLocaleString("pt-BR", { maximumFractionDigits: 2 })} m²` },
    { label: "Área total",                      valor: `${casaCalc.areaTotal.toLocaleString("pt-BR")} m²`, divisor: true },
    { label: "Padrão",                          valor: labelPadrao[casaCalc.padrao] || casaCalc.padrao },
    { label: "Preço base",                      valor: `${moeda(casaCalc.precoBase)} / m²` },
    { label: "Preço por m² (com complexidade)", valor: `${moeda(casaCalc.precoM2)} / m²` },
    { label: "Honorário total",                 valor: moeda(casaCalc.honorario), destaque: true, divisor: true },
  ];

  return (
    <div style={{
      background:"#fff",
      border:"1px solid #e5e7eb",
      borderRadius:10,
      overflow:"hidden",
      boxShadow:"0 1px 2px rgba(0,0,0,0.03)",
      animation:"vk-fade-up 0.4s ease-out",
    }}>
      {/* Header preto/branco */}
      <div style={{
        background:"#111", color:"#fff",
        padding:"7px 14px",
        fontSize:10.5, fontWeight:700, letterSpacing:1, textTransform:"uppercase",
      }}>
        Casa simulada
      </div>

      {/* Subtítulo: lista de cômodos */}
      <div style={{ padding:"6px 14px", fontSize:11, color:"#374151", lineHeight:1.4, background:"#fafbfc", borderBottom:"1px solid #f3f4f6" }}>
        3 suítes (1 master) · sala de estar · sala de jantar · cozinha · lavabo · lavanderia · 2 vagas garagem
      </div>

      {/* Linhas zebra */}
      <div>
        {linhas.map((l, i) => (
          <div key={i} style={{
            display:"flex", justifyContent:"space-between", alignItems:"baseline",
            padding: l.destaque ? "7px 14px" : "5px 14px",
            background: l.destaque ? "#f3f4f6" : (i % 2 === 0 ? "#fff" : "#fafbfc"),
            borderTop: l.divisor ? "1px solid #e5e7eb" : (i === 0 ? "none" : "1px solid #f9fafb"),
            fontSize: l.destaque ? 13 : 12,
            fontVariantNumeric:"tabular-nums",
          }}>
            <span style={{ color: l.destaque ? "#111" : "#6b7280", fontWeight: l.destaque ? 700 : 500 }}>
              {l.label}
            </span>
            <span style={{ color:"#111", fontWeight: l.destaque ? 700 : 600 }}>
              {l.valor}
            </span>
          </div>
        ))}
      </div>
    </div>
  );
}

// ───────────────────────────────────────────────────────────────
// Waterfall: SVG full-width, fundo transparente, header preto/branco.
// Cores #3b82f6 (azul) / #22c55e (verde) / #ef4444 (vermelho).
// Animação 700ms crescimento + 900ms entre barras.
// ───────────────────────────────────────────────────────────────
function Waterfall({ casaCalc, honorarioCalculado }) {
  const { areaTotal, indiceComodos, indicePadrao, precoBase } = casaCalc;

  const honorBaseSemFator    = precoBase * areaTotal;
  const honorComComplexidade = precoBase * (1 + indiceComodos) * areaTotal;
  const honorComPadrao       = precoBase * (1 + indiceComodos + indicePadrao) * areaTotal;
  const totalDescontoFaixas  = honorComPadrao - honorarioCalculado;

  const parcelaComplexidade = honorComComplexidade - honorBaseSemFator;
  const parcelaPadrao       = honorComPadrao - honorComComplexidade;

  const steps = [
    { tipo:"base",  label:"Preço base",      sub:`${moeda(precoBase)}/m² × ${areaTotal.toLocaleString("pt-BR")}m²`,
      delta: honorBaseSemFator, acumulado: honorBaseSemFator },
    { tipo:"add",   label:"+ Complexidade",  sub:`${(indiceComodos*100).toFixed(0)}% por ambientes`,
      delta: parcelaComplexidade, acumulado: honorComComplexidade },
    ...(Math.abs(parcelaPadrao) > 1 ? [{
      tipo: parcelaPadrao >= 0 ? "add" : "sub",
      label: parcelaPadrao >= 0 ? "+ Padrão alto" : "− Padrão baixo",
      sub:   parcelaPadrao >= 0 ? "+10% sobre subtotal" : "−10% sobre subtotal",
      delta: parcelaPadrao, acumulado: honorComPadrao,
    }] : []),
    ...(totalDescontoFaixas > 1 ? [{
      tipo:"sub",
      label:"− Desconto progressivo",
      sub:`m² acima de 200`,
      delta: -totalDescontoFaixas, acumulado: honorarioCalculado,
    }] : []),
    { tipo:"total", label:"Honorário final", sub:`casa de ${areaTotal.toLocaleString("pt-BR")}m²`,
      delta: honorarioCalculado, acumulado: honorarioCalculado },
  ];

  // Dimensões compactas. padLeft/padRight maiores que o necessário pras barras
  // pra que os textos centralizados acima/abaixo das barras das pontas (ex.
  // "R$ 90,30/m² × 223,88m²") não cortem nas bordas do SVG.
  const W = 720, H = 160;
  const padTop = 22, padBot = 56, padLeft = 60, padRight = 60;
  const innerW = W - padLeft - padRight;
  const innerH = H - padTop - padBot;
  const barW = Math.min(54, innerW / steps.length - 24);
  const gap  = (innerW - barW * steps.length) / (steps.length - 1);

  const maxValor = Math.max(honorComPadrao, honorarioCalculado, honorBaseSemFator);
  const yScale = (v) => innerH * (v / maxValor);
  const yBase = padTop + innerH;

  // Paleta moderna (#3b82f6 azul, #22c55e verde, #ef4444 vermelho)
  const COR = {
    base:  "#3b82f6",
    add:   "#22c55e",
    sub:   "#ef4444",
    total: "#3b82f6",
  };

  // Animação progressiva — 700ms crescimento + 900ms entre barras
  const [stepRevelado, setStepRevelado] = useState(0);
  useEffect(() => {
    setStepRevelado(0);
    let i = 0;
    const tick = () => {
      i++;
      setStepRevelado(i);
      if (i < steps.length) setTimeout(tick, 900);
    };
    setTimeout(tick, 300);
    // eslint-disable-next-line
  }, [casaCalc.honorario]);

  return (
    <div style={{
      borderRadius:10,
      overflow:"hidden",
      animation:"vk-fade-up 0.4s ease-out",
      background:"transparent",  // fundo transparente conforme pedido
    }}>
      {/* Header preto/branco */}
      <div style={{
        background:"#111", color:"#fff",
        padding:"7px 14px",
        fontSize:10.5, fontWeight:700, letterSpacing:1, textTransform:"uppercase",
        borderRadius:"10px 10px 0 0",
        marginBottom:2,
      }}>
        Como chegamos no valor
      </div>

      {/* SVG sem fundo — herda o background da tela */}
      <div style={{ width:"100%", padding:"2px 0 0" }}>
        <svg viewBox={`0 0 ${W} ${H}`} style={{ width:"100%", height:"auto", display:"block" }}>
          {/* Linha de base sutil */}
          <line x1={padLeft} y1={yBase} x2={W - padRight} y2={yBase} stroke="#e5e7eb" strokeWidth="1" />

          {steps.map((s, i) => {
            const x = padLeft + i * (barW + gap);
            const baseY = (s.tipo === "total" || s.tipo === "base") ? yBase : (yBase - yScale(s.acumulado - s.delta));
            const altura = Math.abs(yScale(s.delta));
            const topY = s.tipo === "sub" ? baseY : baseY - altura;
            const cor = COR[s.tipo] || COR.base;
            const visivel = i < stepRevelado;
            const isTotal = s.tipo === "total";
            const isSub   = s.tipo === "sub";

            // Path da barra com cantos arredondados só de UM lado (topo pra
            // barras normais; fundo pra barras "sub" que crescem pra baixo).
            // Estilo "pílula cortada" — igual ao gráfico de orçamentos do
            // dashboard. Raio adapta à largura da barra (limita a min(altura/2, 12)).
            const r = Math.min(barW * 0.18, altura * 0.5, 12);
            const barPath = isSub
              // Sub: cantos inferiores arredondados, topo reto
              ? `M ${x},${topY} L ${x + barW},${topY} L ${x + barW},${topY + altura - r} Q ${x + barW},${topY + altura} ${x + barW - r},${topY + altura} L ${x + r},${topY + altura} Q ${x},${topY + altura} ${x},${topY + altura - r} Z`
              // Normal/total: cantos superiores arredondados, fundo reto
              : `M ${x + r},${topY} L ${x + barW - r},${topY} Q ${x + barW},${topY} ${x + barW},${topY + r} L ${x + barW},${topY + altura} L ${x},${topY + altura} L ${x},${topY + r} Q ${x},${topY} ${x + r},${topY} Z`;

            return (
              <g key={i} style={{ opacity: visivel ? 1 : 0, transition: "opacity 0.35s" }}>
                {/* Barra com animação suave (700ms, easing bouncy) */}
                <path
                  d={barPath}
                  fill={cor}
                  style={{
                    transformOrigin: `${x + barW/2}px ${baseY}px`,
                    animation: visivel ? `vk-bar-grow 0.7s cubic-bezier(0.34, 1.4, 0.64, 1)` : "none",
                  }}
                />

                {/* Linha pontilhada conectando topo da barra anterior à atual.
                    A barra "total" puxa do topo do acumulado anterior até o topo dela
                    própria (que é igual ao acumulado), fechando visualmente o waterfall. */}
                {i > 0 && visivel && (
                  <line
                    x1={x - gap}
                    y1={isTotal ? yBase - yScale(s.acumulado) : (s.tipo === "sub" ? topY : baseY)}
                    x2={x}
                    y2={isTotal ? yBase - yScale(s.acumulado) : (s.tipo === "sub" ? topY : baseY)}
                    stroke="#9ca3af" strokeWidth="1" strokeDasharray="3,3"
                    style={{ animation: "vk-fade-up 0.4s ease-out 0.5s both" }}
                  />
                )}

                {/* Valor */}
                <text
                  x={x + barW/2}
                  y={s.tipo === "sub" ? baseY + altura + 16 : topY - 8}
                  textAnchor="middle"
                  fontSize="12" fontWeight="700"
                  fill={cor}
                  fontFamily="'Helvetica Neue', Helvetica, Arial, sans-serif"
                  style={{ animation: visivel ? `vk-fade-up 0.4s ease-out 0.5s both` : "none", opacity: visivel ? undefined : 0 }}>
                  {s.tipo === "sub" ? "−" : ""}{moeda(Math.abs(s.delta))}
                </text>

                {/* Label */}
                <text
                  x={x + barW/2}
                  y={H - 36}
                  textAnchor="middle"
                  fontSize="11" fontWeight="600"
                  fill="#374151"
                  fontFamily="'Helvetica Neue', Helvetica, Arial, sans-serif"
                  style={{ animation: visivel ? `vk-fade-up 0.4s ease-out 0.55s both` : "none", opacity: visivel ? undefined : 0 }}>
                  {s.label}
                </text>
                <text
                  x={x + barW/2}
                  y={H - 20}
                  textAnchor="middle"
                  fontSize="10"
                  fill="#9ca3af"
                  fontFamily="'Helvetica Neue', Helvetica, Arial, sans-serif"
                  style={{ animation: visivel ? `vk-fade-up 0.4s ease-out 0.6s both` : "none", opacity: visivel ? undefined : 0 }}>
                  {s.sub}
                </text>

                {/* Seta indicativa: só pra steps de variação (add/sub).
                    Posição: logo ABAIXO da barra de variação (que termina em
                    `baseY` pra add ou `baseY` pra sub também), com folga pra
                    não tocar o label inferior. Centralizada na barra. */}
                {(s.tipo === "add" || s.tipo === "sub") && visivel && (() => {
                  // Ângulo de 40° em radianos pra calcular as pontas
                  const ang = 40 * Math.PI / 180;
                  // Comprimento da diagonal da seta
                  const len = 9;
                  const dx = Math.cos(ang) * len;
                  const dy = Math.sin(ang) * len;

                  // Posição vertical da seta: entre o PÉ visual da barra de
                  // variação e a linha de base do gráfico (yBase).
                  // - add: pé da barra = baseY (que está ACIMA de yBase). Seta
                  //   no meio entre baseY e yBase.
                  // - sub: pé da barra = baseY + altura (também ACIMA de yBase).
                  //   Seta no meio entre (baseY + altura) e yBase.
                  // Em ambos casos, a seta NÃO sobrepõe a barra e fica
                  // claramente separada do label inferior.
                  const peBarra = s.tipo === "sub" ? baseY + altura : baseY;
                  const setaCentroY = (peBarra + yBase) / 2;

                  // Centro horizontal da barra
                  const cx = x + barW / 2;

                  // Pontos da linha (inicia em baixo-esquerda, termina em cima-direita pra add;
                  // ao contrário pra sub)
                  const x1 = cx - dx / 2;
                  const x2 = cx + dx / 2;
                  const y1 = s.tipo === "add" ? setaCentroY + dy / 2 : setaCentroY - dy / 2;
                  const y2 = s.tipo === "add" ? setaCentroY - dy / 2 : setaCentroY + dy / 2;
                  const corSeta = s.tipo === "add" ? "#22c55e" : "#ef4444";
                  const texto   = s.tipo === "add" ? "preço sobe" : "preço desce";

                  // Cabeça da seta
                  const ahLen = 4;
                  const ux = (x2 - x1) / len;
                  const uy = (y2 - y1) / len;
                  const px = -uy;
                  const py = ux;
                  const ahx1 = x2 - ux * ahLen + px * ahLen * 0.6;
                  const ahy1 = y2 - uy * ahLen + py * ahLen * 0.6;
                  const ahx2 = x2 - ux * ahLen - px * ahLen * 0.6;
                  const ahy2 = y2 - uy * ahLen - py * ahLen * 0.6;

                  return (
                    <g style={{ animation: `vk-fade-up 0.4s ease-out 0.65s both` }}>
                      <line
                        x1={x1} y1={y1}
                        x2={x2} y2={y2}
                        stroke={corSeta} strokeWidth="1.3" strokeLinecap="round"
                      />
                      <polygon
                        points={`${x2},${y2} ${ahx1},${ahy1} ${ahx2},${ahy2}`}
                        fill={corSeta}
                      />
                      {/* Texto à direita da seta (não embaixo, pra não invadir o label) */}
                      <text
                        x={x2 + 4}
                        y={s.tipo === "add" ? y2 + 3 : y2 + 3}
                        fontSize="8.5"
                        fill="#111"
                        fontStyle="italic"
                        fontWeight="400"
                        fontFamily="'Helvetica Neue', Helvetica, Arial, sans-serif">
                        {texto}
                      </text>
                    </g>
                  );
                })()}
              </g>
            );
          })}
        </svg>
      </div>
    </div>
  );
}

// Tela exibida após onboarding concluído com sucesso. Prepara o usuário
// pra próxima etapa (cadastro do escritório) explicando POR QUE essas
// informações são necessárias — caso contrário cadastro parece
// "burocrático demais" e usuário pode pular pela aba.
function TelaTransicao({ usuarioNome, onContinuar }) {
  const primeiroNome = (usuarioNome || "").split(" ")[0] || "";
  return (
    <div style={tela}>
      <div style={{ width:"100%", maxWidth:520, padding:"60px 24px", textAlign:"center" }}>
        {/* Ícone de sucesso (check em círculo preto) */}
        <div style={{
          width:56, height:56, borderRadius:"50%",
          background:"#111", color:"#fff",
          display:"flex", alignItems:"center", justifyContent:"center",
          margin:"0 auto 24px",
        }}>
          <svg width="26" height="26" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
            <polyline points="20 6 9 17 4 12"/>
          </svg>
        </div>

        <div style={{ fontSize:22, fontWeight:300, color:"#111", letterSpacing:-0.4, marginBottom:10 }}>
          Tudo certo, {primeiroNome}!
        </div>
        <div style={{ fontSize:14, color:"#6b7280", lineHeight:1.55, marginBottom:36 }}>
          Seu perfil de pricing está configurado. Agora vamos completar o cadastro do seu escritório.
        </div>

        <div style={{
          background:"#fafbfc",
          border:"1px solid #f3f4f6",
          borderRadius:10,
          padding:"20px 22px",
          textAlign:"left",
          marginBottom:32,
        }}>
          <div style={{ fontSize:11, fontWeight:700, color:"#9ca3af", textTransform:"uppercase", letterSpacing:1, marginBottom:12 }}>
            Por que isso importa
          </div>
          <div style={{ fontSize:13, color:"#111", lineHeight:1.7 }}>
            Os dados do escritório (logo, endereço, contatos) aparecem nos seus orçamentos, propostas e PDFs enviados aos clientes. É a sua identidade visual no sistema.
          </div>
        </div>

        <button
          onClick={onContinuar}
          style={{
            ...btnPrimario,
            width:"100%", maxWidth:320,
            padding:"13px 20px", fontSize:14,
          }}>
          Continuar para o cadastro →
        </button>
      </div>
    </div>
  );
}

// ── Estilos compartilhados ─────────────────────────────────────
const tela = {
  position:"fixed", inset:0,
  background:"#fafafa",
  fontFamily:"'Helvetica Neue',Helvetica,Arial,sans-serif",
  overflowY:"auto",
  display:"flex", justifyContent:"center", alignItems:"flex-start",
};
const card = {
  background:"#fff", border:"1px solid #e5e7eb", borderRadius:12,
  padding:"32px 32px 24px", maxWidth:420, width:"100%",
  boxShadow:"0 8px 32px rgba(0,0,0,0.06)",
  margin:"40px 20px",
};
const btnPrimario = {
  background:"#111", color:"#fff", border:"none", borderRadius:8,
  padding:"11px 16px", fontSize:13.5, fontWeight:600, cursor:"pointer",
  fontFamily:"inherit",
};
const btnSecundario = {
  background:"transparent", color:"#6b7280", border:"none",
  padding:"8px", fontSize:12, cursor:"pointer", fontFamily:"inherit",
};
const tdLabel = { color:"#6b7280", padding:"4px 0" };
const tdValor = { textAlign:"right", padding:"4px 0", color:"#111" };

// ── Helpers ────────────────────────────────────────────────────
function moeda(v) {
  if (typeof v !== "number" || !isFinite(v)) return "R$ —";
  return v.toLocaleString("pt-BR", { style:"currency", currency:"BRL" });
}


// ════════════════════════════════════════════════════════════
// orcamento-config.jsx
// ════════════════════════════════════════════════════════════

// ═══════════════════════════════════════════════════════════════
// ORÇAMENTO — Configurações de pricing
// ═══════════════════════════════════════════════════════════════
// Aba "Orçamento" da seção Configuração na sidebar. Por enquanto contém
// apenas o botão de "Resetar e refazer calibragem" — dispara o endpoint
// POST /admin/empresas/:id/reset-onboarding e em seguida refetcha /auth/me
// pra que o app.jsx detecte precisa_fazer_onboarding=TRUE e renderize o
// componente Onboarding direto, sem precisar de logout/login.
//
// Permissões:
// - master e admin podem executar (backend já valida).
// - Outros perfis (editor/visualizador) veem mensagem explicando que
//   precisam de admin/master.

function OrcamentoConfig({ usuario, data, setUsuario }) {
  const [executando, setExecutando] = useState(false);

  // URL base da API. Mesma lógica que escritorio.jsx e shared.jsx —
  // env var Vite com fallback pro Railway prod ativo.
  const _API_URL = (typeof import.meta !== "undefined" && import.meta.env && import.meta.env.VITE_API_URL)
    || "https://orbi-production-5f5c.up.railway.app";

  // Dados frescos do servidor. Não confiamos no localStorage `vicke-user`
  // porque ele pode estar desatualizado (ex: após onboarding que não
  // refetchou). Sempre vai buscar /auth/me ao montar a aba.
  const [me, setMe]               = useState(null);
  const [meLoading, setMeLoading] = useState(true);
  const [meErro, setMeErro]       = useState(null);

  // CUB do estado da empresa (R-1 Normal — referência usada no pricing).
  // Carregado em paralelo com /auth/me. Necessário pra calcular o preço
  // base por m² que aparece em "Preço base aplicado".
  const [cub, setCub] = useState(null);

  async function carregarMe() {
    setMeLoading(true);
    setMeErro(null);
    try {
      const token = localStorage.getItem("vicke-token");
      if (!token) throw new Error("Sessão expirada. Faça login novamente.");
      const res = await fetch(`${_API_URL}/auth/me`, {
        headers: { "Authorization": `Bearer ${token}` },
      });
      const json = await res.json();
      if (!json.ok) throw new Error(json.error || "Falha ao carregar dados");
      setMe(json.data);
      // Carrega CUB do estado retornado pelo backend. Se a empresa ainda não
      // tem estado definido (onboarding incompleto), pula — o card de preço
      // base vai mostrar "—" e tudo bem.
      if (json.data?.estado) {
        try {
          const cubRes = await fetch(
            `${_API_URL}/api/cub/atual?estado=${encodeURIComponent(json.data.estado)}&categoria=R-1&padrao=Normal`,
            { headers: { "Authorization": `Bearer ${token}` } }
          );
          const cubJson = await cubRes.json();
          if (cubJson.ok) setCub(cubJson.data);
          // Se CUB falhar, não interrompe — só não mostra o preço base.
          // Outros campos (profissão, padrão, etc.) continuam visíveis.
        } catch { /* silencioso */ }
      }
    } catch (e) {
      setMeErro(e.message);
    } finally {
      setMeLoading(false);
    }
  }

  useEffect(() => { carregarMe(); /* eslint-disable-next-line */ }, []);

  // Permissão pra disparar o reset: master OU admin (backend valida também,
  // mas escondemos o botão dos outros perfis pra não confundir).
  // Usa `usuario` (props) que já está disponível imediatamente — sem esperar
  // o /auth/me — pra decidir se mostra o botão ou o aviso amigável.
  const podeResetar = usuario?.perfil === "master" || usuario?.nivel === "admin";

  // ID da empresa-alvo. Por enquanto o reset só age sobre a própria empresa
  // do usuário (claim empresa_id do JWT). Master que precisar resetar outra
  // empresa continua usando o drill-in do Admin ou o console.
  const empresaId = me?.empresa_id ?? usuario?.empresa_id;

  // Dados de calibragem atuais. Prioriza `me` (fresco do /auth/me); cai pra
  // `usuario` enquanto carrega. Após o fetch, sempre exibe valores atuais.
  const fonte             = me || usuario || {};
  const pctCalibrado      = fonte.pct_calibrado;
  const pctMatriz         = fonte.pct_matriz_calculado;
  // pct_efetivo: o que de fato vale pro pricing. Se calibrou, usa calibrado;
  // se não, usa o calculado pela matriz.
  const pctEfetivo        = pctCalibrado ?? pctMatriz ?? null;
  const profissao         = fonte.profissao;
  const padraoProjetos    = fonte.padrao_projetos;
  const estado            = fonte.estado;

  // Preço base R$/m² = pct_efetivo × CUB R-1 Normal do estado.
  // É o número que entra na fórmula do orçamento (depois multiplicado pelos
  // índices de cômodos e padrão pra chegar no honorário final).
  const cubValor    = cub?.valor_m2 ?? null;
  const precoBaseM2 = (pctEfetivo != null && cubValor != null) ? pctEfetivo * cubValor : null;

  // Labels amigáveis pros valores brutos do banco
  const labelProfissao = { arquiteto: "Arquiteto(a)", engenheiro: "Engenheiro(a)" };
  const labelPadrao    = { simples: "Simples", medio: "Médio", alto: "Alto", luxo: "Luxo" };

  // Helpers de formatação BR (vírgula em vez de ponto)
  const fmtPct  = (v, casas = 2) => v == null ? null : `${(v * 100).toFixed(casas).replace(".", ",")}%`;
  const fmtBRL  = (v) => v == null ? null : v.toLocaleString("pt-BR", { style: "currency", currency: "BRL" });

  async function executarReset() {
    if (!empresaId) {
      dialogo.alertar({
        titulo: "Empresa não identificada",
        mensagem: "Não foi possível identificar sua empresa. Faça login novamente.",
        tipo: "erro",
      });
      return;
    }

    const confirmou = await dialogo.confirmar({
      titulo: "Resetar e refazer calibragem?",
      mensagem:
        "Isso vai apagar as respostas do onboarding (profissão, porte, padrão, estado, capital) e o pct_calibrado da empresa. " +
        "Você cairá direto na tela de onboarding pra refazer a calibragem — sem precisar fazer login de novo.\n\n" +
        "Os clientes, projetos, orçamentos e dados do escritório NÃO são afetados — apenas a calibragem de pricing.",
      confirmar: "Resetar calibragem",
      destrutivo: true,
    });
    if (!confirmou) return;

    setExecutando(true);
    try {
      const token = localStorage.getItem("vicke-token");
      if (!token) throw new Error("Sessão expirada. Faça login novamente.");

      const res = await fetch(`${_API_URL}/admin/empresas/${empresaId}/reset-onboarding`, {
        method: "POST",
        headers: {
          "Authorization": `Bearer ${token}`,
          "Content-Type": "application/json",
        },
      });
      const json = await res.json();
      if (!json.ok) throw new Error(json.error || "Falha ao resetar onboarding");

      // Sucesso: refetch /auth/me pra trazer estado atualizado (precisa_fazer_onboarding=true,
      // campos zerados). Atualizar setUsuario faz o app.jsx detectar a flag e
      // renderizar <Onboarding /> automaticamente — sem logout, sem reload.
      // Se o usuário fechar a aba/navegador depois disso, o token ainda vale (não foi
      // invalidado), mas ao reabrir, /auth/me vai retornar precisa_fazer_onboarding=true
      // e ele vai cair no onboarding direto após login.
      const meRes = await fetch(`${_API_URL}/auth/me`, {
        headers: { "Authorization": `Bearer ${token}` },
      });
      const meJson = await meRes.json();
      if (!meJson.ok) throw new Error(meJson.error || "Falha ao recarregar dados do usuário");

      // Atualiza state global + localStorage. React vai rerenderizar e o
      // app.jsx vai detectar precisa_fazer_onboarding=true automaticamente.
      if (typeof setUsuario === "function") {
        setUsuario(meJson.data);
      }
      try { localStorage.setItem("vicke-user", JSON.stringify(meJson.data)); } catch {}
      // Não precisa de modal de "sucesso" — a transição visual pra tela de
      // onboarding já é o feedback. Se ficar muito instantâneo, dá pra
      // adicionar um toast leve aqui no futuro.
    } catch (e) {
      dialogo.alertar({
        titulo: "Erro ao resetar calibragem",
        mensagem: e.message,
        tipo: "erro",
      });
    } finally {
      setExecutando(false);
    }
  }

  // Estilos — mesma paleta minimalista do escritorio.jsx pra manter
  // consistência visual entre as abas de Configuração.
  const S = {
    wrap:     { fontFamily:"'Helvetica Neue',Helvetica,Arial,sans-serif", background:"#fff", minHeight:"100vh", color:"#111", maxWidth:1200, margin:"0 auto" },
    header:   { borderBottom:"1px solid #e5e7eb", padding:"24px 32px" },
    titulo:   { fontSize:18, fontWeight:700, color:"#111", margin:0 },
    sub:      { fontSize:13, color:"#9ca3af", marginTop:3 },
    body:     { padding:"32px", maxWidth:760 },
    secao:    { marginBottom:32 },
    secTitulo:{ fontSize:11, fontWeight:700, color:"#9ca3af", textTransform:"uppercase", letterSpacing:1, marginBottom:16 },
    label:    { fontSize:11, color:"#9ca3af", textTransform:"uppercase", letterSpacing:0.5, marginBottom:4 },
    valor:    { fontSize:14, color:"#111" },
    vazio:    { fontSize:14, color:"#d1d5db", fontStyle:"italic" },
    grid2:    { display:"grid", gridTemplateColumns:"1fr 1fr", gap:16, marginBottom:18 },
    btn:      { background:"#111", color:"#fff", border:"none", borderRadius:8, padding:"10px 20px", fontSize:13, fontWeight:600, cursor:"pointer", fontFamily:"inherit" },
    btnDanger:{ background:"#fff", color:"#dc2626", border:"1px solid #fecaca", borderRadius:8, padding:"10px 20px", fontSize:13, fontWeight:600, cursor:"pointer", fontFamily:"inherit" },
    aviso:    { fontSize:13, color:"#6b7280", lineHeight:1.6, background:"#fafbfc", border:"1px solid #f3f4f6", borderRadius:8, padding:"14px 16px", marginBottom:16 },
    avisoSemPerm: { fontSize:13, color:"#92400e", lineHeight:1.6, background:"#fffbeb", border:"1px solid #fde68a", borderRadius:8, padding:"14px 16px" },
    // Box de destaque do preço base R$/m². Visualmente diferente das células
    // do grid pra dar peso ao número que importa no dia a dia.
    boxPrecoBase: { background:"#fafbfc", border:"1px solid #e5e7eb", borderRadius:10, padding:"18px 20px", marginTop:4 },
    boxLabel:     { fontSize:11, color:"#6b7280", textTransform:"uppercase", letterSpacing:0.6, fontWeight:600, marginBottom:6 },
    boxValor:     { fontSize:28, fontWeight:700, color:"#111", lineHeight:1, display:"flex", alignItems:"baseline", gap:6 },
    boxUnidade:   { fontSize:14, fontWeight:500, color:"#9ca3af" },
    boxFormula:   { fontSize:12, color:"#9ca3af", marginTop:8 },
  };

  // Helper de exibição: se o valor for nulo/vazio, mostra "—" cinza itálico
  const Campo = ({ label, valor }) => (
    <div>
      <div style={S.label}>{label}</div>
      {valor != null && valor !== "" ? <div style={S.valor}>{valor}</div> : <div style={S.vazio}>—</div>}
    </div>
  );

  return (
    <div style={S.wrap}>
      {/* Header */}
      <div style={S.header}>
        <div style={S.titulo}>Orçamento</div>
        <div style={S.sub}>Configurações de pricing e calibragem</div>
      </div>

      {/* Conteúdo */}
      <div style={S.body}>
        <div style={S.secao}>
          <div style={S.secTitulo}>Calibragem atual</div>

          {meErro && (
            <div style={{ ...S.avisoSemPerm, marginBottom: 12 }}>
              Não foi possível carregar os dados frescos: {meErro}.
              {" "}<a href="#" onClick={(e) => { e.preventDefault(); carregarMe(); }} style={{ color:"#92400e", fontWeight:600 }}>Tentar novamente</a>
            </div>
          )}

          <div style={S.grid2}>
            <Campo label="Profissão"           valor={labelProfissao[profissao] || profissao} />
            <Campo label="Padrão dos projetos" valor={labelPadrao[padraoProjetos] || padraoProjetos} />
            <Campo label="Estado"              valor={estado} />
            <Campo
              label="Percentual aplicado"
              valor={
                pctEfetivo != null
                  ? `${fmtPct(pctEfetivo)}${pctCalibrado != null ? " (calibrado)" : " (matriz)"}`
                  : null
              }
            />
          </div>

          {/* Box de destaque do preço base R$/m² — número que entra na fórmula
              do orçamento (depois multiplicado pelos índices e tamanho da casa
              pra chegar no honorário final). É o que importa no dia a dia. */}
          <div style={S.boxPrecoBase}>
            <div style={S.boxLabel}>Preço base do m²</div>
            <div style={S.boxValor}>
              {precoBaseM2 != null ? fmtBRL(precoBaseM2) : <span style={S.vazio}>—</span>}
              {precoBaseM2 != null && <span style={S.boxUnidade}>/m²</span>}
            </div>
            {pctEfetivo != null && cubValor != null && (
              <div style={S.boxFormula}>
                {fmtPct(pctEfetivo)} × {fmtBRL(cubValor)} (CUB R-1 Normal {estado})
              </div>
            )}
          </div>

          {meLoading && (
            <div style={{ fontSize:12, color:"#9ca3af", marginTop:12 }}>Atualizando…</div>
          )}
        </div>

        <div style={S.secao}>
          <div style={S.secTitulo}>Refazer calibragem</div>

          {!podeResetar ? (
            <div style={S.avisoSemPerm}>
              Apenas <strong>master</strong> ou <strong>administradores</strong> da empresa podem resetar a calibragem.
              Peça pro responsável da sua empresa fazer o reset.
            </div>
          ) : (
            <>
              <div style={S.aviso}>
                Apaga as respostas do onboarding e os percentuais (<code style={{ background:"#fff", padding:"1px 5px", borderRadius:3, border:"1px solid #e5e7eb", fontSize:12 }}>pct_matriz_calculado</code> e <code style={{ background:"#fff", padding:"1px 5px", borderRadius:3, border:"1px solid #e5e7eb", fontSize:12 }}>pct_calibrado</code>) da empresa.
                Você cai direto na tela de onboarding pra refazer a calibragem — sem precisar fazer login novamente.
                Clientes, projetos e orçamentos <strong>não</strong> são afetados.
              </div>
              <button
                onClick={executarReset}
                disabled={executando}
                style={{
                  ...S.btnDanger,
                  opacity: executando ? 0.5 : 1,
                  cursor: executando ? "not-allowed" : "pointer",
                }}>
                {executando ? "Resetando..." : "Resetar e refazer calibragem"}
              </button>
            </>
          )}
        </div>
      </div>
    </div>
  );
}


// ════════════════════════════════════════════════════════════
// app.jsx
// ════════════════════════════════════════════════════════════

// ═══════════════════════════════════════════════════════════════
// DASHBOARD MASTER
// ═══════════════════════════════════════════════════════════════
// Home do usuário master. Faz uma chamada a /admin/dashboard que devolve:
//   - counts: empresas (ativas/total), mensagens não-lidas, signups 7d, logins 24h, logins_falha_24h
//   - feed: últimas 15 entradas do audit_log com nome da empresa
//
// Renderiza:
//   - 4 cards de números no topo
//   - Feed de atividade recente
//   - 4 cards de navegação (mantidos da versão antiga do HomeMenu)
//
// Refresh: a cada 60s automaticamente quando aba está visível, via setInterval.

// ═══════════════════════════════════════════════════════════════
// ÍCONES OUTLINE (estilo Lucide) — usados no Master Dashboard,
// drill-in de empresas, modais de senha. Paleta neutra preto/cinza.
// Tamanho e cor configuráveis. Não importa biblioteca externa pra evitar
// peso de bundle desnecessário.
// ═══════════════════════════════════════════════════════════════
function IconeMaster({ nome, tamanho = 18, cor = "currentColor" }) {
  const props = {
    width: tamanho, height: tamanho,
    viewBox: "0 0 24 24", fill: "none",
    stroke: cor, strokeWidth: "1.8",
    strokeLinecap: "round", strokeLinejoin: "round",
  };
  switch (nome) {
    case "mensagens":
      // Caixa de email (estilo Lucide "inbox")
      return (<svg {...props}><polyline points="22 12 16 12 14 15 10 15 8 12 2 12"/><path d="M5.45 5.11L2 12v6a2 2 0 0 0 2 2h16a2 2 0 0 0 2-2v-6l-3.45-6.89A2 2 0 0 0 16.76 4H7.24a2 2 0 0 0-1.79 1.11z"/></svg>);
    case "feedback":
      // Balão de chat outline
      return (<svg {...props}><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>);
    case "empresas":
      // Building outline
      return (<svg {...props}><rect x="4" y="2" width="16" height="20" rx="2"/><line x1="9" y1="22" x2="9" y2="18"/><line x1="15" y1="22" x2="15" y2="18"/><line x1="9" y1="6" x2="15" y2="6"/><line x1="9" y1="10" x2="15" y2="10"/><line x1="9" y1="14" x2="15" y2="14"/></svg>);
    case "usuarios":
      // Users outline (3 pessoas)
      return (<svg {...props}><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>);
    case "manutencao":
      // Settings/wrench outline
      return (<svg {...props}><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1 0 2.83 2 2 0 0 1-2.83 0l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-2 2 2 2 0 0 1-2-2v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83 0 2 2 0 0 1 0-2.83l.06-.06a1.65 1.65 0 0 0 .33-1.82 1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1-2-2 2 2 0 0 1 2-2h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 0-2.83 2 2 0 0 1 2.83 0l.06.06a1.65 1.65 0 0 0 1.82.33H9a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 2-2 2 2 0 0 1 2 2v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 0 2 2 0 0 1 0 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 2 2 2 2 0 0 1-2 2h-.09a1.65 1.65 0 0 0-1.51 1z"/></svg>);
    case "cub":
      // Trending up — indica índice de custos
      return (<svg {...props}><polyline points="22 7 13.5 15.5 8.5 10.5 2 17"/><polyline points="16 7 22 7 22 13"/></svg>);
    case "editar":
      return (<svg {...props}><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>);
    case "trash":
      return (<svg {...props}><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg>);
    case "key":
      // Chave outline (resetar senha)
      return (<svg {...props}><path d="M21 2l-2 2m-7.61 7.61a5.5 5.5 0 1 1-7.778 7.778 5.5 5.5 0 0 1 7.777-7.777zm0 0L15.5 7.5m0 0l3 3L22 7l-3-3m-3.5 3.5L19 4"/></svg>);
    case "back":
      return (<svg {...props}><line x1="19" y1="12" x2="5" y2="12"/><polyline points="12 19 5 12 12 5"/></svg>);
    case "plus":
      return (<svg {...props}><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>);
    case "check":
      return (<svg {...props}><polyline points="20 6 9 17 4 12"/></svg>);
    case "copy":
      return (<svg {...props}><rect x="9" y="9" width="13" height="13" rx="2" ry="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg>);
    // ── Ícones da sidebar do escritório (perfil cliente) ───────────
    case "home":
      // Casa outline
      return (<svg {...props}><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg>);
    case "painel":
      // Grid 2x2 (dashboard)
      return (<svg {...props}><rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/></svg>);
    case "clientes":
      // 2 pessoas (mais sutil que users de 3)
      return (<svg {...props}><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M22 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>);
    case "projetos":
      // Pasta (folder)
      return (<svg {...props}><path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/></svg>);
    case "projetos-orcamentos":
      // Documento com $
      return (<svg {...props}><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><path d="M12 18v-6M9 15h6"/></svg>);
    case "projetos-andamento":
      // Clipboard com check (em andamento)
      return (<svg {...props}><path d="M9 11l3 3L22 4"/><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/></svg>);
    case "obras":
      // Casa com martelo / construção
      return (<svg {...props}><path d="M3 21h18"/><path d="M5 21V7l7-4 7 4v14"/><path d="M9 9h.01M15 9h.01M9 13h.01M15 13h.01M9 17h.01M15 17h.01"/></svg>);
    case "escritorio":
      // Engrenagem / settings outline (mesmo ícone que manutenção mas menor uso)
      return (<svg {...props}><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1 0 2.83 2 2 0 0 1-2.83 0l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-2 2 2 2 0 0 1-2-2v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83 0 2 2 0 0 1 0-2.83l.06-.06a1.65 1.65 0 0 0 .33-1.82 1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1-2-2 2 2 0 0 1 2-2h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 0-2.83 2 2 0 0 1 2.83 0l.06.06a1.65 1.65 0 0 0 1.82.33H9a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 2-2 2 2 0 0 1 2 2v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 0 2 2 0 0 1 0 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 2 2 2 2 0 0 1-2 2h-.09a1.65 1.65 0 0 0-1.51 1z"/></svg>);
    case "orcamento":
      // Calculadora outline — usado na aba "Orçamento" da seção Configuração
      return (<svg {...props}><rect x="4" y="2" width="16" height="20" rx="2"/><line x1="8" y1="6" x2="16" y2="6"/><line x1="8" y1="10" x2="8" y2="10"/><line x1="12" y1="10" x2="12" y2="10"/><line x1="16" y1="10" x2="16" y2="10"/><line x1="8" y1="14" x2="8" y2="14"/><line x1="12" y1="14" x2="12" y2="14"/><line x1="16" y1="14" x2="16" y2="14"/><line x1="8" y1="18" x2="8" y2="18"/><line x1="12" y1="18" x2="12" y2="18"/><line x1="16" y1="18" x2="16" y2="18"/></svg>);
    default:
      return null;
  }
}

function DashboardMaster({ data, setAba, tentarTrocar }) {
  const [dash, setDash]     = useState(null);
  const [loading, setLoad]  = useState(true);
  const [erro, setErro]     = useState(null);

  // Detecta mobile pra ajustes de layout (padding, grids).
  const [isMobile, setIsMobile] = useState(() => {
    try { return window.innerWidth < 768; } catch { return false; }
  });
  useEffect(() => {
    function onResize() { try { setIsMobile(window.innerWidth < 768); } catch {} }
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);

  // Carrega dashboard. Função separada pra reutilizar no refresh manual.
  async function carregar() {
    try {
      const d = await api.admin.dashboard();
      setDash(d);
      setErro(null);
    } catch(e) {
      setErro(e.message || "Falha ao carregar dashboard");
    } finally {
      setLoad(false);
    }
  }

  useEffect(() => {
    carregar();
    // Auto-refresh a cada 60s. Pausado quando aba não está visível
    // pra economizar bateria/banda.
    const id = setInterval(() => {
      if (document.visibilityState === "visible") carregar();
    }, 60_000);
    return () => clearInterval(id);
  }, []);

  // Cards de navegação (mesmos do HomeMenu antigo). Mantidos pra preservar
  // o atalho de 1-clique pras subabas mais usadas.
  // Cada item tem um identificador de ícone — renderizado por IconeMaster
  // (definido logo abaixo) com SVG outline estilo Lucide, cor neutra.
  const modulos = [
    { k:"mensagens",              icon:"mensagens",  label:"Mensagens",       desc:"Caixa do time VICKE" },
    { k:"admin:feedback",         icon:"feedback",   label:"Feedback",        desc:"Sugestões e bugs dos clientes" },
    { k:"admin:empresas",         icon:"empresas",   label:"Empresas",        desc:"Gerenciar empresas cadastradas" },
    { k:"admin:usuarios-master",  icon:"usuarios",   label:"Usuários Master", desc:"Acessos da equipe Vicke" },
    { k:"admin:manutencao",       icon:"manutencao", label:"Manutenção",      desc:"Jobs e operações do sistema" },
    { k:"admin:cub",              icon:"cub",        label:"CUB",             desc:"Custo Unitário Básico — atualização mensal" },
  ];

  return (
    <div style={{ padding: isMobile ? "16px 14px 60px" : "32px 32px 60px", fontFamily:"'Helvetica Neue',Helvetica,Arial,sans-serif", maxWidth:1100, margin:"0 auto" }}>
      <div style={{ marginBottom: isMobile ? 18 : 28 }}>
        <div style={{ fontSize: isMobile ? 20 : 24, fontWeight:600, color:"#111", letterSpacing:-0.3 }}>Dashboard</div>
        <div style={{ fontSize:13, color:"#9ca3af", marginTop:4 }}>Visão geral da plataforma VICKE</div>
      </div>

      {erro && (
        <div style={{ background:"#fef2f2", border:"1px solid #fecaca", color:"#991b1b", borderRadius:9, padding:"10px 14px", fontSize:13, marginBottom:20 }}>
          Erro ao carregar dashboard: {erro}
        </div>
      )}

      {/* ── 4 Cards de números ── */}
      <DashboardCards counts={dash?.counts} loading={loading} setAba={setAba} tentarTrocar={tentarTrocar} isMobile={isMobile} />

      {/* ── Navegação (acesso rápido sempre acima da dobra) ──
          Movido pra cima do feed: convenção SaaS (Linear/Vercel/Stripe) é
          navegação primária no topo, atividade/feed embaixo. Com volume de
          empresas crescendo, feed pode esticar muito — não pode empurrar
          os cards de navegação pra fora da tela. */}
      <div style={{ fontSize:11, fontWeight:700, color:"#9ca3af", textTransform:"uppercase", letterSpacing:1, marginBottom:12, marginTop:8 }}>Acesso rápido</div>
      {/* Mobile: 2 colunas fixas (cabe 2 cards de ~150px em 375px de viewport).
          Desktop: auto-fill com mínimo 200px (3-6 colunas conforme largura). */}
      <div style={{ display:"grid", gridTemplateColumns: isMobile ? "1fr 1fr" : "repeat(auto-fill, minmax(200px, 1fr))", gap: isMobile ? 8 : 12, marginBottom:32 }}>
        {modulos.map(m => (
          <button key={m.k} onClick={() => { const go = () => setAba(m.k); if (tentarTrocar) tentarTrocar(go); else go(); }}
            style={{ background:"#fff", border:"1px solid #e5e7eb", borderRadius:12, padding: isMobile ? "12px 10px" : "16px", textAlign:"left", cursor:"pointer", fontFamily:"inherit" }}
            onMouseEnter={e => { if (!isMobile) e.currentTarget.style.borderColor="#111"; }}
            onMouseLeave={e => { if (!isMobile) e.currentTarget.style.borderColor="#e5e7eb"; }}>
            <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:4 }}>
              <IconeMaster nome={m.icon} tamanho={isMobile ? 16 : 18} cor="#374151" />
              <div style={{ fontSize: isMobile ? 12 : 13, fontWeight:600, color:"#111" }}>{m.label}</div>
            </div>
            {!isMobile && (
              <div style={{ fontSize:11.5, color:"#9ca3af", marginLeft:28 }}>{m.desc}</div>
            )}
          </button>
        ))}
      </div>

      {/* ── Feed de atividade recente ── */}
      <DashboardFeed feed={dash?.feed} loading={loading} isMobile={isMobile} />
    </div>
  );
}

// 4 Cards de números. Cada card é clicável quando faz sentido (ex: mensagens
// não-lidas leva pra caixa; signups leva pra empresas). Card de logins não tem
// destino útil no momento, fica não-clicável.
function DashboardCards({ counts, loading, setAba, tentarTrocar, isMobile }) {
  const c = counts || {};
  const goto = (aba) => { const fn = () => setAba(aba); if (tentarTrocar) tentarTrocar(fn); else fn(); };

  const items = [
    {
      label: "Empresas ativas",
      value: loading ? "…" : `${c.empresas_ativas || 0}`,
      sub:   loading ? "" : `de ${c.empresas_total || 0} totais`,
      onClick: () => goto("admin:empresas"),
    },
    {
      label: "Mensagens não-lidas",
      value: loading ? "…" : `${c.mensagens_nao_lidas || 0}`,
      sub:   "caixa do time VICKE",
      onClick: () => goto("mensagens"),
      destaque: !loading && (c.mensagens_nao_lidas || 0) > 0,
    },
    {
      label: "Feedback abertos",
      value: loading ? "…" : `${c.feedback_abertos || 0}`,
      sub:   "sugestões/bugs por revisar",
      onClick: () => goto("admin:feedback"),
      destaque: !loading && (c.feedback_abertos || 0) > 0,
    },
    {
      label: "Signups (7 dias)",
      value: loading ? "…" : `${c.signups_7d || 0}`,
      sub:   "novas empresas",
    },
    {
      label: "Logins (24h)",
      value: loading ? "…" : `${c.logins_24h || 0}`,
      sub:   loading ? "" : (c.logins_falha_24h > 0 ? `${c.logins_falha_24h} tentativa(s) falha(s)` : "atividade nas últimas 24h"),
      destaque: !loading && (c.logins_falha_24h || 0) >= 5,
    },
  ];

  return (
    // Mobile: 2 colunas fixas (5 cards => 2-2-1, pode ser feio mas é menos pior
    // que tentar empilhar tudo em 1 coluna gigante).
    // Desktop: auto-fit com mínimo 200px (5 cards lado a lado em telas largas).
    <div style={{ display:"grid", gridTemplateColumns: isMobile ? "1fr 1fr" : "repeat(auto-fit, minmax(200px, 1fr))", gap: isMobile ? 8 : 12, marginBottom: isMobile ? 20 : 28 }}>
      {items.map((it, i) => (
        <div
          key={i}
          onClick={it.onClick}
          style={{
            background:"#fff",
            border: it.destaque ? "1px solid #f59e0b" : "1px solid #e5e7eb",
            borderRadius:12, padding: isMobile ? "12px 12px" : "16px 18px",
            cursor: it.onClick ? "pointer" : "default",
            transition:"border-color 0.12s",
          }}
          onMouseEnter={e => { if (it.onClick && !isMobile) e.currentTarget.style.borderColor = "#111"; }}
          onMouseLeave={e => { if (!isMobile) e.currentTarget.style.borderColor = it.destaque ? "#f59e0b" : "#e5e7eb"; }}>
          <div style={{ fontSize: isMobile ? 10 : 11, fontWeight:600, color:"#9ca3af", textTransform:"uppercase", letterSpacing:0.6, marginBottom: isMobile ? 6 : 8, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
            {it.label}
          </div>
          <div style={{ fontSize: isMobile ? 22 : 28, fontWeight:600, color:"#111", lineHeight:1.1, fontVariantNumeric:"tabular-nums" }}>
            {it.value}
          </div>
          {it.sub && (
            <div style={{ fontSize: isMobile ? 10.5 : 11.5, color:"#9ca3af", marginTop:4, lineHeight:1.3 }}>{it.sub}</div>
          )}
        </div>
      ))}
    </div>
  );
}

// Feed de atividade recente — lista simples, focada em legibilidade.
// Cada linha: ícone (cor por tipo) + descrição + tempo relativo.
//
// maxHeight + overflowY:auto: feed pode crescer indefinidamente conforme
// audit_log acumula. Scroll interno evita empurrar o resto da página.
// 480px caem ~9-10 linhas de feed comodamente, suficiente pra ver atividade
// recente sem sobrecarregar.
function DashboardFeed({ feed, loading, isMobile }) {
  return (
    <div style={{ background:"#fff", border:"1px solid #e5e7eb", borderRadius:12, padding: isMobile ? "12px 14px" : "16px 18px" }}>
      <div style={{ fontSize:11, fontWeight:700, color:"#9ca3af", textTransform:"uppercase", letterSpacing:0.6, marginBottom:14 }}>
        Atividade recente
      </div>
      {loading && <div style={{ fontSize:13, color:"#9ca3af" }}>Carregando…</div>}
      {!loading && (!feed || feed.length === 0) && (
        <div style={{ fontSize:13, color:"#9ca3af", padding:"12px 0" }}>
          Nenhuma atividade ainda.
        </div>
      )}
      {!loading && feed && feed.length > 0 && (
        <div style={{
          display:"flex", flexDirection:"column",
          // Mobile: maxHeight menor (320px ~ 6 linhas) pra não engolir tela toda.
          // Desktop: 480px ~ 9 linhas — espaço suficiente sem sobrecarregar.
          maxHeight: isMobile ? 320 : 480, overflowY:"auto",
          // Compensação visual pra scroll: padding direito pra scrollbar
          // não colar na borda do conteúdo.
          paddingRight:6, marginRight:-6,
        }}>
          {feed.map((ev, i) => (
            <FeedItem key={ev.id} ev={ev} primeiro={i === 0} />
          ))}
        </div>
      )}
    </div>
  );
}

// Linha do feed. Decora o evento com ícone/cor baseado em `acao`.
function FeedItem({ ev, primeiro }) {
  const meta = decorarEvento(ev);
  return (
    <div style={{
      display:"flex", alignItems:"flex-start", gap:12,
      padding:"10px 0",
      borderTop: primeiro ? "none" : "1px solid #f3f4f6",
    }}>
      <div style={{
        flexShrink:0, width:8, height:8, borderRadius:"50%",
        background: meta.cor, marginTop:6,
      }} />
      <div style={{ flex:1, minWidth:0 }}>
        <div style={{ fontSize:13, color:"#111", lineHeight:1.4 }}>
          {meta.descricao}
        </div>
        <div style={{ fontSize:11.5, color:"#9ca3af", marginTop:2 }}>
          {ev.empresa_nome && ev.empresa_nome !== "—" ? `${ev.empresa_nome} · ` : ""}
          {ev.usuario_email || "anônimo"} · {tempoRelativo(ev.criado_em)}
        </div>
      </div>
    </div>
  );
}

// Mapa de cor + texto humano por ação. Centralizar aqui evita switch espalhado.
function decorarEvento(ev) {
  const acao = ev.acao || "";
  const dados = ev.dados || {};

  // Mapas — fáceis de estender quando criarmos eventos novos.
  // Tons sóbrios (não saturados) pra combinar com a paleta minimalista
  // do sistema. Cor é informação semântica essencial em log de eventos
  // (sucesso/falha/atenção visível de relance), mas não precisa berrar.
  const COR_VERDE   = "#0f766e"; // teal-700, mais discreto que green-600
  const COR_VERMELHO= "#991b1b"; // red-800, vinho em vez de vermelho-aviso
  const COR_AZUL    = "#1e3a8a"; // blue-900, marinho
  const COR_LARANJA = "#92400e"; // amber-800, mostarda em vez de laranja
  const COR_CINZA   = "#9ca3af";

  if (acao === "usuario.login_sucesso") return { cor: COR_VERDE,    descricao: "Login bem-sucedido" };
  if (acao === "usuario.login_falha")   return { cor: COR_VERMELHO, descricao: `Login falhou${dados.motivo ? " — " + dados.motivo.replace(/_/g, " ") : ""}` };
  if (acao === "usuario.signup")        return { cor: COR_AZUL,     descricao: `Nova empresa cadastrada: ${dados.empresa_nome || ev.recurso_id}` };
  if (acao === "usuario.senha_alterada") return { cor: COR_LARANJA, descricao: "Senha alterada" };
  if (acao === "usuario.senha_resetada") return { cor: COR_LARANJA, descricao: `Senha resetada por ${dados.alterado_por === "admin_master" ? "master" : "admin de empresa"} (alvo: ${dados.alvo_email || ev.recurso_id})` };
  if (acao === "usuario.troca_senha_falha") return { cor: COR_VERMELHO, descricao: `Tentativa de troca de senha falhou${dados.motivo ? " — " + dados.motivo.replace(/_/g, " ") : ""}` };
  // Recuperação self-service ("Esqueci senha"): solicitação dispara email,
  // redefinição efetiva acontece quando usuário clica no link e cria senha nova.
  if (acao === "usuario.recuperacao_solicitada") return { cor: COR_LARANJA, descricao: `Recuperação de senha solicitada${dados.email_enviado === false ? " (falha no envio)" : ""}` };
  if (acao === "usuario.recuperacao_rate_limit") return { cor: COR_VERMELHO, descricao: "Recuperação bloqueada por rate limit" };
  if (acao === "usuario.senha_redefinida") return { cor: COR_VERDE, descricao: "Senha redefinida via recuperação" };
  if (acao === "usuario.email_alterado") return { cor: COR_LARANJA, descricao: "Email alterado" };
  if (acao === "usuario.nivel_alterado") return { cor: COR_LARANJA, descricao: `Nível alterado: ${dados.antes?.nivel} → ${dados.depois?.nivel}` };
  if (acao === "usuario.criado")        return { cor: COR_VERDE,    descricao: `Usuário criado: ${dados.email || ev.recurso_id}` };
  if (acao === "usuario.editado")       return { cor: COR_CINZA,    descricao: "Usuário editado" };
  if (acao === "usuario.desativado")    return { cor: COR_LARANJA, descricao: "Usuário desativado" };
  if (acao === "usuario.reativado")     return { cor: COR_VERDE,    descricao: "Usuário reativado" };
  if (acao === "usuario.excluido")      return { cor: COR_VERMELHO, descricao: `Usuário excluído: ${dados.snapshot?.email || ev.recurso_id}` };
  if (acao === "empresa.criada")        return { cor: COR_VERDE,    descricao: `Empresa criada: ${dados.nome || ev.recurso_id}` };
  if (acao === "empresa.editada")       return { cor: COR_CINZA,    descricao: "Empresa editada" };
  if (acao === "empresa.desativada")    return { cor: COR_LARANJA, descricao: "Empresa desativada" };
  if (acao === "empresa.reativada")     return { cor: COR_VERDE,    descricao: "Empresa reativada" };
  if (acao === "empresa.excluida")      return { cor: COR_VERMELHO, descricao: `Empresa excluída: ${dados.snapshot?.nome || ev.recurso_id}` };
  if (acao === "cliente.excluido")      return { cor: COR_VERMELHO, descricao: `Cliente excluído: ${dados.snapshot?.nome || ev.recurso_id}` };
  if (acao === "orcamento.excluido")    return { cor: COR_VERMELHO, descricao: `Orçamento excluído: ${ev.recurso_id}` };
  if (acao === "obra.excluida")         return { cor: COR_VERMELHO, descricao: `Obra excluída: ${ev.recurso_id}` };
  if (acao === "fornecedor.excluido")   return { cor: COR_VERMELHO, descricao: `Fornecedor excluído: ${ev.recurso_id}` };
  if (acao === "lancamento.excluido")   return { cor: COR_VERMELHO, descricao: `Lançamento excluído: ${ev.recurso_id}` };

  // Feedback in-app
  if (acao === "feedback.enviado")        return { cor: COR_AZUL, descricao: `Feedback (${dados.categoria || "outro"}): "${(dados.texto_preview || "").slice(0, 60)}${(dados.texto_preview || "").length > 60 ? "…" : ""}"` };
  if (acao === "feedback.status_alterado") return { cor: COR_CINZA, descricao: `Feedback ${ev.recurso_id}: ${dados.de} → ${dados.para}` };
  if (acao === "feedback.excluido")        return { cor: COR_VERMELHO, descricao: `Feedback excluído: ${ev.recurso_id}` };

  // Default: ação desconhecida — mostra o nome bruto
  return { cor: COR_CINZA, descricao: acao };
}

// "há 3min", "há 2h", "há 4d" — formato compacto pro feed
function tempoRelativo(iso) {
  if (!iso) return "";
  const ms = Date.now() - new Date(iso).getTime();
  if (ms < 60_000) return "agora há pouco";
  const min = Math.floor(ms / 60_000);
  if (min < 60) return `há ${min} min`;
  const h = Math.floor(min / 60);
  if (h < 24) return `há ${h}h`;
  const d = Math.floor(h / 24);
  if (d < 30) return `há ${d}d`;
  // Caiu muito atrás — mostra data formatada (timezone do browser do usuário,
  // que via configuração de SO normalmente já é America/Sao_Paulo).
  return new Date(iso).toLocaleDateString("pt-BR");
}

// ═══════════════════════════════════════════════════════════════
// HOME MENU
// ═══════════════════════════════════════════════════════════════

function HomeMenu({ data, setAba, tentarTrocar, isMaster }) {
  const nomeEscritorio = data?.escritorio?.nome || "";
  const [texto, setTexto] = useState("Bem-vindo");
  const [fase, setFase] = useState("bemvindo");

  // Detecta viewport mobile (<768px) pra ajustar grid e padding.
  // Em mobile, 2 cols em vez de 3 — evita o card direito sair da tela.
  const [isMobile, setIsMobile] = useState(() => {
    try { return window.innerWidth < 768; } catch { return false; }
  });
  useEffect(() => {
    function onResize() { try { setIsMobile(window.innerWidth < 768); } catch {} }
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);

  useEffect(() => {
    if (!nomeEscritorio) return;
    const t1 = setTimeout(() => setFase("saindo"), 1600);
    const t2 = setTimeout(() => { setTexto(nomeEscritorio); setFase("entrando"); }, 2100);
    return () => { clearTimeout(t1); clearTimeout(t2); };
  }, [nomeEscritorio]);

  const opacity = fase === "saindo" ? 0 : 1;
  const transform = fase === "saindo" ? "translateY(-8px)" : "translateY(0)";

  // Cards da home dependem do perfil. Master tem Dashboard com métricas +
  // links pra Mensagens/Empresas/etc. Escritório vê os módulos dele.
  const modulos = isMaster ? [
    { k:"mensagens",              label:"Mensagens",      desc:"Caixa do time VICKE" },
    { k:"admin:empresas",         label:"Empresas",       desc:"Gerenciar empresas cadastradas" },
    { k:"admin:usuarios-master",  label:"Usuários Master", desc:"Acessos da equipe Vicke" },
    { k:"admin:manutencao",       label:"Manutenção",     desc:"Jobs e operações do sistema" },
    { k:"admin:cub",              label:"CUB",            desc:"Custo Unitário Básico — atualização mensal" },
  ] : [
    { k:"clientes",         label:"Clientes",     desc:"Cadastro e orçamentos",     count: data?.clientes?.length },
    { k:"projetos:etapas",  label:"Projetos",     desc:"Etapas e prazos" },
    { k:"obras",            label:"Obras",        desc:"Acompanhamento e execução" },
    { k:"escritorio",       label:"Escritório",   desc:"Dados e equipe" },
  ];

  return (
    <div style={{ display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", minHeight:"calc(100vh - 53px)", padding: isMobile ? "32px 16px" : "40px 32px", fontFamily:"'Helvetica Neue',Helvetica,Arial,sans-serif" }}>
      <div style={{ textAlign:"center", marginBottom: isMobile ? 36 : 56 }}>
        <div style={{ fontSize: isMobile ? 24 : 28, fontWeight:300, color:"#111", letterSpacing:-0.5, transition:"opacity 0.4s ease, transform 0.4s ease", opacity, transform }}>
          {texto}
        </div>
        <div style={{ fontSize:13, color:"#d1d5db", marginTop:8 }}>Selecione um módulo para começar</div>
      </div>
      <div style={{ display:"grid", gridTemplateColumns: isMobile ? "1fr 1fr" : "repeat(3, 1fr)", gap: isMobile ? 10 : 12, width:"100%", maxWidth:680 }}>
        {modulos.map(m => (
          <button key={m.k} onClick={() => { const go = () => setAba(m.k); if (tentarTrocar) tentarTrocar(go); else go(); }}
            style={{ background:"#fff", border:"1px solid #e5e7eb", borderRadius:12, padding: isMobile ? "16px 14px" : "20px", textAlign:"left", cursor:"pointer", fontFamily:"inherit", position:"relative" }}
            onMouseEnter={e => { e.currentTarget.style.borderColor="#111"; }}
            onMouseLeave={e => { e.currentTarget.style.borderColor="#e5e7eb"; }}>
            <div style={{ fontSize:13, fontWeight:600, color:"#111", marginBottom:4 }}>{m.label}</div>
            <div style={{ fontSize:12, color:"#9ca3af" }}>{m.desc}</div>
            {m.count > 0 && <div style={{ position:"absolute", top:12, right:12, background:"#f3f4f6", color:"#6b7280", fontSize:11, fontWeight:600, padding:"2px 8px", borderRadius:10 }}>{m.count}</div>}
          </button>
        ))}
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// TELA: TROCAR SENHA OBRIGATÓRIA
// ═══════════════════════════════════════════════════════════════
// Renderizada quando o usuário tem `precisa_trocar_senha = true` no JWT/me.
// Bloqueia toda navegação até trocar a senha temporária (gerada por admin
// no reset). É a única coisa visível na tela — sem sidebar, sem dados.
//
// Saídas possíveis:
//   - Trocar senha com sucesso → onTrocada() → app libera
//   - Logout → cliente sai sem trocar (caso esteja em máquina errada)

// Input de senha com botão "olho" pra revelar conteúdo. Usado pelos 3
// campos da tela de troca obrigatória. type alterna entre password (oculto,
// default) e text (revelado). Visibilidade é controlada pelo pai.
function CampoSenha({ valor, onChange, visivel, setVisivel, disabled, autoFocus }) {
  return (
    <div style={{ position:"relative" }}>
      <input
        type={visivel ? "text" : "password"}
        value={valor}
        onChange={e => onChange(e.target.value)}
        disabled={disabled}
        autoFocus={autoFocus}
        style={{
          width:"100%", border:"1px solid #e5e7eb", borderRadius:8,
          padding:"10px 40px 10px 12px", // padding direito maior pro botão
          fontSize:13, fontFamily:"inherit", outline:"none", boxSizing:"border-box",
        }}
      />
      <button
        type="button"
        onClick={() => setVisivel(v => !v)}
        disabled={disabled}
        title={visivel ? "Ocultar senha" : "Mostrar senha"}
        aria-label={visivel ? "Ocultar senha" : "Mostrar senha"}
        style={{
          position:"absolute", right:6, top:"50%", transform:"translateY(-50%)",
          background:"none", border:"none", cursor: disabled ? "not-allowed" : "pointer",
          padding:"6px 8px", lineHeight:0,
          color:"#9ca3af", fontFamily:"inherit",
          display:"flex", alignItems:"center", justifyContent:"center",
        }}
        onMouseEnter={e => { if (!disabled) e.currentTarget.style.color = "#374151"; }}
        onMouseLeave={e => { e.currentTarget.style.color = "#9ca3af"; }}>
        {visivel ? (
          // eye-off
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"/>
            <line x1="1" y1="1" x2="23" y2="23"/>
          </svg>
        ) : (
          // eye
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/>
            <circle cx="12" cy="12" r="3"/>
          </svg>
        )}
      </button>
    </div>
  );
}

function TelaTrocarSenhaObrigatoria({ usuario, onTrocada, onLogout }) {
  const [senhaAtual, setSenhaAtual] = useState("");
  const [senhaNova, setSenhaNova]   = useState("");
  const [confirmar, setConfirmar]   = useState("");
  const [loading, setLoading]       = useState(false);
  const [erro, setErro]             = useState(null);
  // Visibilidade independente de cada campo. Default: oculto (boa prática
  // de não vazar senha em ombro alheio enquanto digita). Botão "olho"
  // permite revelar pra conferir o que digitou.
  const [verAtual, setVerAtual]     = useState(false);
  const [verNova, setVerNova]       = useState(false);
  const [verConfirmar, setVerConfirmar] = useState(false);

  function validar() {
    if (!senhaAtual) return "Informe a senha atual (a temporária recebida)";
    if (!senhaNova || senhaNova.length < 6) return "A nova senha deve ter no mínimo 6 caracteres";
    if (senhaNova === senhaAtual) return "A nova senha precisa ser diferente da atual";
    if (senhaNova !== confirmar) return "Confirmação de senha não confere";
    return null;
  }

  async function trocar() {
    const v = validar();
    if (v) { setErro(v); return; }
    setLoading(true);
    setErro(null);
    try {
      await api.auth.trocarSenha(senhaAtual, senhaNova);
      onTrocada();
    } catch (e) {
      setErro(e.message || "Falha ao trocar senha");
    } finally {
      setLoading(false);
    }
  }

  function handleSubmit(e) {
    e.preventDefault();
    trocar();
  }

  return (
    <div style={{
      position:"fixed", inset:0,
      background:"#fafafa",
      display:"flex", alignItems:"center", justifyContent:"center",
      padding:20, fontFamily:"'Helvetica Neue',Helvetica,Arial,sans-serif",
    }}>
      <form onSubmit={handleSubmit}
        style={{
          background:"#fff", border:"1px solid #e5e7eb", borderRadius:12,
          padding:"32px 32px 24px", maxWidth:420, width:"100%",
          boxShadow:"0 8px 32px rgba(0,0,0,0.06)",
        }}>
        <div style={{ fontSize:18, fontWeight:700, color:"#111", marginBottom:6, letterSpacing:-0.3 }}>
          Trocar senha
        </div>
        <div style={{ fontSize:13, color:"#6b7280", marginBottom:20, lineHeight:1.5 }}>
          Sua senha foi resetada por um administrador. Para continuar, escolha uma senha nova que só você saiba.
        </div>

        <div style={{ marginBottom:14 }}>
          <label style={{ display:"block", fontSize:11, fontWeight:600, color:"#6b7280", textTransform:"uppercase", letterSpacing:0.5, marginBottom:6 }}>
            Senha temporária recebida
          </label>
          <CampoSenha
            valor={senhaAtual}
            onChange={setSenhaAtual}
            visivel={verAtual}
            setVisivel={setVerAtual}
            disabled={loading}
            autoFocus
          />
        </div>

        <div style={{ marginBottom:14 }}>
          <label style={{ display:"block", fontSize:11, fontWeight:600, color:"#6b7280", textTransform:"uppercase", letterSpacing:0.5, marginBottom:6 }}>
            Nova senha (mínimo 6 caracteres)
          </label>
          <CampoSenha
            valor={senhaNova}
            onChange={setSenhaNova}
            visivel={verNova}
            setVisivel={setVerNova}
            disabled={loading}
          />
        </div>

        <div style={{ marginBottom:18 }}>
          <label style={{ display:"block", fontSize:11, fontWeight:600, color:"#6b7280", textTransform:"uppercase", letterSpacing:0.5, marginBottom:6 }}>
            Confirme a nova senha
          </label>
          <CampoSenha
            valor={confirmar}
            onChange={setConfirmar}
            visivel={verConfirmar}
            setVisivel={setVerConfirmar}
            disabled={loading}
          />
        </div>

        {erro && (
          <div style={{ fontSize:12.5, color:"#991b1b", background:"#fef2f2", border:"1px solid #fecaca", borderRadius:8, padding:"8px 12px", marginBottom:14 }}>
            {erro}
          </div>
        )}

        <button type="submit" disabled={loading}
          style={{
            background:"#111", color:"#fff", border:"none", borderRadius:8,
            padding:"11px 16px", fontSize:13.5, fontWeight:600, cursor: loading ? "not-allowed" : "pointer",
            fontFamily:"inherit", width:"100%", marginBottom:10,
            opacity: loading ? 0.6 : 1,
          }}>
          {loading ? "Salvando..." : "Trocar senha e continuar"}
        </button>

        <button type="button" onClick={onLogout} disabled={loading}
          style={{
            background:"transparent", color:"#6b7280", border:"none",
            padding:"8px", fontSize:12, cursor:"pointer", fontFamily:"inherit", width:"100%",
          }}>
          Sair sem trocar
        </button>

        <div style={{ fontSize:11, color:"#9ca3af", marginTop:12, textAlign:"center" }}>
          Logado como {usuario?.email || ""}
        </div>
      </form>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// FEEDBACK IN-APP — botão flutuante + modal
// ═══════════════════════════════════════════════════════════════
// Botão fixo no canto inferior direito (z-index alto pra ficar sobre tudo
// que não seja modal/dialog do sistema). Visível em qualquer aba, exceto
// na tela de troca de senha obrigatória (que bloqueia tudo).
//
// Categorias seguem CHECK constraint do backend (feedback_app.categoria):
// sugestao | bug | pergunta | cobranca | elogio | outro

const FEEDBACK_CATEGORIAS = [
  { id: "sugestao",  label: "Sugestão" },
  { id: "bug",       label: "Bug" },
  { id: "pergunta",  label: "Pergunta" },
  { id: "cobranca",  label: "Cobrança" },
  { id: "elogio",    label: "Elogio" },
  { id: "outro",     label: "Outro" },
];

function BotaoFeedbackFlutuante({ usuario }) {
  const [modalAberto, setModalAberto] = useState(false);
  // Detecta mobile pra ajustar offsets do botão.
  const [isMobile, setIsMobile] = useState(() => {
    try { return window.innerWidth < 768; } catch { return false; }
  });
  useEffect(() => {
    function onResize() { try { setIsMobile(window.innerWidth < 768); } catch {} }
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);

  // Master não envia feedback pra si mesmo — caixa é pra clientes.
  if (usuario?.perfil === "master") return null;

  return (
    <>
      <button
        onClick={() => setModalAberto(true)}
        title="Enviar feedback"
        style={{
          position:"fixed",
          right: isMobile ? 16 : 24,
          bottom: isMobile ? 16 : 24,
          zIndex: 800,
          background:"#111", color:"#fff", border:"none",
          borderRadius:"50%",
          width: isMobile ? 44 : 48,
          height: isMobile ? 44 : 48,
          cursor:"pointer", fontFamily:"inherit",
          boxShadow:"0 4px 12px rgba(0,0,0,0.15)",
          display:"flex", alignItems:"center", justifyContent:"center",
          transition:"transform 0.12s ease",
        }}
        onMouseEnter={e => { e.currentTarget.style.transform = "scale(1.05)"; }}
        onMouseLeave={e => { e.currentTarget.style.transform = "scale(1)"; }}>
        {/* Ícone mensagem outline (estilo Lucide) — alinhado com identidade
            visual minimalista preto/branco do sistema */}
        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>
        </svg>
      </button>
      {modalAberto && (
        <ModalEnviarFeedback
          usuario={usuario}
          onFechar={() => setModalAberto(false)}
        />
      )}
    </>
  );
}

function ModalEnviarFeedback({ usuario, onFechar }) {
  const [categoria, setCategoria] = useState("sugestao");
  const [texto, setTexto]         = useState("");
  const [enviando, setEnviando]   = useState(false);
  const [erro, setErro]           = useState(null);
  const [enviado, setEnviado]     = useState(false);
  const MAX_CHARS = 2000;

  async function enviar() {
    const txt = texto.trim();
    if (!txt) { setErro("Escreva alguma coisa antes de enviar"); return; }
    if (txt.length > MAX_CHARS) { setErro(`Texto muito longo (máximo ${MAX_CHARS} caracteres)`); return; }
    setEnviando(true);
    setErro(null);
    try {
      await api.feedback.enviar(categoria, txt);
      setEnviado(true);
      setTimeout(onFechar, 1800); // fecha sozinho após mostrar "enviado"
    } catch (e) {
      setErro(e.message || "Falha ao enviar");
      setEnviando(false);
    }
  }

  // Estado de sucesso: mostra confirmação por ~1.8s antes de fechar.
  // Feedback positivo curto evita que o cliente fique com dúvida se foi.
  if (enviado) {
    return (
      <div onClick={onFechar} style={{
        position:"fixed", inset:0, background:"rgba(0,0,0,0.4)",
        display:"flex", alignItems:"center", justifyContent:"center",
        zIndex:900, padding:20,
        fontFamily:"'Helvetica Neue',Helvetica,Arial,sans-serif",
      }}>
        <div style={{
          background:"#fff", borderRadius:12, padding:"32px 28px",
          maxWidth:380, textAlign:"center", boxShadow:"0 8px 32px rgba(0,0,0,0.15)",
        }}>
          <div style={{ marginBottom:14, display:"flex", justifyContent:"center" }}>
            <div style={{
              width:48, height:48, borderRadius:"50%",
              background:"#111", color:"#fff",
              display:"flex", alignItems:"center", justifyContent:"center",
            }}>
              <IconeMaster nome="check" tamanho={22} cor="#fff" />
            </div>
          </div>
          <div style={{ fontSize:16, fontWeight:600, color:"#111", marginBottom:6 }}>Recebido</div>
          <div style={{ fontSize:13, color:"#6b7280", lineHeight:1.5 }}>
            Obrigado pelo feedback.
          </div>
        </div>
      </div>
    );
  }

  return (
    <div onClick={onFechar} style={{
      position:"fixed", inset:0, background:"rgba(0,0,0,0.4)",
      display:"flex", alignItems:"center", justifyContent:"center",
      zIndex:900, padding:20,
      fontFamily:"'Helvetica Neue',Helvetica,Arial,sans-serif",
    }}>
      <div onClick={e => e.stopPropagation()} style={{
        background:"#fff", borderRadius:12, padding:"24px 24px 20px",
        maxWidth:480, width:"100%", maxHeight:"90vh", overflowY:"auto",
        boxShadow:"0 8px 32px rgba(0,0,0,0.15)",
      }}>
        <div style={{ fontSize:16, fontWeight:700, color:"#111", marginBottom:6 }}>
          Enviar feedback
        </div>
        <div style={{ fontSize:13, color:"#6b7280", marginBottom:18, lineHeight:1.5 }}>
          Sua mensagem chega direto pro time da Vicke. Pode mandar bugs, ideias, perguntas — tudo serve.
        </div>

        <div style={{ marginBottom:14 }}>
          <label style={{ display:"block", fontSize:11, fontWeight:600, color:"#6b7280", textTransform:"uppercase", letterSpacing:0.5, marginBottom:8 }}>
            Tipo
          </label>
          <div style={{ display:"grid", gridTemplateColumns:"repeat(2, 1fr)", gap:6 }}>
            {FEEDBACK_CATEGORIAS.map(c => (
              <button
                key={c.id}
                type="button"
                onClick={() => setCategoria(c.id)}
                disabled={enviando}
                style={{
                  padding:"10px 12px", borderRadius:8, fontSize:13,
                  fontFamily:"inherit", textAlign:"center",
                  cursor: enviando ? "not-allowed" : "pointer",
                  border: categoria === c.id ? "1.5px solid #111" : "1px solid #e5e7eb",
                  background: categoria === c.id ? "#fafbfc" : "#fff",
                  color:"#111",
                  fontWeight: categoria === c.id ? 600 : 400,
                }}>
                {c.label}
              </button>
            ))}
          </div>
        </div>

        <div style={{ marginBottom:14 }}>
          <label style={{ display:"block", fontSize:11, fontWeight:600, color:"#6b7280", textTransform:"uppercase", letterSpacing:0.5, marginBottom:6 }}>
            Mensagem
          </label>
          <textarea
            value={texto}
            onChange={e => setTexto(e.target.value)}
            disabled={enviando}
            placeholder="Escreva o que quiser compartilhar..."
            rows={5}
            style={{
              width:"100%", border:"1px solid #e5e7eb", borderRadius:8,
              padding:"10px 12px", fontSize:13, fontFamily:"inherit",
              outline:"none", boxSizing:"border-box", resize:"vertical",
              minHeight:100,
            }}
          />
          <div style={{ fontSize:11, color: texto.length > MAX_CHARS ? "#b91c1c" : "#9ca3af", marginTop:4, textAlign:"right" }}>
            {texto.length} / {MAX_CHARS}
          </div>
        </div>

        {erro && (
          <div style={{ fontSize:12.5, color:"#991b1b", background:"#fef2f2", border:"1px solid #fecaca", borderRadius:8, padding:"8px 12px", marginBottom:14 }}>
            {erro}
          </div>
        )}

        <div style={{ fontSize:11, color:"#9ca3af", marginBottom:14, lineHeight:1.5 }}>
          Enviado por: <strong style={{ color:"#6b7280" }}>{usuario?.nome}</strong> · {usuario?.email}
        </div>

        <div style={{ display:"flex", gap:10, justifyContent:"flex-end" }}>
          <button onClick={onFechar} disabled={enviando}
            style={{
              background:"#fff", border:"1px solid #e5e7eb", borderRadius:8,
              padding:"9px 14px", fontSize:13, color:"#6b7280", cursor: enviando ? "not-allowed" : "pointer",
              fontFamily:"inherit",
            }}>
            Cancelar
          </button>
          <button onClick={enviar} disabled={enviando || !texto.trim()}
            style={{
              background:"#111", color:"#fff", border:"none", borderRadius:8,
              padding:"9px 16px", fontSize:13, fontWeight:600,
              cursor: (enviando || !texto.trim()) ? "not-allowed" : "pointer",
              fontFamily:"inherit", opacity: (enviando || !texto.trim()) ? 0.5 : 1,
            }}>
            {enviando ? "Enviando..." : "Enviar"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// MAIN
// ═══════════════════════════════════════════════════════════════
export default function ModuloClientesFornecedores() {
  const [usuario, setUsuario]         = useState(null);
  const [token, setToken]             = useState(null);
  const [autenticado, setAutenticado] = useState(false);
  const [data, setData]               = useState(null);
  const [loading, setLoading]         = useState(false);
  const [aba, setAba]                 = useState("home");
  const [showBackup, setShowBackup]   = useState(false);
  const [backupJson, setBackupJson]   = useState("");
  const [clientesKey, setClientesKey]         = useState(0);
  const [fornecedoresKey, setFornecedoresKey] = useState(0);
  const [projetosKey, setProjetosKey]         = useState(0);
  const [orcamentosKey, setOrcamentosKey]     = useState(0);
  const [obrasKey, setObrasKey]               = useState(0);
  const [financeiroKey, setFinanceiroKey]     = useState(0);
  const [escritorioKey, setEscritorioKey]     = useState(0);
  // Sidebar colapsada: estado persistido em localStorage. False = full
  // (ícones + texto). True = estreita (só ícones, popover nos submenus).
  // Padrão dos SaaS modernos (Linear/Notion/VSCode) — usuário escolhe uma
  // vez e a preferência persiste entre sessões.
  const [sidebarColapsada, setSidebarColapsada] = useState(() => {
    try {
      return localStorage.getItem("vicke-sidebar-colapsada") === "true";
    } catch { return false; }
  });
  useEffect(() => {
    try { localStorage.setItem("vicke-sidebar-colapsada", String(sidebarColapsada)); } catch {}
  }, [sidebarColapsada]);

  // Mobile: detecta tamanho de tela pra alternar comportamento da sidebar.
  // <768px: sidebar vira overlay/drawer (fechada por default, abre por toque).
  // >=768px: sidebar normal lado a lado com conteúdo (igual desktop).
  // Listener no resize pra reagir a rotação do dispositivo / redimensionamento.
  const [isMobile, setIsMobile] = useState(() => {
    try { return window.innerWidth < 768; } catch { return false; }
  });
  useEffect(() => {
    function onResize() {
      try { setIsMobile(window.innerWidth < 768); } catch {}
    }
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);

  // Força meta viewport restrito em mobile + bloqueia scroll horizontal global.
  // Roda uma vez no boot. Garante que mesmo se o index.html tiver viewport
  // permissivo, a UI não dê zoom horizontal nem permita scroll lateral.
  useEffect(() => {
    try {
      // 1. Atualiza/insere <meta name="viewport"> com escala fixa
      let meta = document.querySelector('meta[name="viewport"]');
      if (!meta) {
        meta = document.createElement("meta");
        meta.name = "viewport";
        document.head.appendChild(meta);
      }
      meta.content = "width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no, viewport-fit=cover";

      // 2. Injeta CSS global pra bloquear overflow horizontal em html/body.
      // Se algum elemento estourar a largura, fica oculto em vez de criar
      // scroll lateral. ID único pra não duplicar se App remontar.
      if (!document.getElementById("vicke-global-mobile-fix")) {
        const style = document.createElement("style");
        style.id = "vicke-global-mobile-fix";
        style.textContent = `
          html, body, #root { max-width: 100vw; overflow-x: hidden; }
          /* Previne tap delay e zoom em double tap em mobile */
          * { touch-action: manipulation; }
        `;
        document.head.appendChild(style);
      }
    } catch {}
  }, []);

  // Sidebar drawer em mobile: estado controla se está aberta (overlay visível).
  // Sempre começa fechada em mobile — usuário toca hamburguer pra abrir.
  // Em desktop esse state é ignorado (sidebar sempre visível).
  const [sidebarMobileAberta, setSidebarMobileAberta] = useState(false);

  const [orcamentoTelaCheia, setOrcamentoTelaCheia] = useState(null);
  const [clienteRetorno, setClienteRetorno] = useState(null);
  const [cadastroNovoCliente, setCadastroNovoCliente] = useState(false);
  const [backendOffline, setBackendOffline]   = useState(false);

  // Ref pro data atual — usada dentro de callbacks que não devem capturar closure.
  // Sem isso, callbacks criados numa render leem data antigo mesmo após saves.
  // Bug histórico: durante edição de orçamento, ao salvar nova proposta o
  // handler onSalvar misturava data velho + orcamentosProjeto novo, perdendo
  // propostas intermediárias (card mostrava valor antigo mesmo após gerar
  // proposta nova com valor diferente).
  const dataRef = useRef(null);
  useEffect(() => { dataRef.current = data; }, [data]);

  // Flag interna: true quando há salvamento em andamento.
  // Usada pelo beforeunload pra bloquear fechamento durante saves.
  const savingRef = useRef(false);

  // Flag: orçamento em tela cheia está aberto.
  // Usada pelo beforeunload — se o usuário entrou num form de orçamento,
  // já pode estar preenchendo e o F5 não deve deixar sair silenciosamente.
  // Mesmo que o form ainda não tenha registrado __vickeOrcHasDirty,
  // esta flag captura a situação defensivamente.
  const orcamentoAbertoRef = useRef(false);
  useEffect(() => { orcamentoAbertoRef.current = !!orcamentoTelaCheia; }, [orcamentoTelaCheia]);

  // isMaster: dupla checagem — state em memória + JWT real do localStorage.
  // Defesa contra inconsistência: se o state diz "master" mas o JWT em uso
  // diz "escritorio" (cenário de autopreenchimento + login rápido), retorna
  // false e a sidebar esconde itens master automaticamente. Backend já bloqueia,
  // mas isso evita o usuário ver opções que vão dar 403.
  const isMaster = (() => {
    if (usuario?.perfil !== "master") return false;
    if (typeof localStorage === "undefined") return true; // SSR safety
    try {
      const tok = localStorage.getItem("vicke-token");
      if (!tok) return false;
      const payload = decodeJWT(tok);
      // JWT é a fonte da verdade do que o backend vai aceitar
      return payload?.perfil === "master";
    } catch { return false; }
  })();

  // tentarTrocar: quando há orçamento em tela cheia com dados não salvos,
  // consulta o handler registrado pelo FormOrcamento (window.__vickeOrcDirtyPrompt).
  // Em mobile, fecha o drawer da sidebar após troca bem-sucedida (UX padrão
  // de drawers — usuário escolhe item, drawer some pra mostrar conteúdo).
  function tentarTrocar(fn) {
    const fnComFechamento = () => {
      fn();
      // Fecha drawer mobile (no-op em desktop)
      try { setSidebarMobileAberta(false); } catch {}
    };
    if (typeof window !== "undefined" && typeof window.__vickeOrcDirtyPrompt === "function") {
      const absorveu = window.__vickeOrcDirtyPrompt(fnComFechamento);
      if (absorveu) return;
    }
    fnComFechamento();
  }

  // Accordion: Projetos fica aberto quando qualquer aba "projetos:*" está ativa
  const [projetosAberto, setProjetosAberto] = useState(() => (typeof aba === "string" && aba.indexOf("projetos") === 0));
  // Popover do submenu Projetos quando sidebar está colapsada. null = fechado,
  // ou {x, y} pra posicionar absolutamente perto do botão pai.
  const [popoverProjetos, setPopoverProjetos] = useState(null);
  // Fecha popover ao clicar fora (delegação no document — captura
  // clicks em qualquer lugar da página quando popover está aberto).
  useEffect(() => {
    if (!popoverProjetos) return;
    function onClickFora(e) {
      // Se clicou dentro do popover ou no botão que abriu, ignora
      const popover = document.getElementById("popover-projetos");
      const trigger = document.getElementById("trigger-projetos");
      if (popover && popover.contains(e.target)) return;
      if (trigger && trigger.contains(e.target)) return;
      setPopoverProjetos(null);
    }
    document.addEventListener("mousedown", onClickFora);
    return () => document.removeEventListener("mousedown", onClickFora);
  }, [popoverProjetos]);
  useEffect(() => {
    if (typeof aba === "string" && aba.indexOf("projetos") === 0) setProjetosAberto(true);
  }, [aba]);

  // Modal "Sessão alterada em outra aba" — única ação possível: recarregar.
  // Declarado cedo porque é usado por hooks de bootstrap/visibilidade.
  const [conflitoSessao, setConflitoSessao] = useState(null);
  // null = sem conflito | "outro_usuario" | "logout"

  // Bootstrap: restaura sessão salva no localStorage se ainda válida.
  useEffect(() => {
    try {
      const tok = localStorage.getItem("vicke-token");
      const usr = localStorage.getItem("vicke-user");
      if (tok && usr) {
        const payload = decodeJWT(tok);
        if (!payload) {
          localStorage.removeItem("vicke-token");
          localStorage.removeItem("vicke-user");
          return;
        }
        if (isTokenExpirado(payload)) {
          localStorage.removeItem("vicke-token");
          localStorage.removeItem("vicke-user");
          return;
        }
        setUsuario(JSON.parse(usr));
        setToken(tok);
        setAutenticado(true);
      }
    } catch {
      try {
        localStorage.removeItem("vicke-token");
        localStorage.removeItem("vicke-user");
      } catch {}
    }
  }, []);

  // Verificação de consistência: quando a aba volta ao foco OU quando window
  // ganha foco, comparar state em memória com localStorage. Se divergirem,
  // significa que outra aba mexeu no storage enquanto esta estava em background
  // — aba precisa recarregar pra refletir o estado correto.
  //
  // Cenário coberto: aba A logada como master, outra aba B faz logout/login
  // como Padovan, usuário volta na aba A → state em memória ainda diz master
  // mas localStorage agora tem Padovan. Reload corrige.
  //
  // Defesa em profundidade — o BroadcastChannel/storage event já cobrem isso
  // em tempo real, mas se algum evento for perdido (browser bug, foco em outra
  // janela com aba em sleep), esse hook captura na volta.
  useEffect(() => {
    function verificarConsistencia() {
      // Sem usuário em memória? Não estamos logados, nada pra verificar
      if (!usuario?.id) return;
      try {
        const usrLS = localStorage.getItem("vicke-user");
        const tokLS = localStorage.getItem("vicke-token");
        // localStorage vazio mas state diz logado: alguém deslogou em outra aba
        if (!usrLS || !tokLS) {
          setConflitoSessao("logout");
          return;
        }
        const userLS = JSON.parse(usrLS);
        // Usuário diferente do que está em memória
        if (userLS?.id && userLS.id !== usuario.id) {
          setConflitoSessao("outro_usuario");
        }
        // Mesmo usuário mas token diferente: silenciosamente atualiza memória
        else if (userLS?.id === usuario.id && tokLS !== token) {
          setToken(tokLS);
        }
      } catch { /* JSON corrompido, deixa próximo request com 401 lidar */ }
    }
    function onVisibility() {
      if (document.visibilityState === "visible") verificarConsistencia();
    }
    window.addEventListener("focus", verificarConsistencia);
    document.addEventListener("visibilitychange", onVisibility);
    return () => {
      window.removeEventListener("focus", verificarConsistencia);
      document.removeEventListener("visibilitychange", onVisibility);
    };
  }, [usuario?.id, token]);

  // loadData roda quando autenticado vira true OU quando o estado da empresa
  // muda (ex: usuário acaba de concluir onboarding e o usuario.estado passou
  // de null pra "SP" — precisa recarregar dados pra trazer o CUB do estado).
  useEffect(() => { if (autenticado) { setLoading(true); loadData(); } }, [autenticado, usuario?.estado]);

  useEffect(() => {
    if (aba === "projetos") setAba("projetos:etapas");
    else if (aba === "teste") setAba("projetos:orcamentos");
  }, [aba]);

  // beforeunload: dispara se há trabalho que o usuário pode perder.
  // Condições que ativam:
  //   (a) save em andamento
  //   (b) orçamento em tela cheia aberto (usuário pode estar preenchendo)
  //   (c) form registrou __vickeOrcHasDirty e retorna true
  // A condição (b) é defensiva: cobre o caso em que o usuário começa a
  // preencher cômodos antes do form fazer setup do handler próprio.
  useEffect(() => {
    const handler = (e) => {
      const savingAgora = savingRef.current;
      const orcamentoAberto = orcamentoAbertoRef.current;
      let orcSujo = false;
      try {
        if (typeof window !== "undefined" && typeof window.__vickeOrcHasDirty === "function") {
          orcSujo = !!window.__vickeOrcHasDirty();
        }
      } catch {}
      if (!savingAgora && !orcamentoAberto && !orcSujo) return;
      e.preventDefault();
      e.returnValue = "";
      return "";
    };
    window.addEventListener("beforeunload", handler);
    return () => window.removeEventListener("beforeunload", handler);
  }, []);

  function handleLogin(usr, tok) {
    setUsuario(usr); setToken(tok); setAutenticado(true); setAba("home");
    // Notifica outras abas que pode haver troca de usuário.
    // Inclui userId pra outras abas decidirem: mesma sessão (atualizar token)
    // ou usuário diferente (forçar reload).
    anunciarSessao("login", { userId: usr.id });
  }
  function handleLogout() {
    anunciarSessao("logout", { userId: usuario?.id });
    clearAuth();
    // Reload pra estado limpo: descarta TODO state em memória (data, aba ativa,
    // forms abertos, etc.) e força bootstrap fresh com localStorage vazio.
    // Sem reload, restos do app antigo podem se misturar com o login novo
    // (ex: sidebar mostrando "Admin" mesmo após login com perfil escritorio).
    // Pequeno delay pra anunciarSessao chegar em outras abas antes do reload.
    setTimeout(() => { window.location.href = "/"; }, 50);
  }

  // Reage a mudanças de sessão em outras abas
  useSessionCoordinator({
    usuarioAtual: usuario,
    onMesmoUsuario: () => {
      // Mesmo usuário relogou em outra aba → token novo no localStorage.
      // Atualiza state local sem reload pra continuar trabalhando.
      try {
        const novoToken = localStorage.getItem("vicke-token");
        if (novoToken && novoToken !== token) setToken(novoToken);
      } catch { /* se falhar, próximo request com 401 dá fallback */ }
    },
    onOutroUsuario: () => {
      // Outro usuário logou nesta máquina → continuar usaria credenciais
      // erradas. Modal pede reload, sem opção de "ignorar" (é inconsistência).
      setConflitoSessao("outro_usuario");
    },
    onLogout: () => {
      // Outra aba fez logout → token saiu do localStorage. Mostrar modal
      // pra usuário entender o que aconteceu antes do reload.
      setConflitoSessao("logout");
    },
  });

  async function loadData() {
    try {
      // Passa estado da empresa pra loadAllData buscar o CUB em paralelo
      // (Sprint 3). Lê do localStorage como fonte primária — usuario state
      // pode estar null/stale no primeiro loadData() pós-login (closure
      // capturou null antes do setUsuario propagar pro React).
      // Localstorage é setado SINCRONO no handleLogin/bootstrap antes do
      // setAutenticado disparar este effect. Fallback pro state cobre o caso
      // de loadData ser chamado de novo depois (botão "Tentar novamente").
      let estadoEmpresa = null;
      try {
        const usrStored = JSON.parse(localStorage.getItem("vicke-user") || "null");
        estadoEmpresa = usrStored?.estado || usuario?.estado || null;
      } catch {
        estadoEmpresa = usuario?.estado || null;
      }
      const saved = await loadAllData(estadoEmpresa);
      setData(saved);
      setBackendOffline(false);
    }
    catch(e) {
      console.error("Erro ao carregar dados do servidor:", e);
      setData(SEED);
      setBackendOffline(true);
    }
    setLoading(false);
  }

  // save(): otimista — aplica localmente, envia pro backend, e fim.
  // Se backend falhar, marca offline mas não reverte (usuário continua
  // trabalhando; quando reconectar, próximo save sincroniza).
  //
  // IMPORTANTE: callers em callbacks capturados (ex: onSalvar do FormOrcamento)
  // devem usar dataRef.current em vez de data, senão leem data congelado e
  // sobrescrevem atualizações intermediárias.
  async function save(newData, opts = {}) {
    const oldData = dataRef.current || data;
    setData(newData);
    dataRef.current = newData; // mantém ref em sync imediato pra callbacks subsequentes
    savingRef.current = true;
    try {
      await saveAllData(newData, oldData);
      setBackendOffline(false);
    }
    catch(e) {
      console.error("Erro ao salvar:", e);
      setBackendOffline(true);
    }
    finally {
      savingRef.current = false;
    }
  }

  // Backup (exportar/importar): disponível APENAS pro master.
  // Editor/admin de escritório não precisam exportar todo o banco.
  function exportarDados() {
    const json = JSON.stringify(data, null, 2);
    try {
      const blob = new Blob([json], { type: "application/json" });
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = `vicke-backup-${new Date().toISOString().slice(0,10)}.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    } catch (e) {
      console.error("Falha no download direto, abrindo modal:", e);
      setBackupJson(json);
      setShowBackup(true);
    }
  }

  function importarDados(e) {
    const file = e.target.files[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = async (ev) => {
      try { const parsed = JSON.parse(ev.target.result); await save(parsed); toast.sucesso("Dados importados"); }
      catch { dialogo.alertar({ titulo: "Arquivo inválido", mensagem: "Não foi possível ler este arquivo JSON.", tipo: "erro" }); }
    };
    reader.readAsText(file); e.target.value = "";
  }

  // Renderiza modal de conflito de sessão (compartilhado entre todos os returns)
  const conflitoModal = conflitoSessao && (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.4)", zIndex:100050, display:"flex", alignItems:"center", justifyContent:"center", padding:20 }}>
      <div style={{ background:"#fff", border:"1px solid #e5e7eb", borderRadius:12, padding:"28px 32px", maxWidth:440, width:"100%", boxShadow:"0 8px 32px rgba(0,0,0,0.15)" }}>
        <div style={{ fontSize:16, fontWeight:700, color:"#111", marginBottom:8 }}>
          {conflitoSessao === "logout" ? "Sessão encerrada" : "Sessão alterada em outra aba"}
        </div>
        <div style={{ fontSize:13, color:"#6b7280", marginBottom:20, lineHeight:1.55 }}>
          {conflitoSessao === "logout"
            ? "Você foi desconectado em outra aba. Esta página será atualizada para voltar à tela de login."
            : "Outra aba acabou de logar com um usuário diferente. Por segurança, esta página será atualizada para refletir a nova sessão."}
        </div>
        <div style={{ display:"flex", justifyContent:"flex-end" }}>
          <button
            onClick={() => { setConflitoSessao(null); window.location.reload(); }}
            style={{ background:"#111", color:"#fff", border:"none", borderRadius:8, padding:"9px 20px", fontSize:13, fontWeight:600, cursor:"pointer", fontFamily:"inherit" }}
          >
            Atualizar agora
          </button>
        </div>
      </div>
    </div>
  );

  if (!autenticado) return <><TelaLogin onLogin={handleLogin} /><DialogosHost /><VersionWatcher />{conflitoModal}</>;

  // Senha resetada por admin/master → forçar troca antes de qualquer navegação.
  // Bloqueia tudo (sidebar, abas, dados) até o usuário escolher senha nova.
  // Logout disponível pra escape sem trocar senha (usuário pode estar na máquina errada).
  if (usuario?.precisa_trocar_senha) {
    return (
      <>
      <TelaTrocarSenhaObrigatoria
        usuario={usuario}
        onTrocada={() => {
          // Atualiza o state local pra liberar o app. Backend já zerou a flag.
          const usrAtualizado = { ...usuario, precisa_trocar_senha: false };
          setUsuario(usrAtualizado);
          try { localStorage.setItem("vicke-user", JSON.stringify(usrAtualizado)); } catch {}
        }}
        onLogout={handleLogout}
      />
      <DialogosHost />
      <VersionWatcher />
      {conflitoModal}
      </>
    );
  }

  // Onboarding obrigatório (Sprint 3) → empresa nova precisa configurar perfil
  // antes de usar o app. Bloqueia tudo até concluir. Aparece DEPOIS da troca
  // de senha (admin pode ter resetado pra um usuário de empresa nova — primeiro
  // troca senha, depois onboarding). Empresas existentes têm o flag = false e
  // pulam direto pro app.
  // Master nunca cai aqui (perfil "master" não tem onboarding de pricing).
  if (usuario?.precisa_fazer_onboarding && usuario?.perfil !== "master") {
    return (
      <>
      <TelaOnboarding
        usuario={usuario}
        onConcluido={async (estadoOnboarding) => {
          // Backend zerou precisa_fazer_onboarding e gravou as respostas
          // (profissao, padrao_projetos, pct_matriz_calculado, etc).
          // Refaz /auth/me pra trazer TODOS os campos atualizados — fazer
          // merge manual aqui esquece de copiar campos novos e deixa o
          // localStorage desatualizado (componentes que leem de lá vêem
          // null em profissao/padrao/pct_calibrado).
          try {
            const _API_URL = (typeof import.meta !== "undefined" && import.meta.env && import.meta.env.VITE_API_URL)
              || "https://orbi-production-5f5c.up.railway.app";
            const token = localStorage.getItem("vicke-token");
            const res = await fetch(`${_API_URL}/auth/me`, {
              headers: { "Authorization": `Bearer ${token}` },
            });
            const json = await res.json();
            if (json?.ok && json?.data) {
              setUsuario(json.data);
              try { localStorage.setItem("vicke-user", JSON.stringify(json.data)); } catch {}
            } else {
              throw new Error(json?.error || "Falha ao recarregar dados do usuário");
            }
          } catch (e) {
            // Fallback: se /auth/me falhar (rede ruim), aplica merge mínimo
            // pra pelo menos sair da tela de onboarding. Próximo refresh corrige.
            console.error("Falha ao refetch /auth/me após onboarding:", e);
            const usrFallback = {
              ...usuario,
              precisa_fazer_onboarding: false,
              estado: estadoOnboarding || usuario.estado || null,
            };
            setUsuario(usrFallback);
            try { localStorage.setItem("vicke-user", JSON.stringify(usrFallback)); } catch {}
          }

          // Pré-preenche o estado no escritório se ainda estiver vazio.
          // Estrutura do data.escritorio é FLAT (cfg.estado, cfg.cidade, cfg.endereco
          // são todos campos de primeiro nível) — não aninhado em endereco.estado.
          // Evita que o usuário tenha que digitar de novo a mesma info que acabou
          // de informar no onboarding.
          if (estadoOnboarding && data?.escritorio && !data.escritorio.estado) {
            const escritorioAtualizado = {
              ...data.escritorio,
              estado: estadoOnboarding,
            };
            save({ ...data, escritorio: escritorioAtualizado }).catch(e => {
              console.error("Falha ao pré-preencher estado:", e);
            });
          }

          // Redireciona pra aba Escritório pra completar cadastro completo
          // (logo, endereço, contatos, equipe). Mensagem explicando o porquê
          // fica na tela de transição do onboarding.
          setAba("escritorio");
          setEscritorioKey(n => n + 1);
        }}
        onLogout={handleLogout}
      />
      <DialogosHost />
      <VersionWatcher />
      {conflitoModal}
      </>
    );
  }

  if (loading) return (
    <>
    <div style={{ display:"flex", alignItems:"center", justifyContent:"center", height:"100vh", background:"#fff", fontFamily:"'Helvetica Neue',Helvetica,Arial,sans-serif" }}>
      <div style={{ textAlign:"center" }}>
        <div style={{ width:20, height:20, border:"2px solid #e5e7eb", borderTop:"2px solid #111", borderRadius:"50%", animation:"spin 0.8s linear infinite", margin:"0 auto 12px" }} />
        <p style={{ color:"#9ca3af", fontSize:13, margin:0 }}>Carregando...</p>
      </div>
    </div>
    <DialogosHost />
    <VersionWatcher />
    {conflitoModal}
    </>
  );

  if (!data) {
    return (
      <>
      <div style={{ display:"flex", alignItems:"center", justifyContent:"center", height:"100vh", background:"#fff", fontFamily:"'Helvetica Neue',Helvetica,Arial,sans-serif", padding:20 }}>
        <div style={{ textAlign:"center", maxWidth:400 }}>
          <div style={{ fontSize:15, color:"#111", marginBottom:8, fontWeight:600 }}>Servidor indisponível</div>
          <div style={{ fontSize:13, color:"#6b7280", marginBottom:16 }}>Não foi possível carregar os dados. Tente novamente em alguns segundos.</div>
          <button onClick={() => { setLoading(true); loadData(); }} style={{ background:"#111", color:"#fff", border:"none", borderRadius:8, padding:"10px 20px", fontSize:13, fontWeight:600, cursor:"pointer", fontFamily:"inherit" }}>Tentar novamente</button>
          <button onClick={handleLogout} style={{ marginLeft:10, background:"transparent", color:"#6b7280", border:"1px solid #e5e7eb", borderRadius:8, padding:"10px 20px", fontSize:13, fontWeight:600, cursor:"pointer", fontFamily:"inherit" }}>Sair</button>
        </div>
      </div>
      <DialogosHost />
      <VersionWatcher />
      {conflitoModal}
      </>
    );
  }

  const nomeEscritorio = data?.escritorio?.nome || "Vicke";

  // MENU dinâmico baseado no perfil:
  // - Master (Renato/Vicke): foca em gestão da plataforma — Painel, Mensagens,
  //   Empresas, Usuários Master, Manutenção. Não vê Clientes/Projetos/Obras
  //   (irrelevantes pra quem opera o SaaS).
  // - Escritório (Padovan, futuras empresas): menu original — gestão do dia a dia.
  const MENU = isMaster ? [
    { k:"home",                   icon:"painel",     label:"Painel" },
    { k:"mensagens",               icon:"mensagens",  label:"Mensagens" },
    { k:"admin:empresas",          icon:"empresas",   label:"Empresas" },
    { k:"admin:usuarios-master",   icon:"usuarios",   label:"Usuários Master" },
    { k:"admin:manutencao",        icon:"manutencao", label:"Manutenção" },
    { k:"admin:cub",               icon:"cub",        label:"CUB" },
  ] : [
    { k:"home",        icon:"home",       label:"Início" },
    { k:"clientes",    icon:"clientes",   label:"Clientes",     count: data?.clientes?.length },
    { k:"projetos",    icon:"projetos",   label:"Projetos", sub: [
      { k:"projetos:orcamentos", icon:"projetos-orcamentos", label:"Orçamentos" },
      { k:"projetos:etapas",     icon:"projetos-andamento",  label:"Em Andamento" },
    ]},
    { k:"obras",       icon:"obras",      label:"Obras" },
    // Módulos Financeiro, Fornecedores e Notas Fiscais foram removidos do menu
    // (decisão Sprint 3): serão refeitos do zero. Mantenho os componentes/rotas
    // por enquanto pra não quebrar dados antigos, só ocultos do menu.
  ];

  // colapsadaEf: "colapsada efetiva" — em mobile, sidebar nunca está colapsada
  // (o conceito não faz sentido em overlay). Sempre mostra com texto+ícone.
  // Em desktop, usa a preferência salva do usuário.
  const colapsadaEf = isMobile ? false : sidebarColapsada;

  const itemStyle = (ativo) => ({
    display:"flex", alignItems:"center",
    justifyContent: colapsadaEf ? "center" : "space-between",
    padding: colapsadaEf ? "10px 8px" : (isMobile ? "12px 14px" : "8px 12px"), // touch target maior em mobile
    borderRadius:7, cursor:"pointer", fontSize:13,
    fontWeight: ativo ? 600 : 400, color: ativo ? "#111" : "#6b7280",
    background: ativo ? "#f3f4f6" : "transparent",
    border:"none", fontFamily:"'Helvetica Neue',Helvetica,Arial,sans-serif",
    width:"100%", textAlign:"left",
  });

  return (
    <>
    <div style={{ display:"flex", height:"100vh", fontFamily:"'Helvetica Neue',Helvetica,Arial,sans-serif", background:"#fff", overflow:"hidden" }}>
      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>

      {/* ── Backdrop mobile: fundo escurecido por trás do drawer.
          Aparece SÓ em mobile quando sidebar está aberta. Toque fecha. */}
      {isMobile && sidebarMobileAberta && (
        <div
          onClick={() => setSidebarMobileAberta(false)}
          style={{
            position:"fixed", inset:0, background:"rgba(0,0,0,0.4)",
            zIndex:990,
            transition:"opacity 0.2s",
          }}
        />
      )}

      {/* ── Sidebar: comportamento muda em mobile ──
          Desktop (>= 768px): fluxo lateral normal, ocupa espaço da grid.
          Mobile (< 768px): overlay flutuante (position:fixed), só aparece
          quando sidebarMobileAberta=true, sempre expandida (220px),
          ignora colapsadaEf. */}
      <div style={
        isMobile ? {
          // Drawer mobile
          position:"fixed", top:0, left:0, bottom:0,
          width: 260, // um pouco mais largo que o desktop expandido (260) pro toque ser confortável
          background:"#fff", borderRight:"1px solid #f3f4f6",
          display:"flex", flexDirection:"column",
          zIndex:991,
          transform: sidebarMobileAberta ? "translateX(0)" : "translateX(-100%)",
          transition:"transform 0.22s ease",
          boxShadow: sidebarMobileAberta ? "2px 0 16px rgba(0,0,0,0.12)" : "none",
        } : {
          // Sidebar desktop normal
          width: colapsadaEf ? 56 : 220,
          minWidth: colapsadaEf ? 56 : 220,
          transition:"width 0.18s ease, min-width 0.18s ease",
          background:"#fff", borderRight:"1px solid #f3f4f6",
          display:"flex", flexDirection:"column",
        }
      }>
        {/* ── Header da sidebar: nome do escritório + botão toggle ──
            Quando colapsada: apenas o botão toggle centralizado (sem título).
            Quando aberta: título à esquerda + toggle à direita. */}
        <div style={{
          padding: (!isMobile && colapsadaEf) ? "16px 8px" : "20px 16px 16px",
          borderBottom:"1px solid #f3f4f6",
          display:"flex", alignItems:"center",
          justifyContent: (!isMobile && colapsadaEf) ? "center" : "space-between",
          gap: 8,
        }}>
          {(isMobile || !colapsadaEf) && (
            <div style={{ flex:1, minWidth:0 }}>
              <div style={{ fontSize:15, fontWeight:700, color:"#111", letterSpacing:-0.3, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{nomeEscritorio}</div>
              <div style={{ fontSize:11, color:"#d1d5db", marginTop:2 }}>Vicke</div>
            </div>
          )}
          {/* Botão de toggle: muda comportamento conforme dispositivo.
              - Desktop: alterna entre sidebar colapsada/expandida (preferência localStorage)
              - Mobile: fecha o drawer (X), pois colapsada não faz sentido em overlay */}
          <button
            onClick={() => {
              if (isMobile) setSidebarMobileAberta(false);
              else setSidebarColapsada(c => !c);
            }}
            title={isMobile ? "Fechar menu" : (colapsadaEf ? "Expandir menu" : "Recolher menu")}
            aria-label={isMobile ? "Fechar menu" : (colapsadaEf ? "Expandir menu" : "Recolher menu")}
            style={{
              background:"none", border:"none", cursor:"pointer",
              padding: isMobile ? 10 : 6, // touch target maior em mobile
              color:"#9ca3af", lineHeight:0,
              display:"flex", alignItems:"center", justifyContent:"center",
              borderRadius:6, fontFamily:"inherit",
            }}
            onMouseEnter={e => { if (!isMobile) { e.currentTarget.style.background="#f3f4f6"; e.currentTarget.style.color="#374151"; } }}
            onMouseLeave={e => { if (!isMobile) { e.currentTarget.style.background="transparent"; e.currentTarget.style.color="#9ca3af"; } }}>
            {isMobile ? (
              // X de fechar em mobile
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <line x1="18" y1="6" x2="6" y2="18"/>
                <line x1="6" y1="6" x2="18" y2="18"/>
              </svg>
            ) : (
              // Toggle panel-left em desktop
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                <rect x="3" y="3" width="18" height="18" rx="2"/>
                <line x1="9" y1="3" x2="9" y2="21"/>
              </svg>
            )}
          </button>
        </div>
          <nav style={{ flex:1, padding:"12px 8px", display:"flex", flexDirection:"column", gap:2, overflowY:"auto" }}>
            {MENU.map(item => {
              const {k, label, count, sub, icon} = item;
              if (sub && sub.length) {
                const ativoNeleMesmoOuSubitem = aba === k || (typeof aba === "string" && aba.indexOf(k + ":") === 0);
                return (
                  <div key={k} style={{ display:"flex", flexDirection:"column", position:"relative" }}>
                    <button
                      id={k === "projetos" ? "trigger-projetos" : undefined}
                      title={colapsadaEf ? label : undefined}
                      style={{
                        ...itemStyle(ativoNeleMesmoOuSubitem),
                        justifyContent: colapsadaEf ? "center" : "flex-start",
                        gap: 6,
                        background: aba === k ? "#f3f4f6" : "transparent",
                        fontWeight: ativoNeleMesmoOuSubitem ? 600 : 400,
                        color: ativoNeleMesmoOuSubitem ? "#111" : "#6b7280",
                      }}
                      onMouseEnter={e => { if (aba !== k) e.currentTarget.style.background="#f9fafb"; }}
                      onMouseLeave={e => { if (aba !== k) e.currentTarget.style.background="transparent"; }}
                      onClick={(ev) => {
                        if (colapsadaEf) {
                          // Sidebar colapsada: abre popover lateral com os subitens.
                          // Posiciona absoluto à direita do botão.
                          const rect = ev.currentTarget.getBoundingClientRect();
                          setPopoverProjetos({ top: rect.top, left: rect.right + 4 });
                        } else {
                          // Sidebar aberta: comportamento accordion (expandir/recolher)
                          setProjetosAberto(o => !o);
                        }
                      }}
                    >
                      <span style={{ display:"flex", alignItems:"center", gap:10, flex:1, justifyContent: colapsadaEf ? "center" : "flex-start" }}>
                        {icon && <IconeMaster nome={icon} tamanho={16} cor={ativoNeleMesmoOuSubitem ? "#111" : "#6b7280"} />}
                        {!colapsadaEf && label}
                      </span>
                      {!colapsadaEf && (
                        <span style={{
                          color:"#9ca3af", fontSize:9,
                          transition:"transform 0.2s",
                          transform: projetosAberto ? "rotate(90deg)" : "rotate(0deg)",
                          display:"inline-block",
                          lineHeight: 1,
                        }}>▶</span>
                      )}
                    </button>
                    {/* Submenus inline (accordion) — só quando expandida */}
                    {!colapsadaEf && projetosAberto && (
                      <div style={{ display:"flex", flexDirection:"column", gap:1, marginLeft:14, paddingLeft:8, borderLeft:"1px solid #f3f4f6", marginTop:2 }}>
                        {sub.map(s => {
                          const ativoSub = aba === s.k;
                          return (
                            <button
                              key={s.k}
                              style={{
                                padding:"6px 10px", borderRadius:6,
                                fontSize:12.5,
                                color: ativoSub ? "#111" : "#9ca3af",
                                fontWeight: ativoSub ? 600 : 400,
                                background: ativoSub ? "#f3f4f6" : "transparent",
                                cursor:"pointer", border:"none",
                                fontFamily:"'Helvetica Neue',Helvetica,Arial,sans-serif",
                                textAlign:"left", transition:"all 0.12s",
                              }}
                              onMouseEnter={e => { if (!ativoSub) { e.currentTarget.style.background="#f9fafb"; e.currentTarget.style.color="#6b7280"; } }}
                              onMouseLeave={e => { if (!ativoSub) { e.currentTarget.style.background="transparent"; e.currentTarget.style.color="#9ca3af"; } }}
                              onClick={() => {
                                tentarTrocar(() => {
                                  setAba(s.k);
                                  setOrcamentoTelaCheia(null);
                                  if (s.k === "projetos:etapas") setProjetosKey(n=>n+1);
                                  if (s.k === "projetos:orcamentos") setOrcamentosKey(n=>n+1);
                                });
                              }}
                            >
                              <span style={{ display:"flex", alignItems:"center", gap:10 }}>
                                {s.icon && <IconeMaster nome={s.icon} tamanho={14} cor={ativoSub ? "#111" : "#9ca3af"} />}
                                {s.label}
                              </span>
                            </button>
                          );
                        })}
                      </div>
                    )}
                  </div>
                );
              }
              return (
                <button key={k} style={itemStyle(aba===k)}
                  title={colapsadaEf ? label : undefined}
                  onMouseEnter={e => { if(aba!==k) e.currentTarget.style.background="#f9fafb"; }}
                  onMouseLeave={e => { if(aba!==k) e.currentTarget.style.background="transparent"; }}
                  onClick={() => {
                    tentarTrocar(() => {
                      setAba(k);
                      setOrcamentoTelaCheia(null);
                      if(k==="clientes")    setClientesKey(n=>n+1);
                      if(k==="obras")       setObrasKey(n=>n+1);
                      if(k==="financeiro")  setFinanceiroKey(n=>n+1);
                      if(k==="fornecedores")setFornecedoresKey(n=>n+1);
                      if(k==="projetos:orcamentos") setOrcamentosKey(n=>n+1);
                    });
                  }}>
                  <span style={{ display:"flex", alignItems:"center", gap:10 }}>
                    {icon && <IconeMaster nome={icon} tamanho={16} cor={aba===k ? "#111" : "#6b7280"} />}
                    {!colapsadaEf && label}
                  </span>
                  {!colapsadaEf && count > 0 && <span style={{ background:"#f3f4f6", color:"#9ca3af", fontSize:11, padding:"1px 7px", borderRadius:8 }}>{count}</span>}
                </button>
              );
            })}
          </nav>
          <div style={{ padding:"8px 8px 12px", borderTop:"1px solid #f3f4f6", display:"flex", flexDirection:"column", gap:2 }}>
            {/* Header da seção — esconde quando sidebar colapsada (não cabe). */}
            {!isMaster && !colapsadaEf && (
              <div style={{ fontSize:10, fontWeight:700, color:"#9ca3af", textTransform:"uppercase", letterSpacing:0.6, padding:"6px 12px 2px" }}>
                Configuração
              </div>
            )}
            {/* Botão Escritório só pra perfil escritório (Master vê tudo no menu principal) */}
            {!isMaster && (
              <button style={itemStyle(aba==="escritorio")}
                title={colapsadaEf ? "Escritório" : undefined}
                onMouseEnter={e => { if(aba!=="escritorio") e.currentTarget.style.background="#f9fafb"; }}
                onMouseLeave={e => { if(aba!=="escritorio") e.currentTarget.style.background="transparent"; }}
                onClick={() => { tentarTrocar(() => { setAba("escritorio"); setOrcamentoTelaCheia(null); setEscritorioKey(n=>n+1); }); }}>
                <span style={{ display:"flex", alignItems:"center", gap:10 }}>
                  <IconeMaster nome="escritorio" tamanho={16} cor={aba==="escritorio" ? "#111" : "#6b7280"} />
                  {!colapsadaEf && "Escritório"}
                </span>
              </button>
            )}
            {/* Aba "Orçamento" — configurações de pricing/calibragem.
                Visível pra todos os perfis (botão interno é que valida permissão).
                Master também vê — útil pra Vicke caso queira testar o fluxo. */}
            <button style={itemStyle(aba==="orcamento")}
              title={colapsadaEf ? "Orçamento" : undefined}
              onMouseEnter={e => { if(aba!=="orcamento") e.currentTarget.style.background="#f9fafb"; }}
              onMouseLeave={e => { if(aba!=="orcamento") e.currentTarget.style.background="transparent"; }}
              onClick={() => { tentarTrocar(() => { setAba("orcamento"); setOrcamentoTelaCheia(null); }); }}>
              <span style={{ display:"flex", alignItems:"center", gap:10 }}>
                <IconeMaster nome="orcamento" tamanho={16} cor={aba==="orcamento" ? "#111" : "#6b7280"} />
                {!colapsadaEf && "Orçamento"}
              </span>
            </button>
            {/* Botão Escritório do Master (gerenciar dados da Vicke). Mantido aqui
                discretamente — uso raro mas existe. */}
            {isMaster && (
              <button style={itemStyle(aba==="escritorio")}
                title={colapsadaEf ? "Escritório (Master)" : undefined}
                onMouseEnter={e => { if(aba!=="escritorio") e.currentTarget.style.background="#f9fafb"; }}
                onMouseLeave={e => { if(aba!=="escritorio") e.currentTarget.style.background="transparent"; }}
                onClick={() => { tentarTrocar(() => { setAba("escritorio"); setOrcamentoTelaCheia(null); setEscritorioKey(n=>n+1); }); }}>
                <span style={{ display:"flex", alignItems:"center", gap:10 }}>
                  <IconeMaster nome="escritorio" tamanho={16} cor={aba==="escritorio" ? "#111" : "#6b7280"} />
                  {!colapsadaEf && (
                    <>
                      Escritório
                      <span style={{ fontSize:9, fontWeight:700, color:"#1e3a8a", background:"#eff6ff", border:"1px solid #bfdbfe", borderRadius:3, padding:"1px 5px", textTransform:"uppercase", letterSpacing:0.5 }}>Master</span>
                    </>
                  )}
                </span>
              </button>
            )}
            <div style={{ padding:"8px 12px", marginTop:4, display:"flex", alignItems:"center", justifyContent:"space-between", gap:8 }}>
              {!colapsadaEf && (
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ fontSize:12, fontWeight:600, color:"#374151", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{usuario?.nome || "—"}</div>
                  <div style={{ fontSize:11, color:"#d1d5db" }}>{usuario?.perfil || ""}</div>
                </div>
              )}
              <button
                onClick={handleLogout}
                title="Sair"
                style={{
                  background:"none", border:"none", color:"#9ca3af",
                  fontSize:12, cursor:"pointer", fontFamily:"inherit",
                  padding: colapsadaEf ? "6px" : "4px 8px",
                  borderRadius:6, lineHeight:0,
                  display:"flex", alignItems:"center", justifyContent:"center",
                }}
                onMouseEnter={e => { e.currentTarget.style.background="#f3f4f6"; e.currentTarget.style.color="#374151"; }}
                onMouseLeave={e => { e.currentTarget.style.background="transparent"; e.currentTarget.style.color="#9ca3af"; }}>
                {colapsadaEf ? (
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/>
                    <polyline points="16 17 21 12 16 7"/>
                    <line x1="21" y1="12" x2="9" y2="12"/>
                  </svg>
                ) : "Sair"}
              </button>
            </div>
            {/* Importar/Exportar — só master. Discreto, no rodapé. */}
            {isMaster && !colapsadaEf && (
              <div style={{ padding:"4px 12px 8px", display:"flex", gap:6, fontSize:11 }}>
                <label style={{ flex:1, textAlign:"center", color:"#9ca3af", cursor:"pointer", border:"1px solid #f3f4f6", borderRadius:6, padding:"5px 8px" }}
                  onMouseEnter={e => { e.currentTarget.style.background="#f9fafb"; e.currentTarget.style.color="#374151"; }}
                  onMouseLeave={e => { e.currentTarget.style.background="transparent"; e.currentTarget.style.color="#9ca3af"; }}>
                  Importar
                  <input type="file" accept=".json" style={{ display:"none" }} onChange={importarDados} />
                </label>
                <button onClick={exportarDados}
                  style={{ flex:1, color:"#9ca3af", cursor:"pointer", border:"1px solid #f3f4f6", borderRadius:6, padding:"5px 8px", background:"transparent", fontFamily:"inherit", fontSize:11 }}
                  onMouseEnter={e => { e.currentTarget.style.background="#f9fafb"; e.currentTarget.style.color="#374151"; }}
                  onMouseLeave={e => { e.currentTarget.style.background="transparent"; e.currentTarget.style.color="#9ca3af"; }}>
                  Exportar
                </button>
              </div>
            )}
          </div>
      </div>

      <div style={{ flex:1, display:"flex", flexDirection:"column", overflow:"hidden" }}>
        {/* ── Header mobile: aparece só em <768px. Tem hamburguer pra abrir
            o drawer da sidebar + nome do escritório (compacto). ── */}
        {isMobile && (
          <div style={{
            display:"flex", alignItems:"center", gap:10,
            padding:"10px 14px",
            borderBottom:"1px solid #f3f4f6",
            background:"#fff",
            zIndex: 10,
          }}>
            <button
              onClick={() => setSidebarMobileAberta(true)}
              aria-label="Abrir menu"
              style={{
                background:"none", border:"none",
                padding:8, lineHeight:0,
                cursor:"pointer", color:"#374151",
                borderRadius:6,
                display:"flex", alignItems:"center", justifyContent:"center",
              }}>
              {/* Ícone hamburguer Lucide */}
              <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <line x1="3" y1="6" x2="21" y2="6"/>
                <line x1="3" y1="12" x2="21" y2="12"/>
                <line x1="3" y1="18" x2="21" y2="18"/>
              </svg>
            </button>
            <div style={{
              fontSize:14, fontWeight:600, color:"#111",
              overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap", flex:1,
            }}>
              {nomeEscritorio}
            </div>
          </div>
        )}
        {backendOffline && (
          <div style={{ background:"#fef2f2", borderBottom:"1px solid #fecaca", padding:"8px 20px", display:"flex", alignItems:"center", justifyContent:"space-between", gap:12 }}>
            <div style={{ fontSize:12, color:"#991b1b" }}>
              <span style={{ fontWeight:600 }}>⚠ Servidor indisponível</span>
              <span style={{ marginLeft:8, color:"#b91c1c" }}>— trabalhando no modo offline. Alterações não serão salvas até o servidor voltar.</span>
            </div>
            <button onClick={loadData} style={{ background:"#fff", color:"#991b1b", border:"1px solid #fca5a5", borderRadius:6, padding:"4px 12px", fontSize:12, fontWeight:600, cursor:"pointer", fontFamily:"inherit" }}>
              Tentar reconectar
            </button>
          </div>
        )}
        <div style={{ flex:1, overflowY:"auto" }}>
          <>
          {orcamentoTelaCheia ? (
            <FormOrcamentoProjetoTeste
              clienteNome={orcamentoTelaCheia.clienteOrc.nome}
              clienteWA={orcamentoTelaCheia.clienteOrc.contatos?.find(c=>c.whatsapp)?.telefone||""}
              orcBase={orcamentoTelaCheia.orcBase || null}
              escritorio={data.escritorio || {}}
              usuario={usuario}
              cub={data?.cub}
              modoVer={orcamentoTelaCheia.modo === "ver"}
              modoAbertura={orcamentoTelaCheia.modo}
              onSalvar={async (orc) => {
                // CRITICAL FIX — Cenário 1: usar dataRef.current em vez de data.
                // Este callback é criado na renderização em que orcamentoTelaCheia
                // mudou. Chamadas subsequentes (salvar orçamento + gerar proposta
                // + salvar snapshot) disparam este mesmo callback repetidas vezes,
                // e `data` capturado no closure fica congelado. Resultado: a 2ª
                // chamada sobrescreve orcamentosProjeto inteiro com o estado
                // antigo + mudança atual, perdendo atualizações intermediárias
                // (como propostas recém-salvas).
                // Solução: ler sempre de dataRef.current, que é atualizado em
                // tempo real pelo save() e pelo useEffect que segue `data`.
                const dataAtual = dataRef.current || data;
                const todos = dataAtual.orcamentosProjeto || [];
                const maxSeq = todos.reduce((mx2, o2) => {
                  const mm = (o2.id||"").match(/^ORC-(\d+)$/);
                  return mm ? Math.max(mx2, parseInt(mm[1])) : mx2;
                }, 0);
                const nextId = "ORC-" + String(maxSeq + 1).padStart(4, "0");
                const novo2 = {
                  ...orc,
                  clienteId: orcamentoTelaCheia.clienteOrc.id,
                  cliente: orcamentoTelaCheia.clienteOrc.nome,
                  whatsapp: orcamentoTelaCheia.clienteOrc.contatos?.find(c=>c.whatsapp)?.telefone || "",
                  id: orc.id || nextId,
                  criadoEm: orc.criadoEm || new Date().toISOString(),
                };
                const novos2 = orc.id
                  ? todos.map(o2=>o2.id===orc.id?novo2:o2)
                  : [...todos, novo2];
                await save({ ...dataAtual, orcamentosProjeto: novos2 });
                // Propaga o orc atualizado pro state de tela cheia, assim a
                // próxima edição/geração de proposta vai trabalhar em cima dele.
                setOrcamentoTelaCheia(prev => ({ ...prev, orcBase: novo2 }));
              }}
              onVoltar={() => {
                setClienteRetorno(orcamentoTelaCheia.clienteOrc);
                setOrcamentoTelaCheia(null);
                setAba("clientes");
                setClientesKey(n=>n+1);
                // Sem loadData — save() já atualizou data otimisticamente.
              }}
            />
          ) : (<>
          {aba === "home" && isMaster && <DashboardMaster setAba={setAba} data={data} tentarTrocar={tentarTrocar} />}
          {aba === "home" && !isMaster && <HomeMenu setAba={setAba} data={data} tentarTrocar={tentarTrocar} isMaster={isMaster} />}
          {aba === "clientes"               && <Clientes key={clientesKey} data={data} save={save} onReload={()=>setClientesKey(n=>n+1)} onAbrirOrcamento={(c, orc, modo) => setOrcamentoTelaCheia({ clienteOrc: c, orcBase: orc, modo: modo || "editar" })} orcamentoAberto={!!orcamentoTelaCheia} abrirClienteDetail={clienteRetorno} onClienteDetailAberto={() => setClienteRetorno(null)} abrirCadastroNovo={cadastroNovoCliente} onCadastroNovoAberto={() => setCadastroNovoCliente(false)} />}
          {aba === "projetos:etapas"        && <Etapas key={projetosKey} data={data} save={save} />}
          {aba === "projetos:orcamentos"    && <TesteOrcamento key={orcamentosKey} data={{ ...data, _usuario: usuario }} save={save} onCadastrarCliente={() => { setAba("clientes"); setClientesKey(n=>n+1); setCadastroNovoCliente(true); }} />}
          {aba === "obras"                  && <Obras key={obrasKey} data={data} save={save} />}
          {aba === "financeiro"             && <Financeiro key={financeiroKey} data={data} save={save} />}
          {aba === "fornecedores"           && <Fornecedores key={fornecedoresKey} data={data} save={save} />}
          {aba === "nf"                     && <ImportarNF data={data} save={save} />}
          {aba === "escritorio"             && <Escritorio key={escritorioKey} data={data} save={save} />}
          {aba === "orcamento"              && <OrcamentoConfig usuario={usuario} data={data} setUsuario={setUsuario} />}
          {/* Sub-abas do menu Master — Admin recebe initialTab pra abrir direto na aba certa */}
          {aba === "admin" && isMaster && <Admin usuario={usuario} data={data} save={save} />}
          {aba === "admin:empresas" && isMaster && <Admin usuario={usuario} data={data} save={save} initialTab="empresas" />}
          {aba === "admin:usuarios-master" && isMaster && <Admin usuario={usuario} data={data} save={save} initialTab="usuarios-master" />}
          {aba === "admin:manutencao" && isMaster && <Admin usuario={usuario} data={data} save={save} initialTab="manutencao" />}
          {aba === "admin:feedback" && isMaster && <Admin usuario={usuario} data={data} save={save} initialTab="feedback" />}
          {aba === "admin:cub" && isMaster && <Admin usuario={usuario} data={data} save={save} initialTab="cub" />}
          {/* Caixa de Mensagens — só Master */}
          {aba === "mensagens" && isMaster && <Mensagens usuario={usuario} />}
          </>)}
          </>
        </div>
      </div>
      {showBackup && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.5)", zIndex:99999, display:"flex", alignItems:"center", justifyContent:"center", padding:20 }}>
          <div style={{ background:"#fff", border:"1px solid #e5e7eb", borderRadius:14, padding:24, width:"100%", maxWidth:600, maxHeight:"85vh", display:"flex", flexDirection:"column", gap:16 }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>
              <div style={{ fontWeight:700, fontSize:15, color:"#111" }}>Backup dos dados</div>
              <button onClick={() => setShowBackup(false)} style={{ background:"transparent", border:"none", color:"#9ca3af", fontSize:20, cursor:"pointer" }}>×</button>
            </div>
            <div style={{ color:"#6b7280", fontSize:13 }}>Download automático não disponível. Selecione tudo (<b>Ctrl+A</b>), copie (<b>Ctrl+C</b>) e salve num arquivo <b>.json</b>.</div>
            <textarea readOnly value={backupJson} onClick={e => e.target.select()}
              style={{ flex:1, minHeight:320, background:"#f9fafb", border:"1px solid #e5e7eb", borderRadius:8, color:"#374151", fontSize:11, fontFamily:"monospace", padding:14, resize:"none", outline:"none" }} />
            <div style={{ display:"flex", gap:10, justifyContent:"flex-end" }}>
              <button onClick={() => navigator.clipboard?.writeText(backupJson).catch(()=>{})}
                style={{ background:"#111", color:"#fff", border:"none", borderRadius:7, padding:"8px 18px", fontSize:13, fontWeight:600, cursor:"pointer", fontFamily:"inherit" }}>Copiar tudo</button>
              <button onClick={() => setShowBackup(false)}
                style={{ background:"#fff", color:"#6b7280", border:"1px solid #e5e7eb", borderRadius:7, padding:"8px 18px", fontSize:13, cursor:"pointer", fontFamily:"inherit" }}>Fechar</button>
            </div>
          </div>
        </div>
      )}
    </div>
    {/* ── Popover dos subitens de Projetos (sidebar colapsada) ──
        Posicionado fixed na coordenada do trigger. Click fora fecha (handler
        em useEffect mais acima). Aparece à direita do botão na sidebar. */}
    {popoverProjetos && colapsadaEf && (() => {
      const projetosItem = MENU.find(m => m.k === "projetos");
      if (!projetosItem) return null;
      return (
        <div
          id="popover-projetos"
          style={{
            position:"fixed",
            top: popoverProjetos.top,
            left: popoverProjetos.left,
            background:"#fff",
            border:"1px solid #e5e7eb",
            borderRadius:8,
            boxShadow:"0 4px 16px rgba(0,0,0,0.08)",
            padding:"6px",
            minWidth:180,
            zIndex:1000,
            fontFamily:"'Helvetica Neue',Helvetica,Arial,sans-serif",
            display:"flex", flexDirection:"column", gap:1,
          }}>
          <div style={{ fontSize:10, fontWeight:700, color:"#9ca3af", textTransform:"uppercase", letterSpacing:0.6, padding:"6px 10px 4px" }}>
            {projetosItem.label}
          </div>
          {projetosItem.sub.map(s => {
            const ativoSub = aba === s.k;
            return (
              <button
                key={s.k}
                onClick={() => {
                  tentarTrocar(() => {
                    setAba(s.k);
                    setOrcamentoTelaCheia(null);
                    if (s.k === "projetos:etapas") setProjetosKey(n => n+1);
                    if (s.k === "projetos:orcamentos") setOrcamentosKey(n => n+1);
                  });
                  setPopoverProjetos(null);
                }}
                style={{
                  display:"flex", alignItems:"center", gap:10,
                  padding:"7px 10px", borderRadius:6, fontSize:12.5,
                  border:"none", background: ativoSub ? "#f3f4f6" : "transparent",
                  color: ativoSub ? "#111" : "#374151",
                  fontWeight: ativoSub ? 600 : 400,
                  fontFamily:"inherit", cursor:"pointer", textAlign:"left",
                }}
                onMouseEnter={e => { if (!ativoSub) e.currentTarget.style.background="#f9fafb"; }}
                onMouseLeave={e => { if (!ativoSub) e.currentTarget.style.background="transparent"; }}>
                {s.icon && <IconeMaster nome={s.icon} tamanho={14} cor={ativoSub ? "#111" : "#9ca3af"} />}
                {s.label}
              </button>
            );
          })}
        </div>
      );
    })()}
    <DialogosHost />
    <VersionWatcher />
    <BotaoFeedbackFlutuante usuario={usuario} />
    {conflitoModal}
    </>
  );
}

